-- Poems batch 224
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('7504ac6c-792c-4dfb-81c2-09bda9b7a8aa','南山有梅花','毛珝','宋','宋诗','song-poetry','','[]','南山有梅花，高者五丈餘。',48,'全唐诗/poet.song.206000.json','["南山有梅花，高者五丈餘。", "半空發清香，天人爲踟躕。", "城中三尺本，登盆綴流蘇。", "進之畫堂上，笑彼何粗疎。"]'),
('6a008356-3ac6-4fb4-9a75-616d0f31a992','山中吟七首  其一','毛珝','宋','宋诗','song-poetry','','[]','幽幽山上松，泠泠松下井。',48,'全唐诗/poet.song.206000.json','["幽幽山上松，泠泠松下井。", "白石當銀床，青蘿作脩綆。", "山翁獨酌餘，無客可堪請。", "葛洪分煉丹，陸羽求煎茗。"]'),
('05d69ccd-b6eb-47c0-9906-337896d55d8a','山中吟七首  其二','毛珝','宋','宋诗','song-poetry','','[]','采薇作庭實，紉蘭作筐篚。',48,'全唐诗/poet.song.206000.json','["采薇作庭實，紉蘭作筐篚。", "持以薦王公，謂可蘋藻比。", "王公齲齒謝，王門何用此。", "問客姓與名，或是孤竹子。"]'),
('0c179aee-2abf-4bf3-bd70-9d1359ea2b44','山中吟七首  其三','毛珝','宋','宋诗','song-poetry','','[]','山中夜讀書，山鬼來相試。',48,'全唐诗/poet.song.206000.json','["山中夜讀書，山鬼來相試。", "隔窗問疑難，頗及堯舜事。", "予非卯金人，安能動星緯。", "劃然一推窗，餘音入空翠。"]'),
('8058f116-60f9-4e5c-982d-9189c8ad40fd','山中吟七首  其四','毛珝','宋','宋诗','song-poetry','','[]','山翁不能文，亦免時流笑。',48,'全唐诗/poet.song.206000.json','["山翁不能文，亦免時流笑。", "早愛滄浪歌，知詞不知調。", "長年山水間，所業只耕釣。", "偶得千齡龜，遂通八卦兆。"]'),
('c5dd4b9b-2dc4-41a6-8c56-6bbd059ca836','山中吟七首  其五','毛珝','宋','宋诗','song-poetry','','[]','山花開滿枝，山鳥啼無時。',48,'全唐诗/poet.song.206000.json','["山花開滿枝，山鳥啼無時。", "君胡欲棄此，自取塵污爲。", "山猿囓君屨，山鹿銜君衣。", "挽君君不留，去去終何歸。"]'),
('334c9020-d013-4760-bb73-1e37162ffef7','山中吟七首  其六','毛珝','宋','宋诗','song-poetry','','[]','槲葉可以衣，松實可療饑。',48,'全唐诗/poet.song.206000.json','["槲葉可以衣，松實可療饑。", "騎鹿下山去，儗說高人知。", "高人不可得，紛紛却語誰。", "曉窗白雲過，且自相同歸。"]'),
('158fda81-8b58-4b6f-843d-81519ce3ec6a','山中吟七首  其七','毛珝','宋','宋诗','song-poetry','','[]','題牋寄親友，早早山中來。',48,'全唐诗/poet.song.206000.json','["題牋寄親友，早早山中來。", "紫芝既可採，蟠桃行當開。", "持書托南風，北風復吹回。", "愛之不可見，落日令人哀。"]'),
('f34d4c3a-7305-4d5c-b4d4-a046b503292f','己酉客淮','毛珝','宋','宋诗','song-poetry','','[]','烽燧春尤急，人才嘆寂寥。',48,'全唐诗/poet.song.206000.json','["烽燧春尤急，人才嘆寂寥。", "恨無黄石略，難致碧幢招。", "守塹宵仍甲，防城曉未橋。", "又傳經一雪，殘哨亦蕭蕭。"]'),
('7ea7a92d-aa68-4d7e-bf0c-11483e63b247','過黄山法華寺','毛珝','宋','宋诗','song-poetry','','[]','積雪滿松崗，茲行爲悼亡。',48,'全唐诗/poet.song.206000.json','["積雪滿松崗，茲行爲悼亡。", "本非求吉地，祇欲近禪坊。", "外物心如水，流年鬢已霜。", "只應雙卜宅，永此禮空王。"]'),
('e3a1e7bf-63d1-4ef9-b521-3f767ef3b8d7','送田耕月遊吳  其一','毛珝','宋','宋诗','song-poetry','','[]','衣笈詩囊外，身輕費亦輕。',48,'全唐诗/poet.song.206000.json','["衣笈詩囊外，身輕費亦輕。", "不妨船眼窄，時上岸頭行。", "橘里逢霜信，松江問水程。", "吳中聞歲稔，新糴想須平。"]'),
('db37d11d-0623-4e30-ae1d-e81118e3d8cd','送田耕月遊吳  其二','毛珝','宋','宋诗','song-poetry','','[]','登橋仍問渡，迢遞到吳中。',48,'全唐诗/poet.song.206000.json','["登橋仍問渡，迢遞到吳中。", "倩僕挑茶竈，移船避釣筒。", "月生林屋洞，潮接館娃宮。", "得句人傳去，蘇牋價益穹。"]'),
('d3da48d1-8c61-43ed-8f2d-9050153366b3','送田耕月遊吳  其三','毛珝','宋','宋诗','song-poetry','','[]','此去姑蘇郡，都無五日程。',48,'全唐诗/poet.song.206000.json','["此去姑蘇郡，都無五日程。", "仍聞新太守，最重舊交情。", "有句梅邊索，無田月下耕。", "雙親方待養，吾亦勉君行。"]'),
('e3f8dbd3-a9f9-4abe-aa7d-aea50f50a4cd','湓江','毛珝','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','遠樹一重重，煙村與市通。',48,'全唐诗/poet.song.206000.json','["遠樹一重重，煙村與市通。", "難尋元亮宅，遥酹菊花叢。", "蜀浪帆檣外，廬山几席中。", "何時邊事息，來此作漁翁。"]'),
('97e92c6e-1e5f-43c0-9b12-854b1f71cfb8','吳門田家十詠  其一','毛珝','宋','宋诗','song-poetry','','[]','去年一澇失冬收，逋債于今尚未酬。',32,'全唐诗/poet.song.206000.json','["去年一澇失冬收，逋債于今尚未酬。", "偶爲灼龜逢吉兆，再供租約賃耕牛。"]'),
('cd3f83b0-4672-40aa-914a-87a9728cc845','吳門田家十詠  其二','毛珝','宋','宋诗','song-poetry','','[]','竹罾兩兩夾河泥，近郭溝渠此最肥。',32,'全唐诗/poet.song.206000.json','["竹罾兩兩夾河泥，近郭溝渠此最肥。", "載得滿船歸插種，勝如賈販嶺南歸。"]'),
('0548cf36-82dc-4466-a941-ed3246950e81','吳門田家十詠  其三','毛珝','宋','宋诗','song-poetry','','[]','到處車聲轉水勞，東鄉人事獨逍遥。',32,'全唐诗/poet.song.206000.json','["到處車聲轉水勞，東鄉人事獨逍遥。", "一堤灧灧元非雨，總是吳江淡水潮。"]'),
('a179434e-0495-40e6-a95d-ddb946236762','吳門田家十詠  其四','毛珝','宋','宋诗','song-poetry','','[]','今年田事謝蒼蒼，儘有瓶罌卒歲藏。',32,'全唐诗/poet.song.206000.json','["今年田事謝蒼蒼，儘有瓶罌卒歲藏。", "只恐主家增斛面，雙鷄先把獻監莊。"]'),
('80c14caa-587f-44ea-8979-98525be3f7b6','吳門田家十詠  其五','毛珝','宋','宋诗','song-poetry','','[]','主家租入有常規，十月開倉不許違。',32,'全唐诗/poet.song.206000.json','["主家租入有常規，十月開倉不許違。", "占得頭籌先衆了，繞身紅綵送將歸。"]'),
('f8178414-25d1-4f59-a4b2-517814f07255','吳門田家十詠  其六','毛珝','宋','宋诗','song-poetry','','[]','西鄉本是最高鄉，今歲收成亦倍常。',32,'全唐诗/poet.song.206000.json','["西鄉本是最高鄉，今歲收成亦倍常。", "瓦鼓綵亭連日閙，誰家不謝白龍王。"]'),
('544e4f21-f57a-4cb9-a37b-e0ffab0328ae','吳門田家十詠  其七','毛珝','宋','宋诗','song-poetry','','[]','村村鼓笛樂秋成，露未凝霜水未冰。',32,'全唐诗/poet.song.206000.json','["村村鼓笛樂秋成，露未凝霜水未冰。", "無頼酒家偏罔利，隔年早掛上元燈。"]'),
('1daa19fe-c2e4-4a90-bc14-57a91e136f00','吳門田家十詠  其八','毛珝','宋','宋诗','song-poetry','','[]','田家少婦最風流，白角冠兒皁蓋頭。',32,'全唐诗/poet.song.206000.json','["田家少婦最風流，白角冠兒皁蓋頭。", "笑問傍人披得稱，已遮日色又遮羞。"]'),
('067a3855-4c08-408c-b67d-1c0f88cb054a','吳門田家十詠  其九','毛珝','宋','宋诗','song-poetry','','[]','長襟侈袖若僧衣，閑蕩扁舟入郭嬉。',32,'全唐诗/poet.song.206000.json','["長襟侈袖若僧衣，閑蕩扁舟入郭嬉。", "好是醉歸村舍晚，聲聲耳畔阿郎兒。"]'),
('660f3f3e-5844-4c8d-9c36-50a4d95d5532','吳門田家十詠  其一○','毛珝','宋','宋诗','song-poetry','','[]','主家文牓又圍田，田甲科丁各備船。',32,'全唐诗/poet.song.206000.json','["主家文牓又圍田，田甲科丁各備船。", "下得樁深笆土穩，更遷垂柳護圍邊。"]'),
('15cbe2dc-a7c7-462a-b80d-5e995c8be795','劉寺','毛珝','宋','宋诗','song-poetry','','[]','曾住昭陽殿裏頭，何年香骨掩荒丘。',64,'全唐诗/poet.song.206000.json','["曾住昭陽殿裏頭，何年香骨掩荒丘。", "虛傳碧落歸僊去，誰見蒼梧從帝遊。", "鸞閣粉銷塵影暗，蜃爐香冷石人愁。", "風前不敢梅花折，猶恐君恩寵未休。"]'),
('f9e6067e-66ba-4027-9cf6-3b1210097f30','宿廣果寺','毛珝','宋','宋诗','song-poetry','','[]','寺門初掩夜沉沉，風逼燈寒檜影深。',64,'全唐诗/poet.song.206000.json','["寺門初掩夜沉沉，風逼燈寒檜影深。", "滿屋異香僧入懺，一甌新茗客搜吟。", "雲歸古殿聞龍氣，月照空池見佛心。", "坐久恰眠眠未穩，屋頭鍾起鵲驚林。"]'),
('c0c592f9-ebfe-40b6-ad45-d2520a889ca5','金陵','毛珝','宋','宋诗','song-poetry','','[]','虎踞龍蟠在目前，依前行闕鎖寒煙。',64,'全唐诗/poet.song.206000.json','["虎踞龍蟠在目前，依前行闕鎖寒煙。", "津頭鼓角增新戍，陌上笙簫減舊年。", "高塔直看淮對境，斷碑閑憶晉諸賢。", "我來尚喜秋成日，魚蟹堪賒滿市邊。"]'),
('5b0790e3-ea2e-45f8-89e9-60d40434f067','拄杖','毛珝','宋','宋诗','song-poetry','','[]','數節堅如玉削成，幾年出入伴閑身。',64,'全唐诗/poet.song.206000.json','["數節堅如玉削成，幾年出入伴閑身。", "扶持衰老非無術，變化虛空亦有神。", "藥籠倒挑同入市，酒壺斜掛共尋春。", "雖然未作顛危用，閑指迷津與路人。"]'),
('4131f4a0-11bc-4cfc-86f0-7359e7db4aac','數椽','毛珝','宋','宋诗','song-poetry','','[]','梅有清香竹有陰，數椽於此寄幽深。',64,'全唐诗/poet.song.206000.json','["梅有清香竹有陰，數椽於此寄幽深。", "舊看歸鴈拋孤旅，新聽啼螿悔苦吟。", "幾卷書皆先世迹，一張琴是古人心。", "柴門未必無知己，何必江湖在遠尋。"]'),
('dbac4a25-dc7e-4cd4-9fe1-bd790492132c','陳藏一山房','毛珝','宋','宋诗','song-poetry','','[]','一室焚香即太初，萬人如海儘從渠。',64,'全唐诗/poet.song.206000.json','["一室焚香即太初，萬人如海儘從渠。", "第於心上曾無着，何必山中始可居。", "垂箔護花嫌引蝶，連筒汲井怕生魚。", "草玄政不妨人事，問字敲門未可疎。"]'),
('e592c6f0-139c-4ecb-9a20-2928edbf46e8','元日寓越之三江','毛珝','宋','宋诗','song-poetry','','[]','客裏元正最可憐，就他香案禮蒼天。',64,'全唐诗/poet.song.206000.json','["客裏元正最可憐，就他香案禮蒼天。", "懶拈蓍草占新歲，頻對菱花憶去年。", "僅有邸翁分席拜，不如野老着衣鮮。", "百年草草渾如此，且醉殘梅了目前。"]'),
('2512e201-3f3c-4ee4-8ab2-2ba67f7e8e42','桂','毛珝','宋','宋诗','song-poetry','','[]','天上分來種異常，年年花占菊前黄。',64,'全唐诗/poet.song.206000.json','["天上分來種異常，年年花占菊前黄。", "堆將龍麝應難敵，隔盡屏帷亦透香。", "此日且饒秋富貴，全家疑在月中央。", "明朝酒醒風吹盡，贏得黄金滿步廊。"]'),
('0677cf09-faea-4e8b-a06b-aed285a8daae','滄浪亭','毛珝','宋','宋诗','song-poetry','','[]','濯纓人去水空寒，事屬明時欲問難。',32,'全唐诗/poet.song.206000.json','["濯纓人去水空寒，事屬明時欲問難。", "日暮客歸園館閉，鷺鷥飛上石棋盤。"]'),
('9252cc39-5d0b-4d7d-be9f-294847d44650','石湖','毛珝','宋','宋诗','song-poetry','','[]','一片湖光接薜蘿，功名餘事屬吟多。',32,'全唐诗/poet.song.206000.json','["一片湖光接薜蘿，功名餘事屬吟多。", "至今魚鳥皆堪敬，曾見烏巾照碧波。"]'),
('812cbb39-2e3f-4e9b-bccc-e6f0f3fc9d89','西興寄呈','毛珝','宋','宋诗','song-poetry','','[]','生平未始識東州，不謂招邀得漫遊。',64,'全唐诗/poet.song.206000.json','["生平未始識東州，不謂招邀得漫遊。", "南鎮門前秦望曉，西興浦口浙江秋。", "風摶怒氣潮初落，山湧青冥雨乍收。", "豈爲登臨重回首，使星只在五雲頭。"]'),
('e86616bd-dff4-4cb4-83fe-1bcd2d1207e1','訪白玉蟾值其出題壁','黄春伯','宋','宋诗','song-poetry','','[]','怪訪怪，怪不在。',16,'全唐诗/poet.song.206000.json','["怪訪怪，怪不在。", "茅君山，來相待。"]'),
('58c2b4f8-a88c-42d2-86b7-9f0919746dd2','絕句','黄春伯','宋','宋诗','song-poetry','','[]','半篙春水一蓑烟，抱月懷中枕斗眠。',32,'全唐诗/poet.song.206000.json','["半篙春水一蓑烟，抱月懷中枕斗眠。", "說與時人休問我，英雄迴首即神仙。"]'),
('62825ab2-6565-4d51-8c27-604fdb21e3c3','寄三山彭鶴林','白玉蟾','宋','宋诗','song-poetry','','[]','瞻彼鶴林，在彼無諸。',100,'全唐诗/poet.song.206000.json','["瞻彼鶴林，在彼無諸。", "鼓山之下，螺江之隅。", "瞻彼鶴林，在彼長樂。", "嵩山之上，螺江之角。", "一別鶴林，春聿雲杪。", "青山之外，落花啼鳥。", "一望鶴林，回首千里。", "斜陽之外，白雲流水。", "日復一日，思我鶴林。", "鴈斷魚沉，實傷我心。"]'),
('7176811b-9707-4b59-a144-59ad143943fb','暑熱','白玉蟾','宋','宋诗','song-poetry','','[]','玉友避嫌，竹奴專寵。',20,'全唐诗/poet.song.206000.json','["玉友避嫌，竹奴專寵。", "聽官丐閑，詩勇不將。"]'),
('a251dd92-729d-470a-96d0-0a6c399fe5fc','紅巖感懷四首  其一','白玉蟾','宋','宋诗','song-poetry','','[]','山高兮風寒，煙濛濛兮雨漫漫。',34,'全唐诗/poet.song.206000.json','["山高兮風寒，煙濛濛兮雨漫漫。", "雨霽兮雪飛，半夜無人兮倚欄。", "明月兮空山。"]'),
('b23d098a-f494-4f12-b653-a6c3a663a076','紅巖感懷四首  其二','白玉蟾','宋','宋诗','song-poetry','','[]','猿啼兮鳥哀，風颼颼兮雪皚皚。',34,'全唐诗/poet.song.206000.json','["猿啼兮鳥哀，風颼颼兮雪皚皚。", "雪霽兮雲收，思我故人兮傷懷。", "古徑兮蒼苔。"]'),
('83092074-bffe-4b75-9dcf-9d8794728e84','紅巖感懷四首  其三','白玉蟾','宋','宋诗','song-poetry','','[]','風悲兮花落，鳥哀哀兮水簌簌。',34,'全唐诗/poet.song.206000.json','["風悲兮花落，鳥哀哀兮水簌簌。", "水寒兮石蒼，幽人自感兮惸獨。", "古洞兮枯木。"]'),
('8f81d765-fbd2-4172-af31-9774bd8c6957','紅巖感懷四首  其四','白玉蟾','宋','宋诗','song-poetry','','[]','草青兮煙冷，山蒼蒼兮水楚楚。',34,'全唐诗/poet.song.206000.json','["草青兮煙冷，山蒼蒼兮水楚楚。", "山深兮地僻，青鳥不來兮凄苦。", "斷煙兮荒草。"]'),
('8dd02f15-79ae-49a9-a836-84a475b0bf27','孤鶴辭','白玉蟾','宋','宋诗','song-poetry','','[]','芝田長相依，瑶池長相隨。',72,'全唐诗/poet.song.206000.json','["芝田長相依，瑶池長相隨。", "雲泥共悲歡，生死同襟期。", "行啄林莽間，斷翅誰與醫。", "往者不可復，病者不得飛。", "極目青雲中，臨風翹以思。", "思深不復啄，一唳天容悲。"]'),
('1d20e423-a827-4676-b26d-45c6914e87a1','楓葉辭','白玉蟾','宋','宋诗','song-poetry','','[]','丹楓隕葉紛墮飛，撩撥西風盡倒吹。',72,'全唐诗/poet.song.206000.json','["丹楓隕葉紛墮飛，撩撥西風盡倒吹。", "雲外飄飄呼莫回，四方沉冥鴈爲悲，辭柯一去遐不歸。", "已判此秋長別離，生者有盡死有期。", "憑高望遠深相思，手揮絲桐送斜暉。"]'),
('56622763-e61e-40f4-8bca-9195af0e9561','臨安天慶陳道士濩武夷贈之','白玉蟾','宋','宋诗','song-poetry','','[]','七閩多山水，兩淮好風月。',36,'全唐诗/poet.song.206000.json','["七閩多山水，兩淮好風月。", "瀟湘之烟雲，巴廣之雨雪。", "收拾歸武林，細與令師說。"]'),
('f0e97f81-0f55-4a25-accd-b36a59bcbfaf','孤鴈嘆','白玉蟾','宋','宋诗','song-poetry','','[]','孤鴈聲嚘嚘，憂如司馬牛。',48,'全唐诗/poet.song.206000.json','["孤鴈聲嚘嚘，憂如司馬牛。", "君不見煮豆燃豆萁，斯人者斗米尺布渠豈羞。", "知有鶺鴒在原不，知有棠棣之華不。"]'),
('6bb92971-781a-4b18-add9-0cbb27a627c0','梧州江上夜行','白玉蟾','宋','宋诗','song-poetry','','[]','雲去雲來幾點星，城頭畫鼓轉三更。',64,'全唐诗/poet.song.206000.json','["雲去雲來幾點星，城頭畫鼓轉三更。", "草深螢聚渾成燐，月暗鶴飛惟有聲。", "何處夜航鳴櫓過，滄江如鏡煙半破。", "忽然長嘯驚沙鷗，飛入前山不留箇。"]'),
('0a96786b-c329-4741-85ab-5320384b7d76','悲風曲','白玉蟾','宋','宋诗','song-poetry','','[]','山風凄冷山木悲，虎不敢嘯鬼夜啼。',64,'全唐诗/poet.song.206000.json','["山風凄冷山木悲，虎不敢嘯鬼夜啼。", "溪聲暗繞蒼苔路，翠羽絲毛寒不棲。", "幽人此時樓上立，葉照松梢露珠泣。", "有酒欲飲飲不成，月華縹緲煙光濕。"]'),
('ee19f02d-cf6c-4b19-a16f-f624e2cdc8c8','紅樓曲','白玉蟾','宋','宋诗','song-poetry','','[]','紅樓貯飛瓊，夜夜令人憶。',48,'全唐诗/poet.song.206000.json','["紅樓貯飛瓊，夜夜令人憶。", "回盼千山外，天遠暮雲碧。", "西風白芙蓉，往事殆陳迹。", "爲我收眼纈，織得愁成疋。"]'),
('1afc20a0-65ce-4d57-a92e-3a7a6c85f023','暮雲辭','白玉蟾','宋','宋诗','song-poetry','','[]','雲行太虛中，薄暮何冥冥。',108,'全唐诗/poet.song.206000.json','["雲行太虛中，薄暮何冥冥。", "仰望青松梢，上有白雪翎。", "千巖舞落葉，萬樹羅翠屏。", "流水咽寒澗，湛露濡香蘅。", "幽人一回首，家世渺浮萍。", "蓬萊在何許，絳闕邈太清。", "青鳥杳不來，白雲去玉京。", "夫我何悽其，悵哉此幻形。", "注目玉霄峰，青猿一聲聲。"]'),
('0c417298-2bab-4ba2-b754-879c0b2abcd4','有贈','白玉蟾','宋','宋诗','song-poetry','','[]','我見千家閙管絃，金瓶玉水養春妍。',64,'全唐诗/poet.song.206000.json','["我見千家閙管絃，金瓶玉水養春妍。", "一朝花落空枝在，爨下焦枯亦可憐。", "曾聞李白之詩否，以色事人幾長久。", "斷蘂殘英尚未衰，月明人立黄昏柳。"]'),
('7216c1f4-a2a4-4bcb-ba33-c0be82aafb58','筆架山','白玉蟾','宋','宋诗','song-poetry','','[]','吾是瑶臺翰墨仙，操觚弄槧玉皇前。',128,'全唐诗/poet.song.206000.json','["吾是瑶臺翰墨仙，操觚弄槧玉皇前。", "翻雲爲墨海爲硯，一片寒空如雪牋。", "兔豪象管用不得，倒蘸崑崙醉鈎畫。", "當年染罷八角芒，金闕上章求放逸。", "三峯坐斷江南天，臨汝城頭蒼蒼然。", "狀如筆架翠起伏，與吾閣筆齁齁眠。", "山靈驚呼猿鳥亂，清魂復被風吹散。", "起來叫問山前人，幾度松枯白石爛。"]'),
('1faa5335-798e-4bd4-ba05-7897e070edde','積翠樓','白玉蟾','宋','宋诗','song-poetry','','[]','飛雲湧浪天邊來，翠色迷空撥不開。',64,'全唐诗/poet.song.206000.json','["飛雲湧浪天邊來，翠色迷空撥不開。", "逸人憐此一崔嵬，峨翬危簷倚翠堆。", "客來樓前認林樾，坐久神爽愈飛越。", "移時雙鶴何處歸，遥見前山兩點雪。"]'),
('c358aa11-9496-476e-8741-6c6b67210a2c','妾薄命','白玉蟾','宋','宋诗','song-poetry','','[]','妾居西北方，容貌亞冰雪。',144,'全唐诗/poet.song.206000.json','["妾居西北方，容貌亞冰雪。", "妾長嗟無媒，孤影對明月。", "頭綰墮馬髻，脚襯凌波襪。", "釵梁溜金鳳，舞带蒙錦纈。", "頸瑳素玉圓，胸瑩新酥滑。", "翠靨中蛾眉，瑶花嚲鴉髮。", "腰裊柳絲輕，臉潤桃花發。", "出郊乘紫騮，蔽目舉青繖。", "不敢一回首，煙際暗愁結。", "誰家白面郎，志氣何飄揚。", "使妾一過眼，吾肉燔如湯。", "自惟父母嚴，折花回倚牆。"]'),
('dbf98c1c-0dae-4bf1-ac39-00c66694ee22','陌上桑','白玉蟾','宋','宋诗','song-poetry','','[]','春深陌上桑，羣蠶頼以食。',108,'全唐诗/poet.song.206000.json','["春深陌上桑，羣蠶頼以食。", "鞠蠶妾之事，采桑妾之職。", "桑老蠶繭成，幸而筥筐實。", "繰之復紡之，妾復躬紝維。", "織成一端練，于以蔽袒裼。", "使君一問桑，下車輒思惑。", "妾固願相從，妾夫不足惜。", "安得以婦人，而滅使君德。", "使君勿內熱，妾心堅如石。"]'),
('17d7300d-e411-4588-ba5f-342b3ccc6c2f','孤鴻曲','白玉蟾','宋','宋诗','song-poetry','','[]','秋陰薄薄天風凄，黄落滿空孤鴻飛。',104,'全唐诗/poet.song.206000.json','["秋陰薄薄天風凄，黄落滿空孤鴻飛。", "志在江湖叫何悲，桂枝初花來幾時。", "得非往者失塤箎，雲情月思哀獨歸。", "青霄高處更危機，胡不少棲欲何之，霜翎雨翅不自持。", "非無稻粱與菰黍，食不下咽情永辭。", "江頭弔影鳴愈悽，嘹唳之聲矧可思。"]'),
('6189daa1-feb2-42ad-a7f3-a6a47cd5ee7d','初至梧州','白玉蟾','宋','宋诗','song-poetry','','[]','夜半江風吹竹屋，起挑寒燈憐影獨。',64,'全唐诗/poet.song.206000.json','["夜半江風吹竹屋，起挑寒燈憐影獨。", "荒雞亂啼思轉多，黠鼠嘯躍眠不熟。", "舊曲情聲覺悲凉，故園心眼時斷續。", "何當牽犬臂蒼鷹，錦帽貂裘呼蹴踘。"]'),
('545643f4-c489-4a2b-aae1-4d63668704b9','歲晚書懷','白玉蟾','宋','宋诗','song-poetry','','[]','歲事忽婉娩，旅懷良爾悲。',168,'全唐诗/poet.song.206000.json','["歲事忽婉娩，旅懷良爾悲。", "風霧起無邊，雨雪凄霏霏。", "豈無銷金帳，唱飲羊羔兒。", "寄食他人門，屏息從所依。", "鵰鶚翔九天，鷦鷯巢一枝。", "煙霄有熟路，我當何時歸。", "人間自富榮，信美非所宜。", "朱顔日已改，華髮漸復稀。", "觸目思遠人，勝賞懷昔時。", "園林向衰謝，青山吞斜暉。", "坐久露華重，吟殘雲意遲。", "晴空清已曠，寒月滿我衣。", "莫言一杯酒，容易相對持。", "病鸐棲草亭，會須唳聲飛。"]'),
('b3f8b662-a5f9-4647-906d-ad62ca7c28d6','黄葉辭','白玉蟾','宋','宋诗','song-poetry','','[]','男兒鐵石腸，遇秋多凄凉。',120,'全唐诗/poet.song.206000.json','["男兒鐵石腸，遇秋多凄凉。", "節物遽凋變，今古堪悲傷。", "西來白帝風，暗驚萬葉黄。", "拚與舞零落，此意付夕陽。", "堪嘆遠行子，隻影天一方。", "佳人去不返，蒼煙冥八荒。", "對此一黯然，兩鬢沾吳霜。", "自顧蒲柳姿，眇在煙水鄉。", "晚汀慨鴻鴈，夜浦羞鴛鴦。", "何當從宋玉，問路遊高唐。"]'),
('15a8bba8-8b11-40fd-8a4c-cb9b05ef934b','明妃曲','白玉蟾','宋','宋诗','song-poetry','','[]','行行莫敢悲，一死復千怨。',204,'全唐诗/poet.song.206000.json','["行行莫敢悲，一死復千怨。", "脫身歌舞中，姊姒不足戀。", "蠻帳紫茸氈，雖卑固不賤。", "昔在後宮時，幾見君王面。", "君王有鳳偶，不數芹邊燕。", "儻曾賜御覽，豈爲畫所幻。", "粉黛相嶔巇，亦懼人彘變。", "但念辭鄉國，遠適堪慨嘆。", "此時漢無策，聊塞呼韓願。", "非無霍嫖姚，兩國慮塗炭。", "欲寬公卿憂，隻影非所羨。", "敬將金繒行，不覺淚珠濺。", "請行安得辭，心心存漢殿。", "所憐毛延壽，既殺不可諫。", "馬蹄蹴胡塵，曉月光燦燦。", "悽愴成琵琶，千古庶自見。", "他時冢草青，漢使或一奠。"]'),
('6cce74f8-d5d7-455c-b1d5-9014cb02be5d','公無渡河','白玉蟾','宋','宋诗','song-poetry','','[]','君不見猿啼蒼梧煙，風捲瀟湘水。',97,'全唐诗/poet.song.206000.json','["君不見猿啼蒼梧煙，風捲瀟湘水。", "雙蛾無處挽重瞳，粉篁點點凝春淚。", "又不見鶴飲瑶池月，露泣龜臺花。", "百官極目望八駿，青鳥寥寥空暮霞。", "嗚呼，不自愛惜甘蹈死，亦不聞乎千金子。", "公無渡河要渡河，公要渡河爭奈何。"]'),
('da3b789b-d31f-47ad-91a5-d0827cd3991e','長歌行','白玉蟾','宋','宋诗','song-poetry','','[]','厥初由閥閲，吾志在林泉。',288,'全唐诗/poet.song.206000.json','["厥初由閥閲，吾志在林泉。", "爲舜不無地，睎顔儘有天。", "魚蟲猶可佛，雞犬皆登仙。", "顧我非六六，荷天良拳拳。", "幼時氣宇壯，長日文彩鮮。", "琴劍微暖席，江湖動經年。", "異乎三子撰，契彼五家禪。", "既已出洙泗，從而師偓佺。", "肩依洪崖右，道在靈運前。", "所得既天祕，與交又國賢。", "可圖大藥資，以辦買山錢。", "東訪鼎湖浪，西尋蒼梧煙。", "一寸百煉剛，半生雙行纏。", "簪紳非無欲，魚鳥從所便。", "逸興五湖闊，虛名四海傳。", "飽餐青精飯，細讀黄石編。", "頃自七閩出，放焉迷市廛。", "紅塵刺人眼，名利交相煎。", "富貴已嘗鼎，雲霄當著鞭。", "蹉跎度青春，遲暮即華顛。", "且有安期棗，與夫泰華蓮。", "高陵易爲谷，滄海俄成田。", "光景亦倏忽，物華隨變遷。", "仰天時一笑，顧影長自憐。"]'),
('96115268-cbe6-4575-bc6e-4283cd82b51f','聽猿','白玉蟾','宋','宋诗','song-poetry','','[]','三樹五樹啼寒猿，一聲兩聲落耳根。',64,'全唐诗/poet.song.206000.json','["三樹五樹啼寒猿，一聲兩聲落耳根。", "吾疑耳到猿啼處，却是猿聲隨風奔。", "猿聲不悲亦不怨，吾亦於世何所戀。", "夜深月白風籟寒，聽此忽然毛骨換。"]'),
('e4c643dd-19c2-4dd4-8011-22021b9199d1','徯鶴','白玉蟾','宋','宋诗','song-poetry','','[]','白雲無消息，黄鶴杳不歸。',48,'全唐诗/poet.song.206000.json','["白雲無消息，黄鶴杳不歸。", "華表風露冷，臨臯星斗稀。", "不念桑田變，但向瑶臺飛。", "盍不歸來乎，翩然點翠微。"]'),
('a37e0be5-d3b5-48ad-aba9-5940a1d13b9d','挹爽','白玉蟾','宋','宋诗','song-poetry','','[]','高人今居筆架山，蒼煙冥濛常風寒。',96,'全唐诗/poet.song.206000.json','["高人今居筆架山，蒼煙冥濛常風寒。", "西壁千巖青未了，萬頃嵐光薄清曉。", "曉來軒窗敞且明，風櫺月牖一壺冰。", "雞聲未斷鍾聲起，起飲沆瀣朝紫清。", "人間紅塵刺人眼，世上蝸蠅徒爾亂。", "豈復知此爽氣佳，已被高人俱占斷。"]'),
('1c89b631-193a-438e-af27-3b2f56fe5308','舒嘯','白玉蟾','宋','宋诗','song-poetry','','[]','豁然登高臺，四天一何眇。',48,'全唐诗/poet.song.206000.json','["豁然登高臺，四天一何眇。", "舒懷摩丹田，靜境萬籟悄。", "前村生孤煙，半山吞殘照。", "倚劍呼黄鶴，遽然發長嘯。"]'),
('67691808-cf06-4c83-bdab-5f5c272a2d36','姚魏堂','白玉蟾','宋','宋诗','song-poetry','','[]','青帝收成功，乃王木芙蓉。',48,'全唐诗/poet.song.206000.json','["青帝收成功，乃王木芙蓉。", "姚魏久燮理，功成盍受封。", "向已魁梅花，此當相芍藥。", "桃李寂不言，蜂蝶寒無托。"]'),
('0886ac0d-7995-4a18-a2d6-310f06d9e21b','希夷堂','白玉蟾','宋','宋诗','song-poetry','','[]','道人久矣泯耳目，蕭然自如脫羈束。',64,'全唐诗/poet.song.206000.json','["道人久矣泯耳目，蕭然自如脫羈束。", "朝隨扶桑日頭起，暮趁崑崙雲脚伏。", "青牛過關今幾年，此道分明在目前。", "昨夜琴心三疊後，一堂風冷月娟娟。"]'),
('5a438c60-881f-4289-85a5-f42cffcf5391','秋宵辭  其一','白玉蟾','宋','宋诗','song-poetry','','[]','秋色何凄凄，奈此可憐宵。',60,'全唐诗/poet.song.206000.json','["秋色何凄凄，奈此可憐宵。", "銀河望不極，萬籟凉蕭蕭。", "雲花遠縹緲，月影寒寂寥。", "一鴈蹲滄洲，羣螢飛斷橋。", "仰盼蒼松枝，黯然不自聊。"]'),
('501e0beb-8ba8-48a5-9bcc-60969ec70216','秋宵辭  其二','白玉蟾','宋','宋诗','song-poetry','','[]','長天滑如紙，皓月寒如水。',60,'全唐诗/poet.song.206000.json','["長天滑如紙，皓月寒如水。", "今人成古人，人生復能幾。", "顧此清凉夜，此情不自已。", "聊以寫懷抱，黯黯泣神鬼。", "所泣復何言，已矣復已矣。"]'),
('5bf74dbe-fb6d-4112-b051-62c3ed9b727e','秋宵辭  其三','白玉蟾','宋','宋诗','song-poetry','','[]','仰觀銀河月，千林散寒光。',60,'全唐诗/poet.song.206000.json','["仰觀銀河月，千林散寒光。", "佳人今何之，遠在天一方。", "秋聲酸我鼻，秋色斷我腸。", "夜深倚西風，清淚如雨霶。", "世有千里馬，可憐無王良。"]'),
('9cf8d431-a7b3-482d-8b4c-df3bc6fd5779','秋宵辭  其四','白玉蟾','宋','宋诗','song-poetry','','[]','空山寂無人，出門但明月。',60,'全唐诗/poet.song.206000.json','["空山寂無人，出門但明月。", "悲哉誰與論，對此一愁絕。", "清露襲衣裳，凉風逼毛髮。", "淚雨忽復晴，愁雲悄自滅。", "顧影青松下，此意在絳闕。"]'),
('e3ab620a-8b71-466a-a44e-7cb65a7baeb6','秋宵辭  其五','白玉蟾','宋','宋诗','song-poetry','','[]','長天與遠水，極目煙冥茫。',60,'全唐诗/poet.song.206000.json','["長天與遠水，極目煙冥茫。", "暮鴻孤悲鳴，霜林萬葉黄。", "倚松望翠微，數點寒螢光。", "吾非長夜魂，墮此寂寞鄉。", "衷情憑誰訴，空山草木長。"]'),
('1c466070-307b-4d0c-8816-99eccc19315d','秋宵辭  其六','白玉蟾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','月華明如許，秋色清可掬。',60,'全唐诗/poet.song.206000.json','["月華明如許，秋色清可掬。", "小立西湖道，瀰漫芰荷綠。", "人生真是夢，造物不可覆。", "英雄受凄凉，嬌騃飽粱肉。", "湖山却見知，對人長青目。"]'),
('3efee278-e095-4d56-92b8-7b3ff0cacab7','秋宵辭  其七','白玉蟾','宋','宋诗','song-poetry','','[]','眇哉青松梢，高高九千尺。',60,'全唐诗/poet.song.206000.json','["眇哉青松梢，高高九千尺。", "兩班森道傍，暮起凄黯色。", "嗟彼昂藏姿，山林端可惜。", "浩然呼西風，夜深鳴蕭瑟。", "此意偶相似，嘆息復嘆息。"]'),
('ad502e5f-e28d-4ab1-b5b5-251e6c0de884','秋宵辭  其八','白玉蟾','宋','宋诗','song-poetry','','[]','孤月明秋空，清影跨洞門。',60,'全唐诗/poet.song.206000.json','["孤月明秋空，清影跨洞門。", "彼美嬋娟姿，的是姮娥魂。", "凄然到書帙，惸然入酒樽。", "不歸廣寒家，夜游天子園。", "無人知此懷，驚煙籠啼猿。"]'),
('9898aeb6-6834-491b-b280-56978ec63ce2','秋宵辭  其九','白玉蟾','宋','宋诗','song-poetry','','[]','吾身如浮雲，縹緲歸無家。',60,'全唐诗/poet.song.206000.json','["吾身如浮雲，縹緲歸無家。", "又如孤飛鴈，不鳴跧蓼花。", "路傍多青草，無語閲歲華。", "野外亦有蘭，抱香委泥沙。", "夫豈造物者，故欲孤此邪。"]'),
('5dcb1cc6-152d-4747-a00f-764900a6d7ca','秋宵辭  其一○','白玉蟾','宋','宋诗','song-poetry','','[]','清秋薄湖山，蒲柳生寒煙。',61,'全唐诗/poet.song.206000.json','["清秋薄湖山，蒲柳生寒煙。", "悵望荷花中，誰家鳴筦筦絃。", "豈復念伊人，孤影芙蓉邊。", "吸風咀月露，照水時自憐。", "暗懷夜光寶，長吁不成眠。"]'),
('28e08f10-0c74-4858-ac79-231aa712aacb','秋宵辭  其一一','白玉蟾','宋','宋诗','song-poetry','','[]','佳人遽成古，冰魂喚不譍。',60,'全唐诗/poet.song.206000.json','["佳人遽成古，冰魂喚不譍。", "料得冥冥中，憐我身如僧。", "松間一太息，樹吼蒼雲崩。", "幽愁積如山，心上一層層。", "成連與瓠巴，枯骨悲荒陵。"]'),
('908a833e-2e85-4280-9ce1-c80555736ade','秋宵辭  其一二','白玉蟾','宋','宋诗','song-poetry','','[]','此身非我有，在世聊爾爲。',60,'全唐诗/poet.song.206000.json','["此身非我有，在世聊爾爲。", "於此儻有得，夫復何所悲。", "遂將鬰抑懷，寫作悽苦辭。", "如彼深閨婦，暗起鴛鴦思。", "蒼蒼亦有耳，此情知不知。"]'),
('c38855f5-d2b1-43fc-868f-96e514da4537','凝翠','白玉蟾','宋','宋诗','song-poetry','','[]','香穟飛紫煙，茗花湧白雪。',48,'全唐诗/poet.song.206000.json','["香穟飛紫煙，茗花湧白雪。", "坐對松竹林，已換塵俗骨。", "前山多翠色，凝然暮欲滴。", "凭欄拍掌呼，天外鶴來一。"]'),
('47f366df-35fa-4325-9b17-518eaed68e63','述古  其一','白玉蟾','宋','宋诗','song-poetry','','[]','黍大青混沌，此即萬化鞘。',96,'全唐诗/poet.song.206000.json','["黍大青混沌，此即萬化鞘。", "盤古不得窺，鑿之忽七竅。", "太樸既脫手，銀蝠乃夜嘯。", "乾坤兩餠分，日月雙丸跳。", "九鴉方爇天，致渠共工鬭。", "額血不周山，山裂天西漏。", "媧皇煉彩石，一發大庭笑。", "宓犧方蛇蟠，商契亦燕鷇。"]'),
('0c6aaeb3-990c-4ee1-87a7-4bf069c89937','述古  其二','白玉蟾','宋','宋诗','song-poetry','','[]','帝子御飛龍，鼎湖叫奚爲。',72,'全唐诗/poet.song.206000.json','["帝子御飛龍，鼎湖叫奚爲。", "玉京鬰崔嵬，銀河汎渺瀰。", "俯首視紅塵，萬蟻紛何知。", "乘雲遊八極，手翫珊瑚枝。", "湯武事干戈，此事矧肯期。", "但聞穆天子，八駿曾瑶池。"]'),
('1385a71c-7f24-4f65-953f-0c595384d665','述古  其三','白玉蟾','宋','宋诗','song-poetry','','[]','河水一鏡清，中有驪龍舞。',72,'全唐诗/poet.song.206000.json','["河水一鏡清，中有驪龍舞。", "波心呈寶圖，始脈造化祖。", "燧人鑽炎凉，炎帝餌甘苦。", "身披獝狨衣，口服觳觫乳。", "此時至尊者，帝階三尺土。", "嬴政築阿房，籛鏗纔傴僂。"]'),
('bba93b97-4a8c-45e4-82a8-0d189604ff7f','山中憶鶴林  其一','白玉蟾','宋','宋诗','song-poetry','','[]','碧桃兮花落，青鳥去兮春寂寞。',28,'全唐诗/poet.song.206000.json','["碧桃兮花落，青鳥去兮春寂寞。", "風止兮雪霽，望美人兮天一角。"]'),
('6da0be8a-0e39-404c-a71a-7e624600a808','山中憶鶴林  其二','白玉蟾','宋','宋诗','song-poetry','','[]','可惜兮春光，芹泥香兮燕忙。',27,'全唐诗/poet.song.206000.json','["可惜兮春光，芹泥香兮燕忙。", "花紅兮水暖，望美人兮天一方。"]'),
('3ca42374-f34a-4445-bf7c-cdc8fd601867','山中憶鶴林  其三','白玉蟾','宋','宋诗','song-poetry','','[]','白雲兮孤飛，鴈向北兮燕南枝。',28,'全唐诗/poet.song.206000.json','["白雲兮孤飛，鴈向北兮燕南枝。", "青山兮方疊，望美人兮天一涯。"]'),
('7ef7682f-7bdc-46a0-8441-0d31c3e52c53','山中憶鶴林  其四','白玉蟾','宋','宋诗','song-poetry','','[]','蒼崖兮巍巍，對落花兮倚斜暉。',28,'全唐诗/poet.song.206000.json','["蒼崖兮巍巍，對落花兮倚斜暉。", "猿啼兮鶴唳，望美人兮天一隅。"]'),
('02159ae3-e0a6-45ae-ba47-e7df7f484cce','棲霞','白玉蟾','宋','宋诗','song-poetry','','[]','冷煙纏山腰，暗水冽石骨。',48,'全唐诗/poet.song.206000.json','["冷煙纏山腰，暗水冽石骨。", "欲風松先鳴，未雨苔已滑。", "洞前多琪花，洞裏多紫霞。", "高人得所棲，日永蒸胡麻。"]'),
('9d1260a2-754c-48df-b20c-1901f749a09f','習劍','白玉蟾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','劍法年來久不傳，年來劍俠亦無聞。',64,'全唐诗/poet.song.206000.json','["劍法年來久不傳，年來劍俠亦無聞。", "一從袖裏青蛇去，君山洞庭空水雲。", "逸人習劍得其訣，時見巖前青石裂。", "何如把此入深番，爲國瀝盡匈奴血。"]'),
('17f253ae-4721-41da-be1e-0a2d909d04e7','夜坐','白玉蟾','宋','宋诗','song-poetry','','[]','硯水寒欲冰，燭蠟凝成淚。',48,'全唐诗/poet.song.206000.json','["硯水寒欲冰，燭蠟凝成淚。", "月夜天飛霜，瑣窗人不寐。", "萬竹舞風青，孤松溘露翠。", "樓前呼黄鶴，凄然發清唳。"]'),
('ab891164-9f28-450d-b9b7-80ae2d050d79','百丈巖觀水','白玉蟾','宋','宋诗','song-poetry','','[]','手携青藜杖，巖上俯清池。',108,'全唐诗/poet.song.206000.json','["手携青藜杖，巖上俯清池。", "池水夜來冰，凍磷殊未澌。", "戲以藜杖尖，斲破黄琉璃。", "橫杖擔兩片，忍凍巖前嬉。", "愛日怡我神，凉風吹我衣。", "應念石季倫，銷步錦金圍。", "終夜燒紅獸，但飲甘如飴。", "夫豈知山林，清寒益我姿。", "此意誰與論，巖下青松知。"]'),
('a987861f-acf4-43dc-b28e-ca9856bda317','少年行','白玉蟾','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','寸心鐵石壯，一面冰霜寒。',72,'全唐诗/poet.song.206000.json','["寸心鐵石壯，一面冰霜寒。", "落葉鬼神哭，出言風雨翻。", "氣呵泰山倒，眼吸滄海乾。", "怒立大鵬背，醉衝九虎關。", "飄然乘雲氣，俯首視世寰。", "散髮抱素月，天人咸仰觀。"]'),
('e5315d1c-93f7-43b0-b453-37f3a706896e','大霄觀風竿軒','白玉蟾','宋','宋诗','song-poetry','','[]','蕭蕭從何來，撼我青琅玕。',48,'全唐诗/poet.song.206000.json','["蕭蕭從何來，撼我青琅玕。", "笙簫動天籟，雨露生秋寒。", "鐵笛不用吹，瑶琴不用彈。", "聽此夜不寐，山月落邯鄲。"]'),
('36c2a9af-55de-46f9-b459-56bba8c0d8bb','明月曲','白玉蟾','宋','宋诗','song-poetry','','[]','月色一何明，不堪顧孤影。',108,'全唐诗/poet.song.206000.json','["月色一何明，不堪顧孤影。", "倚樓暮風寒，舉手挈衣領。", "行雲若相憐，徘徊西風頂。", "强飲不成醉，幽情默自省。", "莫道負明月，明月亦應知。", "只知今夜我，不覺瓊樓時。", "我記在瓊樓，醉弄珊瑚枝。", "枝頭月明好，何曾解相惱。", "今夜涕汍瀾，只恐朱顔老。"]'),
('2e55562d-47dd-488b-83a3-2ab269a6f454','鴈','白玉蟾','宋','宋诗','song-poetry','','[]','嘹唳疇爾憐，凄凉去何渺。',48,'全唐诗/poet.song.206000.json','["嘹唳疇爾憐，凄凉去何渺。", "寧無稻粱謀，豈是江湖小。", "昆仲畏弓矰，奴儓失昏曉。", "關山夜月寒，風雨秋天杳。"]'),
('56fa564d-37b0-4a81-8077-755632d6fb0b','贈紫巖潘庭堅四首  其一','白玉蟾','宋','宋诗','song-poetry','','[]','我穿雙不借，已辦一莫難。',48,'全唐诗/poet.song.206000.json','["我穿雙不借，已辦一莫難。", "背劍嗟鏽鋏，腰瓢獨金丹。", "歲晏乃得子，勞作青眼看。", "行矣各努力，歲月颯已殘。"]'),
('2c7e4828-7f51-410c-9d26-9a9504fa165d','贈紫巖潘庭堅四首  其二','白玉蟾','宋','宋诗','song-poetry','','[]','得君四律詩，何啻百木難。',48,'全唐诗/poet.song.206000.json','["得君四律詩，何啻百木難。", "我老非田光，何以酬燕丹。", "俯挹流泉漱，仰把青天看。", "絳闕遥相期，莫待瓊花殘。"]'),
('3bae79ed-f3aa-4acc-9d5d-5e0bb98ece01','贈紫巖潘庭堅四首  其三','白玉蟾','宋','宋诗','song-poetry','','[]','無愁是雲愁，無羞是雪羞。',48,'全唐诗/poet.song.206000.json','["無愁是雲愁，無羞是雪羞。", "我非雲與雪，何以白我頭。", "日出雪自消，雨晴雲亦休。", "盛年輕弃擲，不及且娛遊。"]'),
('a1084cdd-916d-4551-ad7d-42927dda4443','贈紫巖潘庭堅四首  其四','白玉蟾','宋','宋诗','song-poetry','','[]','富貴非足羨，貧賤不足羞。',48,'全唐诗/poet.song.206000.json','["富貴非足羨，貧賤不足羞。", "張儀但有舌，周朴不惜頭。", "我少亦學劍，到此萬年休。", "知君耿素抱，曷不遠行遊。"]'),
('f41b4fe1-e9cf-4d67-949d-c93c34d5f23a','雙鵲','白玉蟾','宋','宋诗','song-poetry','','[]','蒼然東阿松，上有烏鵲枝。',63,'全唐诗/poet.song.206000.json','["蒼然東阿松，上有烏鵲枝。", "雙雙噪西風，而背夕陽歸。", "雙飛復雙止，長與蒼松期。", "饑啄鼎{嗈隹}巔，渴飲閩水湄。", "莫苦飛太遠，咫尺成相思。"]'),
('65b1ee15-c589-4704-a622-e8f8fcb7fd49','題黄庭經後','白玉蟾','宋','宋诗','song-poetry','','[]','琴心玉文洞玄玄，金鈕朱錦乃汝傳。',200,'全唐诗/poet.song.206000.json','["琴心玉文洞玄玄，金鈕朱錦乃汝傳。", "子能得之可長年，黄素鎮贋完且堅。", "橫理如髮約兩邊，從有赤道如朱絃。", "文居其間走玄蟻，飛雲相與爲終始。", "大道甚夷非力使，無爲自然有至理。", "誰能精專換骨髓，掃去俗塵不瑕穢。", "目中有神乃識真，白玉爲軹裝車輪，裏以天上翠織成。", "仙人樓居儼長生，鸞鶴翔舞猿猱輕。", "子能寶之慎勿輕，室宮之中夜自明。", "上清真人楊與許，焚香清齋接神女。", "手作此書留下土，千年流傳子爲主。", "東方蒼龍右白虎，四神嚴訶孰予侮。"]'),
('0601b5c1-7b30-44cd-91e9-a661c0c62532','西湖大醉走筆百韻','白玉蟾','宋','宋诗','song-poetry','','["\u897f\u6e56", "\u592a\u6e56", "\u5cb3\u9633\u697c"]','廼先天皇君，萬有七千祀。',288,'全唐诗/poet.song.206000.json','["廼先天皇君，萬有七千祀。", "迄彼大庭時，封於葛天氏。", "邈計幾何年，是生余小子。", "上清太極公，造道窮天髓。", "有晉勾漏侯，煉丹極地肺。", "豈曰其雲仍，容或有肖似。", "阿亾昔吞月，誕日非指李。", "少長異强袌，世家得源委。", "誰言空桑生，乃嗣白仲理。", "少傅仕唐朝，香山號居士。", "不曾受衣盂，漫自訪根柢。", "長是娛林泉，靡復鬨都鄙。", "光景長如絲，功名大似米。", "留情十種仙，托契五窮鬼。", "塵埃日以遥，富貴雲而已。", "允矣躬清明，聽之自贊毀。", "且非筆不鋒，自信文甚綺。", "接踵李杜壇，信威屈賈壘。", "既而倦釣鰲，何以更呼蟡。", "此念輕萬鍾，所懽在四美。", "青帝御山河，東風管紅紫。", "煙寒綠柳顰，日暖黄鸝喜。", "當此醉則歌，悠然起而舞。", "槐陰清晝長，蟬噪新聲止。"]'),
('2fd17ffc-7ae0-408d-b257-00f44ded25be','丹丘同王茶幹李縣尉高會','白玉蟾','宋','宋诗','song-poetry','','[]','佳友品字坐，寒宵未渠央。',240,'全唐诗/poet.song.206000.json','["佳友品字坐，寒宵未渠央。", "竹亭天籟動，梅塢月華香。", "酒與我爲春，我瘦如松蒼。", "遇酒輒一莞，梅竹侍我旁。", "以詩互塤箎，笑語逐飛觴。", "酒行三四周，五官舞明堂。", "王郎信矣偉，心胸浩琳瑯。", "咳唾亦珠玉，氣習無膏粱。", "頃來赤城天，謁我九華房。", "期俱控綠煙，汗漫遊帝鄉。", "李郎自可喜，契闊俄四霜。", "少日珠庭豐，今愈奕有光。", "手仗六尺藜，叩我青錦囊。", "不思蓬萊路，往昔同商羊。", "年時鼓高志，海上弄干將。", "笑撫蒼崔嵬，眇視碧浩茫。", "一別何沉綿，再見欲飛颺。", "胡不賈酒勇，相與形骸忘。", "燭花已三灺，醉墨方琳瑯。", "此樂良難常，人生易夕陽。"]'),
('0593dfef-3b15-4eed-8e26-a9f8b4f5f246','相思','白玉蟾','宋','宋诗','song-poetry','','[]','蕭瑟兮楓林，嗚咽兮巖泉。',84,'全唐诗/poet.song.206000.json','["蕭瑟兮楓林，嗚咽兮巖泉。", "於此明月夜，撥動相思絃。", "音容尚如昨，恩愛空自憐。", "天風吹廣寒，夜露飄飛仙。", "夫豈不垂念，孤鳳誰與眠。", "人生亦客寄，胡不俱死遄。", "使我向闌干，淚雨如涓涓。"]'),
('369b35ad-1c22-4704-a921-e054358955c9','自謂','白玉蟾','宋','宋诗','song-poetry','','[]','造物果小兒，可得問天公。',216,'全唐诗/poet.song.206000.json','["造物果小兒，可得問天公。", "一生貧到骨，萬感悲填胸。", "形神本塵坌，身世相羈籠。", "安得騎玉鼇，眇然追冥鴻。", "錦步四十里，濁哉一石崇。", "東閣萬張頤，哺一公孫洪。", "銅山流臭泉，到了埋鄧通。", "何如德行貴，晞顔師仲弓。", "文苑麗長春，學海深無窮。", "人自涇渭水，我但夷齊風。", "貂裘有何異，羊棗遠不同。", "人生水上萍，世事江頭楓。", "三思欲四休，一拙勝萬工。", "火宅煎殺人，此身如甑中。", "於道有所味，觸意無復忡。", "心杓指以南，性水决而東。", "鍊得身如鶴，始可沖秋空。", "道人亦不貧，朝灌三畦松。"]'),
('e0f30188-52a1-4111-a46a-ddee78178cbb','懷仙樓歌奉呈鶴林尊友','白玉蟾','宋','宋诗','song-poetry','','[]','閩爲昔無諸，山水實秀嫵。',288,'全唐诗/poet.song.206000.json','["閩爲昔無諸，山水實秀嫵。", "其間多神仙，後先各軒翥。", "任敦丹井寒，董奉杏壇古。", "雲飛鄧伯元，風御王玄甫。", "烏石隠士周，霍童仙君褚。", "王霸騎白龜，徐登跨黑虎。", "趙炳石室空，薛丕梅溪舉。", "何家九弟兄，黄老一宗祖。", "無處覓榴花，曾巔但煙雨。", "此身猶埃塵，不得奉笑語。", "偶亦嗜好同，於焉問出處。", "彼美彭鶴林，往在神霄府。", "名位居瑶臺，觴詠揮玉麈。", "不入鵷鷺行，甘與猿鶴侶。", "清譽塞江湖，大手壓燕許。", "西北有高樓，懷仙扁其所。", "生晚不同時，悵欲與爲伍。", "青蛇吼雲崖，黄鶴眇星渚。", "去去無消息，忡忡鎮凝佇。", "天上多歡娛，世間厭凄苦。", "鸞鳳相招携，雲泥少間阻。", "幾回心欲飛，不覺手自舞。", "倚欄數百年，歸日指可僂。", "先謁南華宮，次謁西王母。"]'),
('ed338344-9c10-4aa9-aeb7-242619035722','江子有懷','白玉蟾','宋','宋诗','song-poetry','','[]','寒夢去易回，歸心動復止。',96,'全唐诗/poet.song.206000.json','["寒夢去易回，歸心動復止。", "天涯一逆旅，身傍五窮鬼。", "渺渺三山雲，浩浩九江水。", "幽窗風雨夜，此情竟誰委。", "人生一夢耳，夢中復作夢。", "一夜月許明，千里思與共。", "我且執詩籌，爾或卧酒甕。", "夢回自搔首，此夢亦無用。"]'),
('43136fcb-cbed-4e48-95a3-a70ba302c5e6','游簡寂觀','白玉蟾','宋','宋诗','song-poetry','','[]','手把武夷竹，江山滿吾目。',240,'全唐诗/poet.song.206000.json','["手把武夷竹，江山滿吾目。", "落花稱意紅，芳草無心綠。", "雙澗瀉翠璚，羣山斷蒼玉。", "青林隠成帷，碧洞深如屋。", "煙鎖花間猿，雨驚巖下鹿。", "藥爐埋白雲，丹井浸枯木。", "虎岫聳錦屏，龍湫噴銀粟。", "晉人陸修靜，於此曾卜築。", "饑則餌嫩松，寒則披老槲。", "惠遠同種蓮，淵明共採菊。", "當年學阿彌，飛神到天竺。", "舊有曬藥臺，荆棘蔽幽谷。", "舊有朝元石，霧靄籠飛瀑。", "園桃曉猿攀，庭柏夜鶴宿。", "何人建琳宮，先生留寶躅。", "鐵板時敲茶，銅鐘曉喚粥。", "冠褐靄鏘鏘，車馬來僕僕。", "巨壑有魚飛，寒池足鴉浴。", "天高星斗寒，更深鬼神哭。", "到此風骨清，直欲騎黄鵠。"]'),
('b2c307d0-dfc3-448d-9666-c2fea3d8dbf3','結庵','白玉蟾','宋','宋诗','song-poetry','','[]','結庵居深山，靜中觀萬物。',60,'全唐诗/poet.song.206000.json','["結庵居深山，靜中觀萬物。", "綠苔封曉雲，蒼藤縛夜月。", "啼鳥掛巖頭，暗水洗石骨。", "風起山若雷，海翻浪似雪。", "少年不歸來，人間空白髮。"]'),
('fd337adb-53be-4639-b60c-4373e97efa18','玉澗橋','白玉蟾','宋','宋诗','song-poetry','','[]','長虹飲玉澗，飛下蒼松灣。',48,'全唐诗/poet.song.206000.json','["長虹飲玉澗，飛下蒼松灣。", "高僧一指呼，蜿蜒依青山。", "澗底綠水寒，倒影卧波間。", "行人此駐錫，直透趙州關。"]'),
('e747c4fa-9b99-436e-8ea9-756bbd85f5b7','明發石壁菴','白玉蟾','宋','宋诗','song-poetry','','[]','有客東北來，翩然袖青蛇。',168,'全唐诗/poet.song.206000.json','["有客東北來，翩然袖青蛇。", "掀髯石壁前，人間日已斜。", "前望羅浮山，千峰如排衙。", "魚龍吹海水，洒雨行天涯。", "何處安期生，種棗大如瓜。", "見說蒲澗中，尚有九節芽。", "後來葛稚川，亦得飯胡麻。", "自汲水簾洞，笑嚥黄金砂。", "海山冥古今，縹緲煙月賒。", "急呼南海神，采采扶桑花。", "我欲騎天風，去歸五雲家。", "整衣謁紫皇，及此鬢未華。", "嗟彼紅塵人，還如兔在罝。", "胡不學飛仙，白日昇九霞。"]'),
('fa6fef01-924b-47d4-a167-6515c11e84b4','題友人夜光詩集','白玉蟾','宋','宋诗','song-poetry','','[]','海底有明月，圓於明月輪。',48,'全唐诗/poet.song.206000.json','["海底有明月，圓於明月輪。", "得之一寸光，可買萬古春。", "石上栽花者，火中撈雪人。", "步行騎水牛，乃知無價珍。"]'),
('89efebd6-f404-4fc5-8839-29e73edc0f2b','贈譚倚','白玉蟾','宋','宋诗','song-poetry','','[]','丹山金鸑鷟，絳闕玉麒麟。',36,'全唐诗/poet.song.206000.json','["丹山金鸑鷟，絳闕玉麒麟。", "氣宇秋潭月，文章閬苑春。", "青雲露如掌，策騎上龍津。"]'),
('28ce2963-607c-4996-b3e9-83eeb4cb68ff','贈秦止齋','白玉蟾','宋','宋诗','song-poetry','','[]','名顯不如晦，身進不如退。',72,'全唐诗/poet.song.206000.json','["名顯不如晦，身進不如退。", "水澄秋月現，雲散春山在。", "神棲方寸間，心照大千界。", "虛室乃生白，天光始發泰。", "可以止則止，知止則不殆。", "冥茫無有邊，不在天地外。"]'),
('fc9f62d8-5226-4f58-b10a-58685daa3d04','瓊姬曲','白玉蟾','宋','宋诗','song-poetry','','[]','深深芙蓉城，鳳笛聲何長。',48,'全唐诗/poet.song.206000.json','["深深芙蓉城，鳳笛聲何長。", "綽約六銖衣，雲中弄明鐺。", "瓊姿夜月暖，玉唾春風香。", "去去勞悵想，峽猿嘯高唐。"]'),
('f8b85ff5-c7a8-49a4-90ad-7e3e126e7572','憶留紫元古意  其一','白玉蟾','宋','宋诗','song-poetry','','[]','東風若有情，吹我夢魂飛。',48,'全唐诗/poet.song.206000.json','["東風若有情，吹我夢魂飛。", "燈前半夜醒，枕上三山歸。", "二子相與言，相執不相違。", "何處一聲鍾，寒淚滴征衣。"]'),
('f3517cd6-e866-4823-ab83-bc825edad023','憶留紫元古意  其二','白玉蟾','宋','宋诗','song-poetry','','[]','爲山莫太高，太高常苦寒。',48,'全唐诗/poet.song.206000.json','["爲山莫太高，太高常苦寒。", "恩愛莫太深，太深別離難。", "黄鶴今何之，白雲不復還。", "暗想紫仙堂，月照雙飛鸞。"]'),
('e064212f-d345-4073-bbf1-d4d8b255f21d','寒碧','白玉蟾','宋','宋诗','song-poetry','','[]','清秋訪林館，寒碧凝瑶風。',108,'全唐诗/poet.song.206000.json','["清秋訪林館，寒碧凝瑶風。", "冷入琅玕聚，凉生琛玉叢。", "枝枝撐明月，葉葉起清風。", "朝雲掛餘翠，夕照摇殘紅。", "斷鴉噪方宿，鳴鳳棲復沖。", "扶疎玉梵府，析蔌水晶宮。", "露花滴翡翠，煙絮纏蛟龍。", "萬竿響笙竽，一林撼絲桐。", "飲罷身欲蛻，聯鑣翔太空。"]'),
('32b69713-d88e-40e2-8eee-6689b8eac421','樓前雨霽','白玉蟾','宋','宋诗','song-poetry','','[]','飛廉驅鐵騎，萬雨飛落地。',48,'全唐诗/poet.song.206000.json','["飛廉驅鐵騎，萬雨飛落地。", "煙淡松自蒼，風起竹似醉。", "倚窗橫膝琴，政有作詩意。", "白鳥忽飛來，點破一山翠。"]'),
('d864e6cd-d041-468c-9ef6-d8ff7dbb45d0','病起','白玉蟾','宋','宋诗','song-poetry','','[]','我愛山水清，淘洗詩中俗。',120,'全唐诗/poet.song.206000.json','["我愛山水清，淘洗詩中俗。", "朅來山水間，白晝卧茅屋。", "天公知此癖，復還我以病。", "病中翫山水，詩句覺愈勝。", "我欲抱病吟，生怕病忽愈。", "錮口莫湯藥，靜對山水語。", "君看病中句，不特苦且清。", "長如酒後時，雄吟畏酒醒。", "行带瓊臺雲，隨風下山去。", "回首山上菴，記在猿啼處。"]'),
('7256a469-1b49-4595-9522-92ae8c4a0f86','戴月游西林','白玉蟾','宋','宋诗','song-poetry','','[]','悄然無人聲，但有一杯月。',228,'全唐诗/poet.song.206000.json','["悄然無人聲，但有一杯月。", "誰家鳴乳厖，萬籟靜不發。", "蒼鬚指前路，滿地鋪翠樾。", "清露滴秋衾，夜氣飛霰屑。", "遥岑有無中，煙渺天空闊。", "劍光衝斗牛，長嘯蒼崖裂。", "山行二三里，詩腸思酒渴。", "冷雲曳山腰，暗水洗石骨。", "勒馬過斷橋，枯木凍欲折。", "枝頭驚鳥鵲，草根鳴蟋蟀。", "試問夜如何，孤猿啼不歇。", "柴門自推敲，殘燈更明滅。", "回首古招提，地僻居窮髮。", "紅裳照經幢，紫殿閉鎖闥。", "題名墨未乾，壁上龍蛇活。", "秉燭出雲房，古徑蒼苔滑。", "歸來倦拂床，聯句鬭擊鉢。", "老蒼擁地爐，坐把寒灰撥。", "黄雞啼四更，驚破梅花雪。"]'),
('3750f6fb-d16b-44cd-b77d-c6c9f4cab70c','月庭','白玉蟾','宋','宋诗','song-poetry','','[]','佳人冰雪姿，奕奕紫芝眉。',96,'全唐诗/poet.song.206000.json','["佳人冰雪姿，奕奕紫芝眉。", "中懷徑寸珠，曉夜光陸離。", "似月充其庭，謂是亦良非。", "乃知可憐宵，誠與姮娥期。", "四座生虛白，一笑搴其衣。", "拔子出紅塵，相與游瑶池。", "舉頭叫風伯，招手邀雲師。", "高折丹桂花，縱身空中飛。"]'),
('5a70a7b8-d645-421f-822b-15fd2ce3114b','題三山天慶觀  其一','白玉蟾','宋','宋诗','song-poetry','','[]','渺渺神霄天，玉京何岧嶢。',48,'全唐诗/poet.song.206000.json','["渺渺神霄天，玉京何岧嶢。", "瓊花露泣蘂，琪樹風鳴條。", "瑶妃侍雲笈，羽童舞金翹。", "嗟彼世間人，紅塵徒朝朝。"]'),
('9e3efff0-00ba-40c4-bd53-f80f5da0283e','題三山天慶觀  其二','白玉蟾','宋','宋诗','song-poetry','','[]','紫瓊飛清都，翠雲護絳闕。',48,'全唐诗/poet.song.206000.json','["紫瓊飛清都，翠雲護絳闕。", "不見有星辰，俯視但日月。", "下世二千年，不敢向人說。", "吾已成金丹，留下飛仙訣。"]'),
('38a24477-0003-4517-aeb8-70705baa5f8a','題三山天慶觀  其三','白玉蟾','宋','宋诗','song-poetry','','[]','玉皇香案吏，金闕禁垣卿。',48,'全唐诗/poet.song.206000.json','["玉皇香案吏，金闕禁垣卿。", "寶罏烹日月，鐵尺鞭雷霆。", "曉煉西山雲，夜煎北斗星。", "城南告樹精，吾家在瑶京。"]'),
('8ee6935d-ed6e-447d-91ae-b6b690414dfa','鶴林賞蓮','白玉蟾','宋','宋诗','song-poetry','','[]','玉洞生翠霧，瑶林映素霞。',48,'全唐诗/poet.song.206000.json','["玉洞生翠霧，瑶林映素霞。", "天飛明月英，夜浴白蓮花。", "碧水香以浄，松聲吹露華。", "衆仙鸞鶴散，寂寂五雲家。"]'),
('d05b5572-26b3-4688-a820-c4f023e2f64e','荷風薦凉屷于御風臺者六因賦古意示諸同我','白玉蟾','宋','宋诗','song-poetry','','[]','黄昏六點星，飛墮天南方。',144,'全唐诗/poet.song.206000.json','["黄昏六點星，飛墮天南方。", "蕩蕩無邊秋，水色涵天光。", "紫壺如朱槿，鮮妍敵露霜。", "紫瓊如芙蓉，風韻何清凉。", "紫煙如芝蘭，澗谷含幽芳。", "紫雲如木犀，內祕天家香。", "鶴林如甘菊，端可壽而臧。", "滿泛九霞觴，與客秋興長。", "紫清如芰荷，堪製仙人裳。", "願言六人者，駕月賓帝旁。", "先拜紫皇前，次謁王母房。", "人間塵埃子，白日空茫茫。"]'),
('6b239a5d-08b8-4889-a7b2-7840796f14ec','秋風變','白玉蟾','宋','宋诗','song-poetry','','[]','一從佳人去，念念思杳魂。',228,'全唐诗/poet.song.206000.json','["一從佳人去，念念思杳魂。", "頃刻不離懷，夢寐常溫溫。", "幽人非好色，脂粉何萬羣。", "良馬只一鞍，好花只一春。", "流水去不返，青霄徒白雲。", "香魂在九泉，夫豈不酸辛。", "人間尚寂寂，陰府復何言。", "造物略不悲，蒼天不我憐。", "南風復西風，景物易變遷。", "獨有一寸心，朝暮佳人邊。", "幽冥不可詰，寧忍度歲年。", "此身當如何，何當委荒煙。", "若夫世間人，豈知道義堅。", "孤然不自惜，悵望瑶臺仙。", "置之勿復道，時時淚漣漣。", "不堪酒醒時，月下與風前。", "有夢夢不成，所思長縣縣。", "萬里亦可到，一死今杳然。", "相憶而自歎，蒼天復蒼天。"]'),
('505dd6d1-f412-4971-9e2b-227c89c522bf','夜闌','白玉蟾','宋','宋诗','song-poetry','','[]','試問今宵月，今夕何爽約。',144,'全唐诗/poet.song.206000.json','["試問今宵月，今夕何爽約。", "遂令山中人，倚戶守寂寞。", "上界足官府，天門有關鑰。", "雲鎖烏鵲橋，風把鳳凰閣。", "蟾吞不夜天，兔搗長生藥。", "否則廣寒君，尚或事梳掠。", "如何二鼓去，桂影更不作。", "幽人惟太息，遠趣在碧落。", "伊本不窈窕，我非業諧謔。", "如此良夜何，不飲何時樂。", "悠然舉大白，清嘯散萬壑。", "那有揚州鶴，那有揚州鶴。"]'),
('0574729e-7522-41af-a0ab-082bb1a8bad0','定齋爲楊和甫賦','白玉蟾','宋','宋诗','song-poetry','','[]','水澄秋月現，雲散春山出。',120,'全唐诗/poet.song.206000.json','["水澄秋月現，雲散春山出。", "鏡內影去來，杯中形出沒。", "釋氏慧之源，儒者誠之骨。", "忘軀見天機，灰心契造物。", "落花問啼鳥，流水噪幽石。", "不如窗間雲，不如屋角月。", "此意誰與論，知音更何說。", "悄如寒巖煙，寂似陰崖雪。", "棲神要山林，晦迹老巖穴。", "吾當叫張葛，起與共散髮。"]'),
('1eb635d8-822c-497a-b531-95bc948e1c90','贈侯先生','白玉蟾','宋','宋诗','song-poetry','','[]','腰懸龍泉劍，背負寒玉琴。',48,'全唐诗/poet.song.206000.json','["腰懸龍泉劍，背負寒玉琴。", "閲世幾秋雨，隨身一紙衾。", "蒼髯怒更直，碧眼笑仍深。", "今過青城去，人間何處尋。"]'),
('87414728-0546-4feb-828c-c7120e6f5c87','蒼瓊軒','白玉蟾','宋','宋诗','song-poetry','','[]','竹已萌千龍，水自走萬馬。',48,'全唐诗/poet.song.206000.json','["竹已萌千龍，水自走萬馬。", "人在蒼瓊軒，笑傾白玉斚。", "飲到月華落，醉倒洞之下。", "一堂皆酒仙，地遠無人畫。"]'),
('b55a5a60-7704-4c43-b960-6d84bc9a8126','贈李道士謁仙行','白玉蟾','宋','宋诗','song-poetry','','[]','蓬萊空夜月，琪樹不秋風。',156,'全唐诗/poet.song.206000.json','["蓬萊空夜月，琪樹不秋風。", "霜畦老芝㼌，煙闕多麟龍。", "靈龜不知歲，孤雲杳無蹤。", "白鶴忽歸來，紫鸞鳴雝雝。", "誰種蟠桃核，花開崑崙峰。", "一曲舞胎仙，瑶池讌已終。", "手持三尺霜，浩氣渺太空。", "坐斷壺山景，杖頭風月濃。", "玉皇知何時，錫詔下霄濛。", "玉膏滿甌雪，刀圭一粒紅。", "贈子謁仙行，金鷄呼曉鍾。", "喚起老飛廉，羊角舞巽宮。", "爲君吹夢魂，橫飛過海東。"]'),
('5c05a9d1-9726-415f-8263-1c28723f008a','春日道中','白玉蟾','宋','宋诗','song-poetry','','[]','春光入萬象，天意開百花。',48,'全唐诗/poet.song.206000.json','["春光入萬象，天意開百花。", "鶑雛戲雲錦，鳩婦絡雨紗。", "曉日晴弄柳，夜雷暗驚茶。", "溪带縛洞口，醉歸蜂正衙。"]'),
('b788b9d9-62e0-4b4b-8f2e-29434f456bc6','妾薄命','白玉蟾','宋','宋诗','song-poetry','','[]','長天雲茫茫，流水去不返。',156,'全唐诗/poet.song.206000.json','["長天雲茫茫，流水去不返。", "寂寥不可呼，死者日已遠。", "舊事常在心，思之輒淚眼。", "修晝勞悵想，寒夜百展轉。", "夢裏時相逢，醒後細思忖。", "門前青衿子，相顧吾安忍。", "羅衣疊空箱，久矣廢檀板。", "月明燕子樓，風清荷花館。", "置之勿復道，此念增繾綣。", "自憐妾薄命，鴛衾爲誰煖。", "冉冉冥中魂，尚或暗相管。", "鄰家琴聲悲，精爽竟難挽。", "琴調何凄凉，聞是廣陵散。"]'),
('1b4d25df-4942-4462-9517-b01ab8332542','清夜辭  其一','白玉蟾','宋','宋诗','song-poetry','','[]','霜清兮露冷，暮天碧兮微雲飛。',31,'全唐诗/poet.song.206000.json','["霜清兮露冷，暮天碧兮微雲飛。", "北風兮吹我衣，梅花下兮明月來幾時。"]'),
('37593995-d7ca-465d-aad0-89c2fc599020','清夜辭  其二','白玉蟾','宋','宋诗','song-poetry','','[]','月明兮星稀，煙漠漠兮風悲。',26,'全唐诗/poet.song.206000.json','["月明兮星稀，煙漠漠兮風悲。", "空階兮竹影，悄無人兮螢飛。"]'),
('07377510-e36e-454c-9a85-abbe37327974','清夜辭  其三','白玉蟾','宋','宋诗','song-poetry','','[]','微雲兮淡月，萬籟靜兮猿啼。',28,'全唐诗/poet.song.206000.json','["微雲兮淡月，萬籟靜兮猿啼。", "梅花兮無人言，夜氣清兮露凄凄。"]'),
('52142fe2-12c3-46e9-aa52-74b3954185ea','清夜辭  其四','白玉蟾','宋','宋诗','song-poetry','','[]','風起兮霜下，池塘冰兮井水寒。',28,'全唐诗/poet.song.206000.json','["風起兮霜下，池塘冰兮井水寒。", "望清都兮鶴未還，明月兮空山。"]'),
('3d2cb454-a943-4cc2-83ca-c6c5e29429fb','清夜辭  其五','白玉蟾','宋','宋诗','song-poetry','','[]','清都兮絳闕，五雲深兮冥冥。',27,'全唐诗/poet.song.206000.json','["清都兮絳闕，五雲深兮冥冥。", "玉樓高兮珠殿寒，漠漠兮無聲。"]'),
('851fb4a1-fd2a-4e51-b81d-26b5fc818bec','清夜辭  其六','白玉蟾','宋','宋诗','song-poetry','','[]','橙黄兮橘綠，湛霧飛兮夜月寒。',26,'全唐诗/poet.song.206000.json','["橙黄兮橘綠，湛霧飛兮夜月寒。", "幽人兮夜坐，顧影兮自憐。"]'),
('253836db-ae50-47af-b917-d2e7ea87284c','清夜辭  其七','白玉蟾','宋','宋诗','song-poetry','','[]','南山兮北隴，相對兮碧崔嵬。',25,'全唐诗/poet.song.206000.json','["南山兮北隴，相對兮碧崔嵬。", "青松兮白石，暮煙兮猿哀。"]'),
('091ec871-ac5c-4b2f-b6f6-b2802cce75b2','清夜辭  其八','白玉蟾','宋','宋诗','song-poetry','','[]','餐松兮飲水，望絳闕兮思歸。',26,'全唐诗/poet.song.206000.json','["餐松兮飲水，望絳闕兮思歸。", "白雲兮黄鶴，胡不來兮何時。"]'),
('e1957bf1-37a1-4235-8638-294da90f5741','清夜辭  其九','白玉蟾','宋','宋诗','song-poetry','','[]','凭虛兮御氣，乘風兮駕浮。',24,'全唐诗/poet.song.206000.json','["凭虛兮御氣，乘風兮駕浮。", "朝罷兮歸來，天邊兮月鈎。"]'),
('f91a9e03-866a-48a9-a46e-94451ff23200','清夜辭  其一○','白玉蟾','宋','宋诗','song-poetry','','[]','百年兮一炊黍，萬幻兮一浮漚。',27,'全唐诗/poet.song.206000.json','["百年兮一炊黍，萬幻兮一浮漚。", "吾不知兮此身，騎鯨兮醉游。"]'),
('2e0647f6-d198-42dc-a161-f986dc0cfc7c','古別離 臞菴李侍郎','白玉蟾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','有婉孤山梅，香根寄霜雪。',48,'全唐诗/poet.song.206000.json','["有婉孤山梅，香根寄霜雪。", "早被東皇知，占斷西湖月。", "天風何狼籍，吹付壽陽人。", "騎箕棄鼎鼐，百花空自春。"]'),
('927a6d30-583c-43a8-b0cd-3ebabebe5d3f','古別離 回菴譙大卿','白玉蟾','宋','宋诗','song-poetry','','[]','青青冬嶺松，高出寒崔嵬。',48,'全唐诗/poet.song.206000.json','["青青冬嶺松，高出寒崔嵬。", "憶昔可憐宵，聲如灧澦堆。", "冰霜矧肯摧，枝葉故條暢。", "一夕乘風雷，龍化失羣望。"]'),
('2093e2b4-6a22-4672-8a1f-8127b3e368d5','古別離 覺非彭吏部','白玉蟾','宋','宋诗','song-poetry','','[]','彩鳳何毰毸，有玉飛則立。',48,'全唐诗/poet.song.206000.json','["彩鳳何毰毸，有玉飛則立。", "竹林失所依，梧枝夜露泣。", "鷄鶩疑九苞，鵷鷺厭五毛。", "伊獨怨德衰，簫韶如之何。"]'),
('48491e56-085e-43db-bde0-3482413b3905','古別離 盤莊黄檢院','白玉蟾','宋','宋诗','song-poetry','','[]','溶溶空中雲，膚寸能滂沱。',48,'全唐诗/poet.song.206000.json','["溶溶空中雲，膚寸能滂沱。", "旦暮依神龍，所至蒙恩多。", "歸來太山阿，已罷澤民志。", "溘然登崑崙，猿鶴爲歔欷。"]'),
('1aca14ae-7816-4b29-a30d-a0b33c7cc0bf','古別離 竹莊蘇筠州','白玉蟾','宋','宋诗','song-poetry','','[]','彼美幽汀蘭，開花滿國香。',48,'全唐诗/poet.song.206000.json','["彼美幽汀蘭，開花滿國香。", "悵無與同心，隔水遐相望。", "皓月澤清姿，凉風憐幽芳。", "不及見粧臺，委之田舍郎。"]'),
('c1668361-8a38-423b-87c8-6bc953119674','步虛四章  其一','白玉蟾','宋','宋诗','song-poetry','','[]','昔在神霄府，飛雲步玉天。',48,'全唐诗/poet.song.206000.json','["昔在神霄府，飛雲步玉天。", "玉天三十六，六梵聚飛仙。", "太帝昇煙殿，東皇駕鳳軿。", "真靈來億萬，聽演太靈篇。"]'),
('46176b7e-9c22-49c4-b937-2da1bea1078c','步虛四章  其二','白玉蟾','宋','宋诗','song-poetry','','[]','玉清長生君，錫命青華房。',48,'全唐诗/poet.song.206000.json','["玉清長生君，錫命青華房。", "上念神母言，下慰天八方。", "八方俱紅塵，塵埃何迷茫。", "誰復念玉府，飛神登蒼蒼。"]'),
('98c4858d-99ed-4ec3-a245-c13dc2eb80d2','步虛四章  其三','白玉蟾','宋','宋诗','song-poetry','','[]','帝在蘂珠殿，騫林白鶴翔。',48,'全唐诗/poet.song.206000.json','["帝在蘂珠殿，騫林白鶴翔。", "方會琪花宴，遽聽青鸞歌。", "雲籠六六天，下界徒嗷嗷。", "爾不慕玉府，輪迴復奈何。"]'),
('ce96e61b-abee-4994-b8ae-05743c249965','步虛四章  其四','白玉蟾','宋','宋诗','song-poetry','','[]','清都五雲天，天中飛紫瓊。',48,'全唐诗/poet.song.206000.json','["清都五雲天，天中飛紫瓊。", "上皆青琳府，中有白玉京。", "風露凄且冷，蘂宮雲冥冥。", "玉童折珊瑚，下弄銀河星。"]'),
('50f7118b-f556-4e00-903a-102541c2064f','易水辭','白玉蟾','宋','宋诗','song-poetry','','[]','天爲燕丹畜趙高，風鳴易水止荆軻。',64,'全唐诗/poet.song.206000.json','["天爲燕丹畜趙高，風鳴易水止荆軻。", "不令劉季身秦怨，却速吳陳此水過。", "秦王環柱劍光急，尺八匕首手死執。", "伊獨徙木信市人，殿下鈐奴嬴得立。"]'),
('1866eb93-f300-4c9c-acf2-c916bf48be8f','鶴謠  其一','白玉蟾','宋','宋诗','song-poetry','','[]','鶴者胎化之禽兮明明，後玄鵠兮前蒼鷹，沖若舞兮太清。',25,'全唐诗/poet.song.206000.json','["鶴者胎化之禽兮明明，後玄鵠兮前蒼鷹，沖若舞兮太清。"]'),
('bea5fa69-9a34-4b9e-b2fb-3b4ccc0bfdc0','鶴謠  其二','白玉蟾','宋','宋诗','song-poetry','','[]','鶴者還丹之使兮洋洋，縞雲衣兮玄綺裳，唳以下兮郴陽。',25,'全唐诗/poet.song.206000.json','["鶴者還丹之使兮洋洋，縞雲衣兮玄綺裳，唳以下兮郴陽。"]'),
('3756e747-941c-4aee-912e-c29f8e09e9b1','鶴謠  其三','白玉蟾','宋','宋诗','song-poetry','','[]','鶴者沖虛之梯兮冥冥，朱霞弁兮翠錦熭，浩然歸兮遼東。',25,'全唐诗/poet.song.206000.json','["鶴者沖虛之梯兮冥冥，朱霞弁兮翠錦熭，浩然歸兮遼東。"]'),
('2131a781-8852-4a2f-82f2-267f48355b8c','鶴謠  其四','白玉蟾','宋','宋诗','song-poetry','','[]','鶴者飛仙之御兮英英，十二裙兮六六領，翻而來兮華亭。',25,'全唐诗/poet.song.206000.json','["鶴者飛仙之御兮英英，十二裙兮六六領，翻而來兮華亭。"]'),
('b25ad8af-0b6f-4812-bf7d-99a1fb951dc9','鶴謠  其五','白玉蟾','宋','宋诗','song-poetry','','[]','鶴兮鶴兮芝田兮，遐征不可望兮，倏去忽來兮。',21,'全唐诗/poet.song.206000.json','["鶴兮鶴兮芝田兮，遐征不可望兮，倏去忽來兮。"]'),
('c3668227-5bdf-4710-8cf7-9064af6fca61','鶴謠  其六','白玉蟾','宋','宋诗','song-poetry','','[]','鶴兮鶴兮瑶池兮，若有控以御兮，杳不可詰兮。',21,'全唐诗/poet.song.206000.json','["鶴兮鶴兮瑶池兮，若有控以御兮，杳不可詰兮。"]'),
('504a26d3-bfec-4fbe-87be-3b78b2b07fb2','鶴謠  其七','白玉蟾','宋','宋诗','song-poetry','','[]','鶴兮鶴兮玄圃兮，是必有以致兮，將爲誰來兮。',21,'全唐诗/poet.song.206000.json','["鶴兮鶴兮玄圃兮，是必有以致兮，將爲誰來兮。"]'),
('b7a5b11b-5022-43a2-a8fe-edc0710a746f','鶴謠  其八','白玉蟾','宋','宋诗','song-poetry','','[]','鶴兮鶴兮丹丘兮，下界塵土腥兮，何當致我歸兮。',22,'全唐诗/poet.song.206000.json','["鶴兮鶴兮丹丘兮，下界塵土腥兮，何當致我歸兮。"]'),
('69d84546-df1f-4eef-a4a3-44cf778ae459','懷仙吟','白玉蟾','宋','宋诗','song-poetry','','[]','我懷仙兮神仙侶，霞裾摇曳兮居何所。',65,'全唐诗/poet.song.206000.json','["我懷仙兮神仙侶，霞裾摇曳兮居何所。", "見鶴長吟猶可覆，蓬萊果在半步許。", "空留寶墨落人間，字句成行秋鴈序。", "正心誠意語猶奇，誰識忘形相爾汝。"]'),
('5a6ade31-b860-443f-bcac-b8d5419f749a','見鶴吟','白玉蟾','宋','宋诗','song-poetry','','[]','紙上畫仙掛古壁，朝朝暮暮被煙熏。',128,'全唐诗/poet.song.206000.json','["紙上畫仙掛古壁，朝朝暮暮被煙熏。", "泥塑鍾離木雕木，不是元皇大道君。", "近來塵世無丹訣，啞口道人俱不說。", "武夷散人不辱仙，只圖一日三碗雪。", "白鶴白鶴何方來，丹墀絳闕幾時開。", "空中莫作嘹唳聲，片雲冷風何快哉。", "鶴作聲時我無耳，鶴振羽時我無眼。", "蓬萊只是半步許，一生且做老擔板。"]'),
('e22925d1-7b4c-4b76-84c6-9a3e1c306d95','白雲菴','白玉蟾','宋','宋诗','song-poetry','','[]','宿霧戀喬木，落花粘瘦枝。',48,'全唐诗/poet.song.206000.json','["宿霧戀喬木，落花粘瘦枝。", "鳥聲人靜處，山色雨來時。", "霽月成相約，凉風解見知。", "僧房安一枕，海氣濯冰肌。"]'),
('0ffa43f8-4e43-4ab7-9440-99f8b61aaee5','海豐道中','白玉蟾','宋','宋诗','song-poetry','','[]','海近疑無地，山長儘有天。',48,'全唐诗/poet.song.206000.json','["海近疑無地，山長儘有天。", "蛇崗嵐霧濕，魚市水風膻。", "苔色陪巖草，榕陰冒浦蓮。", "由來金翠盛，遮莫酌貪泉。"]'),
('4035646b-2b4d-43a4-b501-57b29192c693','閩清醉中','白玉蟾','宋','宋诗','song-poetry','','[]','東風正月二，吹我上梅溪。',48,'全唐诗/poet.song.206000.json','["東風正月二，吹我上梅溪。", "白雪方纔散，黄鶑未見啼。", "半空萌雨意，一蝶訪桃蹊。", "醉卧黄三店，夜深聞竹鷄。"]'),
('a2419c64-dbc9-4206-919b-5280b015f618','順昌即事','白玉蟾','宋','宋诗','song-poetry','','[]','筆下千機錦，胸中一滴金。',48,'全唐诗/poet.song.206000.json','["筆下千機錦，胸中一滴金。", "乾坤春甕闊，風月夜樓深。", "世絕夫君操，人誰梁父吟。", "只尋雲外路，誰復聽寒砧。"]'),
('ea5d02a9-816e-40bd-8003-223fe387356b','即事寄紫元','白玉蟾','宋','宋诗','song-poetry','','[]','老雨餞秋菊，孤煙醖暮嵐。',48,'全唐诗/poet.song.206000.json','["老雨餞秋菊，孤煙醖暮嵐。", "鴈驚十月北，梅早一枝南。", "往事風吹帽，良宵月掛簪。", "時哉亦難得，我已到無參。"]'),
('6d755bfd-a0c1-49ec-837b-83468a8285d8','五更解酲梅竹之間徘體','白玉蟾','宋','宋诗','song-poetry','','[]','宿鳥能傳語，殘風且點心。',48,'全唐诗/poet.song.206000.json','["宿鳥能傳語，殘風且點心。", "山情憐澹坐，月色笑孤斟。", "驚我梅花睡，聞他竹葉吟。", "清歸無所得，得句貴如金。"]'),
('82ff9b81-3c85-4d5b-8846-330dc525f6a5','雲霄菴會宿','白玉蟾','宋','宋诗','song-poetry','','[]','春自如情暖，夜何如話長。',48,'全唐诗/poet.song.206000.json','["春自如情暖，夜何如話長。", "酒醨成水淡，詩妙奪花香。", "月出星轉閙，雲行山似忙。", "起來携素手，擁被視農秧。"]'),
('3e0287eb-6cef-4e66-8443-0d531f6ded3c','秋夜','白玉蟾','宋','宋诗','song-poetry','','[]','有客眠孤館，更闌擁紙衾。',48,'全唐诗/poet.song.206000.json','["有客眠孤館，更闌擁紙衾。", "清風千里夢，明月一聲砧。", "素壁秋燈暗，紅爐火夜深。", "寒猿啼嶺外，惹起故鄉心。"]'),
('458f032a-cfee-4a57-b261-ad8ab4aef0e3','得鶴林書','白玉蟾','宋','宋诗','song-poetry','','[]','東望吾彭耜，晴窗墜一蛛。',48,'全唐诗/poet.song.206000.json','["東望吾彭耜，晴窗墜一蛛。", "萬金何足抵，尺紙寄來迂。", "夜後燈花喜，朝來鵲語符。", "手中舒復卷，久別可長吁。"]'),
('d2a6cbd4-173b-48dd-a53e-54c642781a4d','博羅縣驛','白玉蟾','宋','宋诗','song-poetry','','[]','虎嘯月生海，猿啼風撼山。',48,'全唐诗/poet.song.206000.json','["虎嘯月生海，猿啼風撼山。", "夢回三鼓盡，身自九天還。", "雲氣浮窗外，泉聲入枕間。", "問心宜富貴，爲復要清閑。"]'),
('152ebff7-1375-4dfc-8194-7d3ceb61529d','景泰晚眺','白玉蟾','宋','宋诗','song-poetry','','[]','海岸孤絕處，晴沙露遠汀。',48,'全唐诗/poet.song.206000.json','["海岸孤絕處，晴沙露遠汀。", "潮花人鬢白，山色佛頭青。", "夕照雌黄筆，秋煙水墨屏。", "天空杉月冷，鶴夢幾回醒。"]'),
('bf8d38b7-d100-47a9-aa4d-145b0a9ae561','十月十四夜','白玉蟾','宋','宋诗','song-poetry','','[]','十月十四夜，燈寒燄寸長。',48,'全唐诗/poet.song.206000.json','["十月十四夜，燈寒燄寸長。", "披衣臨曲水，把筆向清霜。", "月透詩情冷，風吹醉面凉。", "故人知得否，空斷早梅腸。"]'),
('541a2aeb-c079-4650-a78f-b0afc654843a','溫學士再訪山中','白玉蟾','宋','宋诗','song-poetry','','[]','炎帝辭朱節，清晨立素秋。',48,'全唐诗/poet.song.206000.json','["炎帝辭朱節，清晨立素秋。", "借緋皆木葉，脫白滿林丘。", "流水高山興，疎風冷雨愁。", "詩人應自樂，歌笑海東州。"]'),
('d2e26671-1714-4b62-b934-f45875b4af8d','張道士鹿堂','白玉蟾','宋','宋诗','song-poetry','','[]','清夢繞羅浮，羽衣延我游。',48,'全唐诗/poet.song.206000.json','["清夢繞羅浮，羽衣延我游。", "新茶尋雀舌，獨芋煮鴟頭。", "春鶴飲藥院，夜猿啼石樓。", "丹爐猶暖在，聊爲稚川留。"]'),
('f7e5f137-2fae-429a-bb38-9da591552b52','春日詞','白玉蟾','宋','宋诗','song-poetry','','[]','春日何遲遲，東風吹紫微。',48,'全唐诗/poet.song.206000.json','["春日何遲遲，東風吹紫微。", "子規愁句句，楊柳恨絲絲。", "上帝無消息，仙飈杳去期。", "水長更天遠，跬步成相思。"]'),
('d6e0afe8-296e-48b7-98b9-51976bfbd4f3','再會薛黄庭','白玉蟾','宋','宋诗','song-poetry','','[]','別來真夢耳，相對各潸然。',48,'全唐诗/poet.song.206000.json','["別來真夢耳，相對各潸然。", "一向於湖海，如今更市廛。", "知心能有幾，顧影獨興憐。", "自歎吾衰矣，猶期子勉旃。"]'),
('b0b68d52-1c8c-4e89-8948-bfa35094cb90','送春','白玉蟾','宋','宋诗','song-poetry','','[]','草木從交代，溪山無故新。',48,'全唐诗/poet.song.206000.json','["草木從交代，溪山無故新。", "更斟些子酒，尚是霎時春。", "雨止鶑如怨，花飛柳亦顰。", "東皇催上印，生怕子規嗔。"]'),
('a2b07ada-1c3b-4b75-b626-cdd562f54d52','述懷','白玉蟾','宋','宋诗','song-poetry','','[]','吊影自憐孤，消愁得酒壺。',48,'全唐诗/poet.song.207000.json','["吊影自憐孤，消愁得酒壺。", "客悰迷曉夜，夢事付江湖。", "雨壁琴絃潤，風窗硯水枯。", "晚蟬知此意，爲我噪高梧。"]'),
('4152a5e0-7172-4624-9e39-179753789a6a','有懷','白玉蟾','宋','宋诗','song-poetry','','[]','紫綺輕裘穩，青綾廣被長。',48,'全唐诗/poet.song.207000.json','["紫綺輕裘穩，青綾廣被長。", "明珠懷夜月，孤劍匣秋霜。", "氣魄今諸葛，襟期舊子房。", "西風一長嘯，草木正凄凉。"]'),
('97c2921d-18fa-4961-aeac-7f8b0a5a72a4','紅梅','白玉蟾','宋','宋诗','song-poetry','','[]','人賦紅梅少，予詩爲補遺。',48,'全唐诗/poet.song.207000.json','["人賦紅梅少，予詩爲補遺。", "霞融姑射面，酒沁壽陽肌。", "太潔遭時妬，獨醒爲衆疑。", "漫隨春色媚，自保歲寒姿。"]'),
('2ca6eaf6-e702-4f9e-8372-3e7ec49eaf08','感物','白玉蟾','宋','宋诗','song-poetry','','[]','月生看柳癭，風起笑花癇。',48,'全唐诗/poet.song.207000.json','["月生看柳癭，風起笑花癇。", "事業三盃酒，勳名九轉丹。", "神凄身外蝶，夢黯鏡中鸞。", "爲問金堪带，如何玉可餐。"]'),
('4e45c665-eeec-434b-a395-19322acb6b67','春日道中','白玉蟾','宋','宋诗','song-poetry','','[]','洞口鳥呼鳥，山頭花戴花。',48,'全唐诗/poet.song.207000.json','["洞口鳥呼鳥，山頭花戴花。", "風篁蒼韻玉，煙樹晚籠紗。", "懷白一樽酒，邀盧七椀茶。", "春光索彈壓，萬象曉排衙。"]'),
('55545a9e-a876-464d-95ac-1dc800e97132','月窗寫悶','白玉蟾','宋','宋诗','song-poetry','','[]','不分庭前柳，長啼月下烏。',48,'全唐诗/poet.song.207000.json','["不分庭前柳，長啼月下烏。", "半生嗟命薄，中夜正心孤。", "勳業看雙鬢，歌吟在數鬚。", "從今閑草馬，休得更江湖。"]'),
('8c3a1fdc-1a99-4ae8-a3df-5353a5a8cde0','泰定菴','白玉蟾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','太極函三性，千燈共一光。',48,'全唐诗/poet.song.207000.json','["太極函三性，千燈共一光。", "猿啼廬阜月，鴈叫洞庭霜。", "夜半冰生水，風前麝出囊。", "吾師知箇事，念念守中黄。"]'),
('153fcb0c-3bcc-4eac-bbb6-b6e7ab0d6d9d','舟中遣興二首  其一','白玉蟾','宋','宋诗','song-poetry','','[]','江水皺寒綠，山花蓓淡黄。',48,'全唐诗/poet.song.207000.json','["江水皺寒綠，山花蓓淡黄。", "斷雲漫遠浦，歸鴈背斜陽。", "客恨何凄寞，詩懷墮渺茫。", "人生本蕭散，我欲問漁郎。"]'),
('9d6d939c-c561-4cef-a3e9-871b8d3cb521','舟中遣興二首  其二','白玉蟾','宋','宋诗','song-poetry','','[]','暮樹煙凝翠，秋花雨著黄。',48,'全唐诗/poet.song.207000.json','["暮樹煙凝翠，秋花雨著黄。", "萬松羅谷口，一鶴點山陽。", "霜葉夢零亂，雲山望杳茫。", "眼稍林下寺，髣髴數支郎。"]'),
('8a1d1903-4302-43fe-8720-9018ab243cf9','小桃源','白玉蟾','宋','宋诗','song-poetry','','[]','好事開三徑，栽花滿一園。',48,'全唐诗/poet.song.207000.json','["好事開三徑，栽花滿一園。", "前頭平俯水，裏面曲通村。", "自有鳩夫婦，仍多竹子孫。", "醉歸迷去路，題作小桃源。"]'),
('741be6f7-5e0b-401e-86ed-3237c90b9f20','八月三日即事','白玉蟾','宋','宋诗','song-poetry','','[]','煙冷渾沾水，溪清可數魚。',48,'全唐诗/poet.song.207000.json','["煙冷渾沾水，溪清可數魚。", "鴉翻千點墨，鴈草數行書。", "今日征帆下，前年上國初。", "詩盟寒復講，無酒興何如。"]'),
('edc6b1e2-5a97-4b64-87c2-57c816c23ce0','泊頭圓照堂','白玉蟾','宋','宋诗','song-poetry','','[]','脫白來求法，披緇去出家。',48,'全唐诗/poet.song.207000.json','["脫白來求法，披緇去出家。", "此心如水月，結屋老煙霞。", "翠長真如竹，黄開般若花。", "寄言劉鐵磨，自識趙州茶。"]'),
('e80d0d22-6b20-4e02-a40d-0f4fde64903f','和張紫微韻題清虛菴','白玉蟾','宋','宋诗','song-poetry','','[]','鷄犬聲村市，煙霞古洞天。',48,'全唐诗/poet.song.207000.json','["鷄犬聲村市，煙霞古洞天。", "晨壇凝玉露，夜井浸珠躔。", "鳳翼團宸畫，龜趺負古鎸。", "于湖詩去後，今昔幾千篇。"]'),
('503a74d3-f602-402a-b780-af03ed35e9e7','睡起','白玉蟾','宋','宋诗','song-poetry','','[]','眼瞌蚊方謁，燈微蛾更來。',48,'全唐诗/poet.song.207000.json','["眼瞌蚊方謁，燈微蛾更來。", "汗珠流似雨，鼻息響如雷。", "蝶魄遊仙去，猿聲驚夢回。", "夢回嫌簟濕，怒把枕頭推。"]'),
('accf286b-c7a5-4e50-b077-ecc10db3497c','明堂禮成','白玉蟾','宋','宋诗','song-poetry','','[]','豐年有高廩，宗祀拜明堂。',120,'全唐诗/poet.song.207000.json','["豐年有高廩，宗祀拜明堂。", "玉輅迎閶闔，銀蟾躍未央。", "虎賁森鹵簿，龍衮照旂常。", "寶幄燃紅炬，璇霄降紫皇。", "竹宮循漢古，茆屋法周荒。", "雲藹簫韶暖，風融黍稷香。", "典刑存鬰鬯，陟降奉珪璋。", "水取方諸氏，星沉析木鄉。", "金鷄懽舞蹈，翠鳳播琳瑯。", "何日當封禪，如今尚小康。"]'),
('4af9281e-7688-4fdd-b8e8-32a1e404d39f','皇初平故隠','白玉蟾','宋','宋诗','song-poetry','','[]','昔日登山願，今年破夏償。',72,'全唐诗/poet.song.207000.json','["昔日登山願，今年破夏償。", "乘壺斟雪白，獨酌判黄昏。", "有許松俱老，皆爲鶴所房。", "能多雲擘絮，若箇石爲羊。", "懷古興三嘆，凭高眺八方。", "歸歸天籟起，一我正詩狂。"]'),
('725d9b08-05e4-46ac-92bc-870f1183bd82','贈鶴林','白玉蟾','宋','宋诗','song-poetry','','[]','骨氣秋江月，文章春苑花。',72,'全唐诗/poet.song.207000.json','["骨氣秋江月，文章春苑花。", "片心窮萬法，半語辯千邪。", "朝罷鷄司曉，醉酣蜂報衙。", "未爲三島客，笑指五雲家。", "騎月遊滄海，鞭霆步太霞。", "鬼神私側目，袖裏一青蛇。"]'),
('9d22e9b6-8be7-46ca-8b81-fb77e22f55de','挽覺非先生彭吏部','白玉蟾','宋','宋诗','song-poetry','','[]','公本籛仙後，緣何出自閩。',72,'全唐诗/poet.song.207000.json','["公本籛仙後，緣何出自閩。", "東山爲別久，西浙得書頻。", "投老欣添歲，歸閑剩得春。", "滿朝俱歎譽，八秩向精神。", "見說臨終日，鞭霆謁上真。", "不能躬桂酹，千里一霑巾。"]'),
('93f8b03c-d413-4f10-bddd-69243ff2b14c','靖通菴','白玉蟾','宋','宋诗','song-poetry','','[]','靖通菴外鎖晴雲，壁瑩飛瓊瓦疊鱗。',64,'全唐诗/poet.song.207000.json','["靖通菴外鎖晴雲，壁瑩飛瓊瓦疊鱗。", "野鳥無心一聲曉，巖花有意四時春。", "鑿開風月長生地，占斷煙霞不老身。", "虛靖當年仙去後，不知丹訣付何人。"]'),
('2905ac59-8700-4388-b996-f1aea81f8c85','澹菴','白玉蟾','宋','宋诗','song-poetry','','[]','平生只要樂清虛，占斷人間靜處居。',64,'全唐诗/poet.song.207000.json','["平生只要樂清虛，占斷人間靜處居。", "古壁空懸三尺劍，幽窗閑却一床書。", "遠山喜色日初染，枯木凉聲風自梳。", "細嚼清閑滋味別，雲霞收拾作糧儲。"]'),
('4dd3e417-d76c-46d1-b95c-a373687105e1','假山','白玉蟾','宋','宋诗','song-poetry','','[]','一林幽竹幾時栽，怪石花磚砌綠苔。',64,'全唐诗/poet.song.207000.json','["一林幽竹幾時栽，怪石花磚砌綠苔。", "羽客游岩乘雨至，仙翁採藥破雲來。", "天台猶在眉毛聳，鴈蕩依然眼睫開。", "昨夜摘珠人報道，海中失却小蓬萊。"]'),
('33baf7f1-9c47-43a2-b22c-0d3a1f65e990','贈慵菴盧副宮','白玉蟾','宋','宋诗','song-poetry','','[]','山色凝雲翠幾重，鳥聲驚落夕陽紅。',64,'全唐诗/poet.song.207000.json','["山色凝雲翠幾重，鳥聲驚落夕陽紅。", "要携琴去彈秋月，且掇棋來著晚風。", "一度醉眠知事少，數番吟暢覺心空。", "慵菴不與人相與，閣上柴門滋味濃。"]'),
('678c48a8-87c4-41b1-b37d-1f18efa5640d','天谷菴','白玉蟾','宋','宋诗','song-poetry','','[]','半天突出一奇峰，小小茅簷滋味濃。',64,'全唐诗/poet.song.207000.json','["半天突出一奇峰，小小茅簷滋味濃。", "夾道新松招夜月，滿林幽竹喚秋風。", "迎人野鳥間關語，惱客巖花爛熳紅。", "策杖且隨流水去，柴門時倩白雲封。"]'),
('0328b278-7c9e-4962-94a5-f0a015e8e776','怡齋','白玉蟾','宋','宋诗','song-poetry','','[]','逸士幽居松竹林，小堂偃枕北山陰。',64,'全唐诗/poet.song.207000.json','["逸士幽居松竹林，小堂偃枕北山陰。", "夜深冷月寒蓬戶，曉起清風爽楮衾。", "把劍更餐盃內酒，收書動破壁頭琴。", "自從一見羲皇面，千古誰知養浩心。"]'),
('94317931-0488-4d21-bd1d-6cdce15c098c','雨中題旅館','白玉蟾','宋','宋诗','song-poetry','','[]','風攪長空秋雨懸，路如苔滑懶摇鞭。',64,'全唐诗/poet.song.207000.json','["風攪長空秋雨懸，路如苔滑懶摇鞭。", "入門指僕買盃酒，磨墨倚窗吟一篇。", "黄竹繞簷黄蟻戰，白蘆映水白鷗眠。", "一聲長嘯便歸去，回首孤村空暮煙。"]'),
('ec507218-391b-4855-a857-58e4e4d6c6cf','游楊梓巖','白玉蟾','宋','宋诗','song-poetry','','[]','天半秋風鳴萬松，芫花半落夕陽紅。',64,'全唐诗/poet.song.207000.json','["天半秋風鳴萬松，芫花半落夕陽紅。", "寮煙暗鎖仙壇古，野意深藏丹竈空。", "人採紫芝何處覓，我來白晝不相逢。", "一聲簫管笑揚袂，秋色滿懷詩興濃。"]'),
('7b7792b6-2ebe-4ed0-b71a-8ed602b79725','贈吳草裘','白玉蟾','宋','宋诗','song-poetry','','[]','聞道青城有老吳，話頭入耳十年餘。',64,'全唐诗/poet.song.207000.json','["聞道青城有老吳，話頭入耳十年餘。", "偶同婺女無憂客，來到天台撞見渠。", "身上衣衫惟布素，口中談吐盡丹書。", "想君已是千餘歲，誰道神仙世上無。"]'),
('d8e6e7ad-624f-4bb9-88f9-80f8887df825','贈天台老樊','白玉蟾','宋','宋诗','song-poetry','','[]','別後俄經幾許春，相逢一笑挹南薰。',64,'全唐诗/poet.song.207000.json','["別後俄經幾許春，相逢一笑挹南薰。", "灰頭土面無人識，木食草衣嫌俗紛。", "在浙之台今已久，姓樊名邴寂無聞。", "爲君傳此新詩去，寄與鉛山趙翠雲。"]'),
('84566843-070b-4789-b038-c042bac3f35a','胡中隠菴中傷春','白玉蟾','宋','宋诗','song-poetry','','[]','盡把天工付祝融，東皇歸去太華宮。',64,'全唐诗/poet.song.207000.json','["盡把天工付祝融，東皇歸去太華宮。", "稜稜山色聳蒼玉，湛湛波光浸碧銅。", "楊柳入天鳩要雨，海棠落地蝶嫌風。", "好將杖屨西園看，萬紫千紅一夜空。"]'),
('726cdb3b-a781-4df7-9eec-d9a2f2f68dc7','景泰山送友人','白玉蟾','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','白雲影裏話三生，起坐相從夜共行。',64,'全唐诗/poet.song.207000.json','["白雲影裏話三生，起坐相從夜共行。", "誼與雲天高也薄，道於泰華重邪輕。", "酒非貪飲惟知己，詩不求工貴適情。", "但使忘年成莫逆，何須肉袒負渠荆。"]'),
('480d3669-cbfa-4fab-af14-8c41dd3f0e13','醉中賦別','白玉蟾','宋','宋诗','song-poetry','','[]','話別應知太去匆，明朝馬首定東風。',64,'全唐诗/poet.song.207000.json','["話別應知太去匆，明朝馬首定東風。", "鏡中人瘦如花瘦，湖上春濃似酒濃。", "行色已如天色好，道情不與世情同。", "如今老眼渾無淚，醉頸當筵似玉虹。"]'),
('a510fd04-cc21-43e3-a498-ab53d71129e0','過林靈素墳','白玉蟾','宋','宋诗','song-poetry','','[]','衆僧莫怨趙歸真，此是容成太玉君。',64,'全唐诗/poet.song.207000.json','["衆僧莫怨趙歸真，此是容成太玉君。", "始末四年曾就日，相將五秩即騰雲。", "帝心俾立神霄教，州額由昇應道軍。", "泉石依然冠劍冷，至今雷電禦松墳。"]'),
('c088d077-9512-4650-b9e2-514a8c4c1fc3','嘉定甲申閏月五日聞皇帝升遐','白玉蟾','宋','宋诗','song-poetry','','[]','唳鶴啼猿怨滿懷，煙葵露槿淚盈腮。',64,'全唐诗/poet.song.207000.json','["唳鶴啼猿怨滿懷，煙葵露槿淚盈腮。", "一鈎桂月千林黯，半夜松風萬壑哀。", "不御六龍昌寶祚，遽驂八駿駐瑶臺。", "小臣泉石膏肓了，無任冰肝玉膽摧。"]'),
('079b9847-c0a0-4481-8c4f-35bcf20259fb','武昌懷古十詠 南樓','白玉蟾','宋','宋诗','song-poetry','','[]','凭暖朱欄醉已酥，樓前眼纈望中疎。',64,'全唐诗/poet.song.207000.json','["凭暖朱欄醉已酥，樓前眼纈望中疎。", "漢陽草樹看來短，淮岸漁家淡欲無。", "薄暮鴉翻千點墨，晴空鴈草數行書。", "多情庾亮吟魂遠，風泛蘆花秋滿湖。"]'),
('af7b0814-f32c-4dd3-a797-332933ec0dd1','武昌懷古十詠 黄鶴樓','白玉蟾','宋','宋诗','song-poetry','','[]','白雲黄鶴跡成遺，何獨當年丁令威。',64,'全唐诗/poet.song.207000.json','["白雲黄鶴跡成遺，何獨當年丁令威。", "洞裏不知朝市改，人間再到子孫非。", "笛聲吹斷秋江黯，月影飛來夜漏稀。", "大醉倚樓呼費𩃱，蓬萊山下幾斜暉。"]'),
('acf4755e-f57a-44b2-8142-1273c8887185','武昌懷古十詠 赤壁','白玉蟾','宋','宋诗','song-poetry','','[]','不說江山笑老權，盡稱造化戲曹瞞。',64,'全唐诗/poet.song.207000.json','["不說江山笑老權，盡稱造化戲曹瞞。", "飛烏遶樹孤回首，斷戟沉沙怒激湍。", "豪傑已隨霜葉盡，興亡儘付浪花翻。", "畫堂莫唱坡仙賦，戰骨草中吟夜寒。"]'),
('9a286eae-e399-4a86-8e50-55ff659c7353','武昌懷古十詠 吳王宮','白玉蟾','宋','宋诗','song-poetry','','[]','不將膽命付周郎，安得兒孫見太康。',64,'全唐诗/poet.song.207000.json','["不將膽命付周郎，安得兒孫見太康。", "三國興亡成夢事，一川煙草斷人腸。", "黄旗紫蓋伊巴蜀，翠殿朱樓自武昌。", "縱謂西山非王氣，金陵能得幾時王。"]'),
('3b63ce0c-0c1e-4c05-aa15-96d861baa764','武昌懷古十詠 靈竹寺','白玉蟾','宋','宋诗','song-poetry','','[]','孝之一字協天倫，信可通天感鬼神。',64,'全唐诗/poet.song.207000.json','["孝之一字協天倫，信可通天感鬼神。", "霜滿竹林安得筍，心傾淚雨自生春。", "祇聞郭巨曾埋子，豈得曾參亦殺人。", "鑿隧及泉愚爾耳，斯人盍是舜之臣。"]'),
('0b33f1eb-bebd-45d9-9be2-1c31dc953ba3','武昌懷古十詠 奇章臺','白玉蟾','宋','宋诗','song-poetry','','[]','登臺日費萬緡錢，賓從如雲劍履駢。',64,'全唐诗/poet.song.207000.json','["登臺日費萬緡錢，賓從如雲劍履駢。", "食鼎歌鍾移楚地，貂金珮玉整唐天。", "緬懷𣄛鉞熊旂裏，尚有冰辭雹語傳。", "偃月堂中人用事，牛家僧孺得稱賢。"]'),
('9ce8e998-507b-4153-9cc7-603a59a3d2eb','武昌懷古十詠 江漢亭','白玉蟾','宋','宋诗','song-poetry','','[]','西風黄葉滿秋城，水鳥飛無沙磧腥。',64,'全唐诗/poet.song.207000.json','["西風黄葉滿秋城，水鳥飛無沙磧腥。", "淮浪白如頭似白，沔山青與眼俱青。", "何人得見蓮花女，此地空餘江漢亭。", "一自鄭生雙珮斷，幽情渺在蓼花汀。"]'),
('66507397-dfb2-4544-9afe-52f611677728','武昌懷古十詠 鸚鵡洲','白玉蟾','宋','宋诗','song-poetry','','[]','無人爲叫禰平原，表祖粗人豈識文。',64,'全唐诗/poet.song.207000.json','["無人爲叫禰平原，表祖粗人豈識文。", "鶴在鷄羣懷月露，豹將虎變欠風雲。", "鳳凰池上纔方酒，鸚鵡洲邊已自墳。", "道大不容才見忌，漁陽撾斷不堪聞。"]'),
('eb5e14d6-37f1-46e2-a8ea-2039062f51db','武昌懷古十詠 西塞','白玉蟾','宋','宋诗','song-poetry','','[]','落盡桃花水滿湖，西山西塞長新蒲。',64,'全唐诗/poet.song.207000.json','["落盡桃花水滿湖，西山西塞長新蒲。", "斜風細雨今如許，青笠綠簑誰又無。", "聖主龍飛邦有道，醉仙睡到日高梧。", "何時堯舜無巢許，我也人乎粘壁枯。"]'),
('74e78ecf-2729-4b45-907c-68f5f1f46573','武昌懷古十詠 南浦','白玉蟾','宋','宋诗','song-poetry','','[]','越禽胡馬易空疎，水遠天長夢亦迂。',64,'全唐诗/poet.song.207000.json','["越禽胡馬易空疎，水遠天長夢亦迂。", "南北故人鴻去外，古今陳跡雨晴初。", "雲連碧草別愁黯，風眇綠波征騎孤。", "三徑凄凉一盃酒，夜深重讀寄來書。"]'),
('4abf8649-4352-4ca1-a556-60661cc65c04','潮陽謁靈山大顛禪師','白玉蟾','宋','宋诗','song-poetry','','[]','天地神祇不可誣，小人君子費分疎。',64,'全唐诗/poet.song.207000.json','["天地神祇不可誣，小人君子費分疎。", "我無其事初何卹，自揆於心或未如。", "豈是大顛留乃服，只聞刺史造吾廬。", "誰能脫略形骸外，孟簡尚書謾寄書。"]'),
('4f7ca0d5-5105-4566-8e18-60a6c6c8c08e','次韻宋秀才','白玉蟾','宋','宋诗','song-poetry','','[]','晝弄朱曦夜弄蟾，知他何處地行仙。',64,'全唐诗/poet.song.207000.json','["晝弄朱曦夜弄蟾，知他何處地行仙。", "殿前昔奏三千字，腰下曾纏十萬錢。", "得句直疑無李白，草書真箇過張顛。", "有時興發臨風舞，飲似長鯨吸百川。"]'),
('39778c21-48f2-4baa-9381-3b4857869d99','暑夕有懷','白玉蟾','宋','宋诗','song-poetry','','[]','幽人避暑海城西，西北浮屠儘得棲。',64,'全唐诗/poet.song.207000.json','["幽人避暑海城西，西北浮屠儘得棲。", "更漏有無風逆順，紙窗明暗月高低。", "石泉未到秋先冷，野虎偏從夜即嘶。", "記得去年常德府，武陵今夕况桃谿。"]'),
('f18b7bd5-7a8f-425d-832f-40777d806726','藍琴士贈梅竹酬以詩','白玉蟾','宋','宋诗','song-poetry','','[]','手補天工筆法奇，笑將造化作兒嬉。',64,'全唐诗/poet.song.207000.json','["手補天工筆法奇，笑將造化作兒嬉。", "胸中夜雨澆龍幹，紙上春風舞玉蕤。", "雲水一生無別好，琴心三疊有誰知。", "今宵松殿相期會，彈到西山月落時。"]'),
('20f793a7-c45a-4ca1-b60a-82a6ba006510','送黄心大師','白玉蟾','宋','宋诗','song-poetry','','[]','如今無用繡香囊，已入空王選佛場。',64,'全唐诗/poet.song.207000.json','["如今無用繡香囊，已入空王選佛場。", "生鐵脊梁三事衲，冷灰心緒一爐香。", "庭前竹長真如翠，檻外花開般若香。", "萬事到頭都是夢，天傾三峽洗高唐。"]'),
('0dc72b3b-8dea-44a6-bd63-bb6ac9e62c10','奏章歸','白玉蟾','宋','宋诗','song-poetry','','[]','玉殿朝回夜已深，三千世界靜沉沉。',64,'全唐诗/poet.song.207000.json','["玉殿朝回夜已深，三千世界靜沉沉。", "微微花雨粘琪樹，浩浩天風動寶林。", "煙鎖崑崙山頂上，月明娑竭海中心。", "步虛聲斷一回首，十二樓臺何處尋。"]'),
('53996ab4-efb0-45c1-8858-e053d66ea00f','泛舟黄橋歸廬山','白玉蟾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','清風爲我送歸船，數粒青松起薄煙。',64,'全唐诗/poet.song.207000.json','["清風爲我送歸船，數粒青松起薄煙。", "帆影驚飛秋水鴈，櫓聲攪斷夕陽蟬。", "幾人家在溪頭岸，一片雲生水底天。", "滿眼良朋無好酒，此心已挂九江邊。"]'),
('ea691a9a-8d2b-4854-8f83-6981de612c79','留別鐵柱宮葉法師','白玉蟾','宋','宋诗','song-poetry','','[]','不嫌來往日詩筒，春興無窮我欲東。',64,'全唐诗/poet.song.207000.json','["不嫌來往日詩筒，春興無窮我欲東。", "一雨放行三尺水，萬松回納半帆風。", "且將南浦難題景，寄在西山絕頂峰。", "柳處酒家花處寺，併留他日款游從。"]'),
('fdd03b55-db79-4274-9555-6c3c117419b7','次韻彬上人見惠','白玉蟾','宋','宋诗','song-poetry','','[]','象輪何事過毗耶，詩竅禪關事一家。',64,'全唐诗/poet.song.207000.json','["象輪何事過毗耶，詩竅禪關事一家。", "自古行春難盡美，非風即雨輒成差。", "我文柔似三眠柳，君句清如六出花。", "應悟己公茅屋下，擬之早已涉河沙。"]'),
('cfc3f4fd-b996-475f-81ec-892dc39050f1','送王待制自溫州移鎮三山','白玉蟾','宋','宋诗','song-poetry','','[]','春暖塗歌里詠喧，鶉衣百結過蘇天。',64,'全唐诗/poet.song.207000.json','["春暖塗歌里詠喧，鶉衣百結過蘇天。", "九重親擢公爲此，百姓皆云我自然。", "五馬重來尋墨沼，一麾又去鎮閩川。", "廟堂相位猶虛左，已築沙堤在日邊。"]'),
('0bb6eabc-bc84-4300-a0fb-a2e425a25d70','見浙翁琰禪師','白玉蟾','宋','宋诗','song-poetry','','[]','謂師有道國人皆，何必文殊更五臺。',64,'全唐诗/poet.song.207000.json','["謂師有道國人皆，何必文殊更五臺。", "棒喝交馳聊復爾，離微不犯亦奇哉。", "且言風動還幡動，莫問船來與陸來。", "不道相逢不相識，儘教寒拾笑咍咍。"]'),
('c59d9a8d-c009-4a4f-a10a-e88aeb1d156c','爲李縣尉壽','白玉蟾','宋','宋诗','song-poetry','','[]','浪萍風絮客他鄉，喜者青春鬢未霜。',64,'全唐诗/poet.song.207000.json','["浪萍風絮客他鄉，喜者青春鬢未霜。", "到處煙霞成莫逆，如今山水已相忘。", "子還真箇爲仙尉，我定終身作懶王。", "何似著鞭鉛汞事，笑騎雲外鶴翱翔。"]'),
('66def140-a9a0-470f-819c-01272a9e42b7','歸鴈亭','白玉蟾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','嗟予尚未髮星星，今日杯茶歸鴈亭。',64,'全唐诗/poet.song.207000.json','["嗟予尚未髮星星，今日杯茶歸鴈亭。", "幾見霜翎巢白草，數行雲足篆青冥。", "方將寄字來苕霅，莫便翻身過洞庭。", "握手亭前話今古，仇池仙墨有餘清。"]'),
('bb0a7354-4451-419b-b2a9-4894946b213f','月巖','白玉蟾','宋','宋诗','song-poetry','','[]','素娥飛下碧霄間，別館嵌空萬仞寒。',64,'全唐诗/poet.song.207000.json','["素娥飛下碧霄間，別館嵌空萬仞寒。", "不是高懸青玉玦，直疑斜捧爛銀盤。", "雲根朴朔兔相似，灌木參差桂一般。", "說與長風休送上，千秋留與往來看。"]'),
('79f6ab55-1c9d-4964-9b30-65a4bc7d14f5','席上偶成呈主簿兄','白玉蟾','宋','宋诗','song-poetry','','[]','原氣推宗分不疎，一相思一檢輿圖。',64,'全唐诗/poet.song.207000.json','["原氣推宗分不疎，一相思一檢輿圖。", "三生骨肉幾回別，萬里音書半字無。", "風雨每思君對榻，江湖長只影爲徒。", "春城煙鎖南臺暮，兩地襟情片月孤。"]'),
('29e641aa-1e97-4547-ae57-ddae52dc854b','夏五即事  其一','白玉蟾','宋','宋诗','song-poetry','','[]','驚心節物讀齊諧，迎面南風汎歜杯。',64,'全唐诗/poet.song.207000.json','["驚心節物讀齊諧，迎面南風汎歜杯。", "池畔雨荒靈運草，庭前雲釀洞賓槐。", "藕絲冰水敵時暑，臂綵釵符付女孩。", "遐想湘沅歌楚些，蘭魂桂魄不歸來。"]'),
('10906afa-e443-4ea3-9634-7aac6e67f36c','夏五即事  其二','白玉蟾','宋','宋诗','song-poetry','','[]','曉來掠面更東風，過盡溪山屬祝融。',64,'全唐诗/poet.song.207000.json','["曉來掠面更東風，過盡溪山屬祝融。", "楊柳引教荷芰綠，海棠讓與石榴紅。", "稻針刺水連青畝，麥浪翻雲漲碧空。", "我有浮瓜沉李約，諸君同上紫霄峰。"]'),
('addf69e5-403b-4574-8290-4cec878ece0a','題迎仙堂','白玉蟾','宋','宋诗','song-poetry','','[]','昔日尋師到海涯，手中常袖一青蛇。',64,'全唐诗/poet.song.207000.json','["昔日尋師到海涯，手中常袖一青蛇。", "隨身風月長爲伴，到處溪山總是家。", "玉笥巖前曾結草，金華洞裏獨餐霞。", "有人問我長生事，默默無言指落花。"]'),
('471de8db-a76b-437a-bed3-40579b0188f2','題鼓山超凡閣','白玉蟾','宋','宋诗','song-poetry','','[]','輸與黄龍第一籌，于今不到洞賓羞。',64,'全唐诗/poet.song.207000.json','["輸與黄龍第一籌，于今不到洞賓羞。", "九重城裏聖箭子，三百年來糞掃頭。", "山月扶疎龕石冷，天風浩蕩海槎浮。", "我來會得謙公意，豎起拳頭向趙州。"]'),
('92f1549a-afd7-44c5-8293-e8e2317469a1','題余府浮香亭','白玉蟾','宋','宋诗','song-poetry','','[]','小亭低瞰小池邊，日日春風醉管絃。',64,'全唐诗/poet.song.207000.json','["小亭低瞰小池邊，日日春風醉管絃。", "盤礴好窮詩世界，登臨疑是水神仙。", "玉萍掩映壺中月，錦鯉浮沉鏡裏天。", "芍藥牡丹歸去後，花開十丈藕如船。"]'),
('fe9d4d2e-0ee1-4971-98fe-2f56a5b72248','贈坦菴告別','白玉蟾','宋','宋诗','song-poetry','','[]','杖頭挑起一天雲，政是梅花十月春。',64,'全唐诗/poet.song.207000.json','["杖頭挑起一天雲，政是梅花十月春。", "猿叫千山風勢惡，雪迷萬里雨聲頻。", "今朝瓢笠游方外，舊處煙霞失主人。", "好去著鞭行所得，他時相見話頭新。"]'),
('1f48c5d2-2bc4-4f6c-89e7-2e8367d1a1a9','述翠虛真人安樂法','白玉蟾','宋','宋诗','song-poetry','','[]','收歛神光少默然，頂門一路聚雲煙。',64,'全唐诗/poet.song.207000.json','["收歛神光少默然，頂門一路聚雲煙。", "且昇陽火烹金鼎，却降靈泉灌玉田。", "交結只於牛渚外，分明正在鵲橋邊。", "功夫九九數六六，此是人間安樂仙。"]'),
('2ed559fb-ee21-4428-a709-a9379754ac34','天籟堂','白玉蟾','宋','宋诗','song-poetry','','[]','到此令人玉骨寒，四圍紫翠玉回環。',64,'全唐诗/poet.song.207000.json','["到此令人玉骨寒，四圍紫翠玉回環。", "玲瓏蒼壁竹敲竹，重疊畫屏山間山。", "猿笛曉聞冥漠外，松濤夜吼有無間。", "我將喚起陳知白，蛻却塵軀跨綵鸞。"]'),
('cc8c1c35-415b-48dd-b8c9-18a176aaea09','寄鄭天谷','白玉蟾','宋','宋诗','song-poetry','','[]','况此三晴二雨天，孤村寒綰纏蒼煙。',64,'全唐诗/poet.song.207000.json','["况此三晴二雨天，孤村寒綰纏蒼煙。", "客來長是有蝴蝶，春去不堪聞杜鵑。", "漢蕨可羹今已晚，胡麻未飯必須仙。", "九江城裏鄭天谷，許結焚香瀹茗緣。"]'),
('15fffc4d-bf82-43ca-a6eb-c18b48912281','題棲雲堂','白玉蟾','宋','宋诗','song-poetry','','[]','高人占斷一生閒，長得青山在眼看。',64,'全唐诗/poet.song.207000.json','["高人占斷一生閒，長得青山在眼看。", "棋子縱橫星點亂，琴絃戛擊玉聲寒。", "無心門掩苔三徑，觀化庭栽竹萬竿。", "中有玄機人不會，清風明月兩丸丹。"]'),
('74380c22-04db-44ad-a41a-5c9747523a5c','契妙','白玉蟾','宋','宋诗','song-poetry','','[]','契妙堂中靜養神，神凝氣聚一壺春。',64,'全唐诗/poet.song.207000.json','["契妙堂中靜養神，神凝氣聚一壺春。", "青山綠水無非道，翠竹黄花有幾人。", "世外不知千百世，身中還更兩三身。", "一從契得虛無妙，明月清風是我鄰。"]'),
('d968a720-bca1-433d-b144-fb238bee72cb','玉壺軒','白玉蟾','宋','宋诗','song-poetry','','[]','玉壺四榻靜無塵，琴上無徽筆有神。',64,'全唐诗/poet.song.207000.json','["玉壺四榻靜無塵，琴上無徽筆有神。", "詩債已還休骨瘦，酒冤今醒但眉顰。", "清風吹鶴梧桐曉，明月啼猿楊柳春。", "見說玉樓新架就，紫皇有詔日來頻。"]'),
('6cddf84c-5080-43d9-b1b8-cec96aee5f51','悠然堂','白玉蟾','宋','宋诗','song-poetry','','[]','一池寒碧浸紅鱗，芍藥方花春後春。',64,'全唐诗/poet.song.207000.json','["一池寒碧浸紅鱗，芍藥方花春後春。", "煙閣曉垂天幕靜，風簾夜上月鈎新。", "閑雲流水無窮意，絳闕清都被謫身。", "不向悠然堂上飲，篇詩斗酒付何人。"]'),
('592d4909-652c-4f8c-8435-25ac2803b6d0','奉酬陳宮教','白玉蟾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','落魄逍遥一醉仙，笑携藜杖夕陽邊。',64,'全唐诗/poet.song.207000.json','["落魄逍遥一醉仙，笑携藜杖夕陽邊。", "三年睡法應須得，九藴仙方妙不傳。", "驟雨猛催今日作，老苔爲鎖異時鎸。", "偶來水綠紅花野，自與廬山亦有緣。"]'),
('6d25de67-78c1-4235-95e9-612e7bc0802b','題甕齋','白玉蟾','宋','宋诗','song-poetry','','[]','萬軸牙籤聚碧芸，數間茅屋鎖閑雲。',64,'全唐诗/poet.song.207000.json','["萬軸牙籤聚碧芸，數間茅屋鎖閑雲。", "鶑吟芍藥一歌女，蟻遶菖蒲萬水軍。", "香穗橫窗盤瘦影，茗花浮枕鬭清芬。", "琴心三疊晝眠覺，熟讀數篇韓柳文。"]'),
('e4ca30bf-37d1-4ecd-997d-2b1f9f360dbb','翠麓即事','白玉蟾','宋','宋诗','song-poetry','','[]','千峰萬峰翠入門，一樹兩樹啼斷猿。',64,'全唐诗/poet.song.207000.json','["千峰萬峰翠入門，一樹兩樹啼斷猿。", "山後山前鳩喚婦，舍南舍北竹生孫。", "煙迷洞口苔三徑，風吼松梢月一痕。", "芍藥未花春未老，客來到此倒芳樽。"]'),
('9f93a615-64e9-463b-ac75-09d4a5ff9a53','快軒書懷','白玉蟾','宋','宋诗','song-poetry','','[]','滿樹牡丹相次紅，客來不放酒盃空。',64,'全唐诗/poet.song.207000.json','["滿樹牡丹相次紅，客來不放酒盃空。", "三分春色二分去，一處風光是處同。", "柳絮打殘連夜雨，桃花飛落五更風。", "與君飲到如泥爛，我欲明朝杖屨東。"]'),
('f36ae4c1-c4a7-482f-9773-25e68fdfb7a0','清明','白玉蟾','宋','宋诗','song-poetry','','[]','新除小壘燕方謀，又拜晴蜂萬戶侯。',64,'全唐诗/poet.song.207000.json','["新除小壘燕方謀，又拜晴蜂萬戶侯。", "占破清明三五日，實封芍藥一千頭。", "花間作夢碧蝴蝶，柳外談禪黄栗留。", "物物是題吟不盡，却煩酒作釣詩鈎。"]'),
('ffea1cf0-5cd4-4060-a6f3-709c95f594e5','題天開圖畫','白玉蟾','宋','宋诗','song-poetry','','[]','四時風物現安排，醉上高樓眼豁開。',64,'全唐诗/poet.song.207000.json','["四時風物現安排，醉上高樓眼豁開。", "雲散遠山元不斷，池成明月自然來。", "夕陽粧點丹青樹，煙雨和勻水墨梅。", "此是天工無盡巧，何曾染惹俗塵埃。"]'),
('d017aea4-31a4-41d8-ba3c-e009737e33e8','次李侍郎見贈韻','白玉蟾','宋','宋诗','song-poetry','','[]','家居瓊館海山隅，腹內包藏三教書。',64,'全唐诗/poet.song.207000.json','["家居瓊館海山隅，腹內包藏三教書。", "明月清風爲活計，蓬頭跣足走寰區。", "玉爐丹熟斟瓊醑，金闕朝回唱步虛。", "要識我儂真面目，廣寒宮裏看蟾蜍。"]'),
('767d6c2e-df27-4e63-a598-7de2551f681a','春日飲酒','白玉蟾','宋','宋诗','song-poetry','','[]','拍拍浮浮幾酒樽，梅花入夢酒歸魂。',64,'全唐诗/poet.song.207000.json','["拍拍浮浮幾酒樽，梅花入夢酒歸魂。", "半窗寂寞猿三咽，滿戶蕭騷月一痕。", "山後山前鳩喚婦，舍南舍北竹生孫。", "天明醉醒策霜竹，春在江天蘆荻村。"]'),
('3065eaa3-878a-4ab0-a759-3ec21a0e1335','呼喚體自述','白玉蟾','宋','宋诗','song-poetry','','[]','只貪飲酒與吟詩，煉得丹成身欲飛。',64,'全唐诗/poet.song.207000.json','["只貪飲酒與吟詩，煉得丹成身欲飛。", "曩劫曾爲觀大士，前生又是派禪師。", "蓬萊舊路今尋著，兜率陀天始覺非。", "料我年當三十六，青雲白鶴是歸期。"]'),
('76fad234-0a7d-430a-8aa0-cad8c549067b','題浄明軒','白玉蟾','宋','宋诗','song-poetry','','[]','浄几明窗興味濃，老僧心下萬緣空。',64,'全唐诗/poet.song.207000.json','["浄几明窗興味濃，老僧心下萬緣空。", "黄鸝睡起摇開竹，白鶴飛來點破松。", "些子溪山藏夜月，無邊花柳惱春風。", "真如般若頭頭是，坐斷蒲團子細窮。"]'),
('d12c6b67-9bbc-45e7-8838-c4df15dfc7ce','華陽堂二詠  其一','白玉蟾','宋','宋诗','song-poetry','','[]','幕天席地做生涯，凡聖同居氣象佳。',64,'全唐诗/poet.song.207000.json','["幕天席地做生涯，凡聖同居氣象佳。", "撥過浮山供醉眼，斬新風月入詩懷。", "花間自舞三臺鶴，竹外空歌兩部蛙。", "不是道人多計較，是渠諸聖早安排。"]'),
('23379369-fa42-4d7c-be81-69f1db5ea856','華陽堂二詠  其二','白玉蟾','宋','宋诗','song-poetry','','[]','不著人間一點塵，滿堂盡是學仙人。',64,'全唐诗/poet.song.207000.json','["不著人間一點塵，滿堂盡是學仙人。", "衣衫總带煙霞色，杖屨相隨雲水身。", "鐵笛橫吹滄海月，紙袍包盡洞天春。", "而今會聚十方客，認看何人是洞賓。"]'),
('604b10f0-647c-43c6-8c12-ddd68e2f9ac2','贈盧隠居','白玉蟾','宋','宋诗','song-poetry','','[]','日高丈五尚酣眠，心下無愁不管天。',64,'全唐诗/poet.song.207000.json','["日高丈五尚酣眠，心下無愁不管天。", "野蔌山肴酬白醑，乾柴浄米煮清泉。", "不須求仕如藏用，且自烹茶學玉川。", "時策短筇松竹下，清閒便是地行仙。"]'),
('473116f9-8a69-4124-95c9-ab2ba032f5b1','陪莊歲寒夜坐小酌','白玉蟾','宋','宋诗','song-poetry','','[]','偶然氣分頗相同，道院新移喜畢工。',64,'全唐诗/poet.song.207000.json','["偶然氣分頗相同，道院新移喜畢工。", "坐把詩吟中夜月，笑將酒灑一窗風。", "博山香篆浮青蚓，古壁燈光吐玉蟲。", "君已酕醄吾酩酊，化爲蝴蝶入槐宮。"]'),
('ee6867e4-c3db-4031-bcc4-f1715d57d33f','悲秋','白玉蟾','宋','宋诗','song-poetry','','[]','庭臯一葉夜來秋，拍塞乾坤爽氣浮。',64,'全唐诗/poet.song.207000.json','["庭臯一葉夜來秋，拍塞乾坤爽氣浮。", "有客放船芳草渡，何人吹笛夕陽樓。", "鱸魚蓴菜季鷹興，鴻鴈蘆花宋玉愁。", "碧水映天天映水，淡雲如幕月如鈎。"]'),
('da7a0547-e537-474f-9a41-8446d3693cca','桐柏山書懷','白玉蟾','宋','宋诗','song-poetry','','[]','桐柏山頭避俗囂，篇詩斗酒自逍遥。',64,'全唐诗/poet.song.207000.json','["桐柏山頭避俗囂，篇詩斗酒自逍遥。", "九峰野草迷丹竈，三井飛泉噴石橋。", "萬頃白雲蒸綠野，一聲黄鶴唳青霄。", "人言華頂高高處，東望蓬萊浸海潮。"]'),
('5c8c82ec-8c4d-4353-b2f9-7504aeb5de6a','挽知宮王月谷三章  其一','白玉蟾','宋','宋诗','song-poetry','','[]','去年五月扣松關，方與先生一解顔。',64,'全唐诗/poet.song.207000.json','["去年五月扣松關，方與先生一解顔。", "今我杖藜尋舊隠，聞君琴劍蛻空山。", "交朋滿眼今無幾，羈旅傷心爲一潸。", "自嘆洞前東去水，不若逝者若爲還。"]'),
('9b1953c8-fcb7-4743-90ae-c9c5ef997de7','挽知宮王月谷三章  其二','白玉蟾','宋','宋诗','song-poetry','','[]','去年五月風颼颼，人在方瀛山上頭。',64,'全唐诗/poet.song.207000.json','["去年五月風颼颼，人在方瀛山上頭。", "見我飄然動行色，有詩因爾話離愁。", "早知如許歸仙速，悔不遲爲幾日留。", "聞道先生歸去日，千巖萬壑正中秋。"]'),
('98fa1ee5-6436-42db-93f3-ab50f5f0e56f','挽知宮王月谷三章  其三','白玉蟾','宋','宋诗','song-poetry','','[]','去年五月訪丹元，月谷先生與我言。',64,'全唐诗/poet.song.207000.json','["去年五月訪丹元，月谷先生與我言。", "將謂此生共茅舍，不知何事速雲軒。", "親書數卷空懸壁，舊隠三間半掩門。", "雪魄冰魂無處覓，秋煙秋雨暗孤村。"]'),
('7a49b0ed-e968-495d-b607-f2cedab1b63c','陪王仙卿登樓','白玉蟾','宋','宋诗','song-poetry','','[]','身在煙霞縹緲間，此心已學白雲閒。',64,'全唐诗/poet.song.207000.json','["身在煙霞縹緲間，此心已學白雲閒。", "遣懷把酒自酌月，無事捲簾常看山。", "老去棋冤休死戰，年來詩債逐時還。", "于今養鶴多栽竹，縛住時光且駐顔。"]'),
('130778fd-f74e-40ff-a34e-ba112cadd208','搗藥禽','白玉蟾','宋','宋诗','song-poetry','','[]','靈禽悲噪白雲邊，人到天台古洞天。',64,'全唐诗/poet.song.207000.json','["靈禽悲噪白雲邊，人到天台古洞天。", "點化春愁三月暮，喚回曉夢五更前。", "有如搗藥洒淚響，非杵非舂自戛然。", "毛羽也知仙可學，聲聲要結煉丹緣。"]'),
('6b4786d7-3912-4f7e-80a3-29fe5ab4c8bc','贈夏知觀','白玉蟾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','早歲江湖走一遭，歸來姓字籍祠曹。',64,'全唐诗/poet.song.207000.json','["早歲江湖走一遭，歸來姓字籍祠曹。", "未還風月煙霞債，又主香燈粥飯勞。", "捲雪樓前更襏襫，駐雲堂內飲蒲萄。", "新凉要過廬山去，擬欲從君借小艘。"]'),
('975bf7d5-59a8-4496-8678-878163641345','張子衍爲至德知觀鄢沖真求詩','白玉蟾','宋','宋诗','song-poetry','','[]','一簇樓臺水上居，琅風韻竹動笙竽。',64,'全唐诗/poet.song.207000.json','["一簇樓臺水上居，琅風韻竹動笙竽。", "魚龍飛舞半帆雨，鷗鷺眠呼兩岸蘆。", "雪覆高低春玉樹，月明表裏夜冰壺。", "漁郎倚櫂桃花落，認得扶桑宮殿無。"]'),
('0f5cec28-5908-4551-873f-1be3b7fd6b14','羅適軒浄明軒','白玉蟾','宋','宋诗','song-poetry','','[]','占斷人生百歲閒，絳宮有路透玄關。',64,'全唐诗/poet.song.207000.json','["占斷人生百歲閒，絳宮有路透玄關。", "明如雪夜潭心月，靜似春天雨後山。", "萬籟無聲人不寐，一塵何處夜將闌。", "琴心三疊倚樓坐，黄鶴悠悠去不還。"]'),
('32d18282-7d9e-4833-864a-18a7ba7ac085','題平江府靈巖寺','白玉蟾','宋','宋诗','song-poetry','','["\u592a\u6e56"]','萬松挾嶺壯招提，上有琴臺與墨池。',64,'全唐诗/poet.song.207000.json','["萬松挾嶺壯招提，上有琴臺與墨池。", "佛殿尚存今智積，娃宮曾館古西施。", "太湖遠水如奩鏡，木瀆平田似局棋。", "策杖訪回無際塔，日晡聊看草書碑。"]'),
('0a9de15c-1e2b-4fb0-a026-9efc0fcc208c','泛舟松江','白玉蟾','宋','宋诗','song-poetry','','[]','白酒黄封冽以妍，鱸魚買得一雙鮮。',64,'全唐诗/poet.song.207000.json','["白酒黄封冽以妍，鱸魚買得一雙鮮。", "舟行無浪無風夜，人在非晴非雨天。", "醉熟不知天遠近，夢回但見月嬋娟。", "垂虹亭下星如織，雲滿長洲草滿川。"]'),
('8aaaad0f-6c09-4536-9185-ccd270ea911f','題筆架山積翠樓','白玉蟾','宋','宋诗','song-poetry','','[]','萬頃平田指掌間，松梢直上與簷干。',64,'全唐诗/poet.song.207000.json','["萬頃平田指掌間，松梢直上與簷干。", "雲粘暮色月華濕，樹顫秋聲天籟寒。", "窗外好山千翡翠，屋頭修竹萬琅玕。", "樓中嘯罷玉龍去，浩蕩天風生羽翰。"]'),
('34a76857-4ed2-4755-805e-a498a73f5204','題鶴林宮','白玉蟾','宋','宋诗','song-poetry','','[]','王鄧諸公焉在哉，雲屏煙嶂鎖蒼苔。',64,'全唐诗/poet.song.207000.json','["王鄧諸公焉在哉，雲屏煙嶂鎖蒼苔。", "大千國土無雙客，第一洞天遊兩回。", "太極光陰忘甲子，九霄雲氣接蓬萊。", "桑田海水今如許，勞得朝猿暮鶴哀。"]'),
('56171bc5-9a9b-4631-b113-1ea3af5e3f03','柳花','白玉蟾','宋','宋诗','song-poetry','','[]','閑傍珠簾散漫初，垂垂欲下得風扶。',64,'全唐诗/poet.song.207000.json','["閑傍珠簾散漫初，垂垂欲下得風扶。", "繡床漸滿圓還碎，醉目遥看有似無。", "只見魚吞池面水，不知萍滿岸頭湖。", "往來無數香毬子，粘綴春衣自不須。"]'),
('461a97e2-da92-4b23-9296-df3a49fa0803','白石巖','白玉蟾','宋','宋诗','song-poetry','','[]','平野巉然石一拳，千崖萬岫翠相連。',64,'全唐诗/poet.song.207000.json','["平野巉然石一拳，千崖萬岫翠相連。", "鳥飛不到疑無路，雲與齊高直接天。", "下面仰看巖是屋，上頭仍有玉爲泉。", "李仙丹熟山魈遁，尚有宸章寄紫煙。"]'),
('4792c4bf-8b2f-49f6-90dc-3777f53fa04c','送蜀李道士','白玉蟾','宋','宋诗','song-poetry','','[]','我居瓊海子潼川，相望西南路八千。',64,'全唐诗/poet.song.207000.json','["我居瓊海子潼川，相望西南路八千。", "乃祖青牛今不返，予家白鹿尚閑眠。", "雲萍莫測真如夢，琴劍相逢亦宿緣。", "多少西風黄葉恨，待須貰酒泛湖船。"]'),
('f66b4cc1-8c5d-441b-bd57-d16cf81454e1','次玉簫臺韻','白玉蟾','宋','宋诗','song-poetry','','[]','莫便嗔人離此山，白雲黄鶴雲遊還。',64,'全唐诗/poet.song.207000.json','["莫便嗔人離此山，白雲黄鶴雲遊還。", "意行但任杖屨樂，別後豈忘詩酒懽。", "不謂業風吹我脚，只將明月當君顔。", "未知雲水何時會，煙雨蕭蕭暗碧壇。"]'),
('8c876a66-9221-4dca-bc3a-0402a359e104','次韻東坡蒲澗寺  其一','白玉蟾','宋','宋诗','song-poetry','','[]','滿山紅白福桑花，蒲澗深中儘可家。',64,'全唐诗/poet.song.207000.json','["滿山紅白福桑花，蒲澗深中儘可家。", "景泰得泉從卓錫，安期種棗說成瓜。", "豈無仙化羊如石，尚有書蹤壁似鴉。", "一飯招提共僧語，法華經裏問牛車。"]'),
('81ed2496-d10e-4c17-99b7-b5ef80d64d5e','次韻東坡蒲澗寺  其二','白玉蟾','宋','宋诗','song-poetry','','[]','陳蹤行覽寺門前，自取椰瓢酌冷泉。',64,'全唐诗/poet.song.207000.json','["陳蹤行覽寺門前，自取椰瓢酌冷泉。", "山下果然無白地，洞中儘自有青天。", "更誰識得安期事，且去參他景泰禪。", "冠蓋如雲自來往，如今何處有神仙。"]'),
('0c407690-bd1b-4104-b7b7-220c4bc59db1','賦梅奉呈陳太博','白玉蟾','宋','宋诗','song-poetry','','[]','霜清木脫嫩寒森，驚見孤英吐竹林。',64,'全唐诗/poet.song.207000.json','["霜清木脫嫩寒森，驚見孤英吐竹林。", "不負雪期如有信，偶先春事本無心。", "月橫瘦影池塘淺，風遞微香院落深。", "莫問調羹并止渴，枝枝且愜醉來簪。"]'),
('44d784a8-bd4d-4f9a-b99d-daf3374c1057','次韻王將仕','白玉蟾','宋','宋诗','song-poetry','','[]','詩壇勍敵我何堪，只把新詩著意參。',64,'全唐诗/poet.song.207000.json','["詩壇勍敵我何堪，只把新詩著意參。", "韻險有如行棧閤，句香何止食餘甘。", "江寒風落餘章謬，鳥過身輕一字慙。", "飯了相陪閒笑語，錦囊非我許誰探。"]'),
('42ecb8be-df6c-4162-a1d7-39e5555e3761','題南海祠','白玉蟾','宋','宋诗','song-poetry','','[]','何處人間得五羊，海城鼓角咽昏黄。',64,'全唐诗/poet.song.207000.json','["何處人間得五羊，海城鼓角咽昏黄。", "無心燕子觀秦越，有口簷鈴說漢唐。", "九十日秋多雨水，一千年史幾興亡。", "聖朝昌盛鯨波息，萬國迎琛舶卸檣。"]'),
('e883fa40-6fdd-46cc-bcdb-15afd34d9ca7','秋日有懷','白玉蟾','宋','宋诗','song-poetry','','[]','一點秋光寄畫圖，秋來吟鬢似楓疎。',64,'全唐诗/poet.song.207000.json','["一點秋光寄畫圖，秋來吟鬢似楓疎。", "晴煙染樹看何足，缺月梳雲狀不如。", "暑退凉生蟬有語，水長天遠鴈無書。", "此心直欲鵬南舉，不學蜘蛛結網居。"]'),
('44f8e78d-cb4b-4119-864f-aa2766c57566','舟行適興','白玉蟾','宋','宋诗','song-poetry','','[]','天知一舸過扶胥，排辦千山作畫圖。',64,'全唐诗/poet.song.207000.json','["天知一舸過扶胥，排辦千山作畫圖。", "暮靄催詩歸彩筆，秋光入酒透冰壺。", "篙頭點水月破碎，雲脚行天星有無。", "岸柳江楓共招手，西風吹我出賁隅。"]'),
('2c777dde-9392-44a5-8e32-df31bd81ca47','丹詩','白玉蟾','宋','宋诗','song-poetry','','[]','太乙壇前偃月爐，不消柴炭及吹噓。',64,'全唐诗/poet.song.207000.json','["太乙壇前偃月爐，不消柴炭及吹噓。", "金翁跨虎歸瑶闕，姹女騎龍到雪壺。", "採得三斤寒水玉，煉成一顆夜明珠。", "從茲只用抽添法，産箇嬰兒一似渠。"]'),
('8a7a4f40-f12c-49ba-b229-04a0f9c3aa07','夏夜宿水館','白玉蟾','宋','宋诗','song-poetry','','[]','松脂明滅已更寒，蛙市無聲萬籟沉。',64,'全唐诗/poet.song.207000.json','["松脂明滅已更寒，蛙市無聲萬籟沉。", "千里清風孤館夢，一輪明月故人心。", "欲眠還醒推籐枕，驟熱仍寒弄楮衾。", "搔首起來顧清影，斷煙低鎖荻花林。"]'),
('b8feb825-25bc-4950-aef5-506e720b608d','清聽堂','白玉蟾','宋','宋诗','song-poetry','','[]','白龍過澗玉琮琤，澗外松聲擊戛鳴。',64,'全唐诗/poet.song.207000.json','["白龍過澗玉琮琤，澗外松聲擊戛鳴。", "煙鎖簷牙春二月，月移簾額夜三更。", "琴彈白雪陽春調，曲轉高山流水聲。", "清聽堂中杳無夢，我將乘興跨長鯨。"]'),
('6949583a-5ef2-459c-8cd7-24a938bebcd0','游山','白玉蟾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山山下倒芳樽，八九人家煙水村。',64,'全唐诗/poet.song.207000.json','["廬山山下倒芳樽，八九人家煙水村。", "千尺雲崖春上蘚，幾重月樹夜啼猿。", "人騎黄鶴去不返，草沒丹爐今尚存。", "携子高歌醉歸去，一溪寒碧遶山根。"]'),
('698ee58e-0a74-485d-8387-51d49b3b90d6','別李仁甫','白玉蟾','宋','宋诗','song-poetry','','[]','君向星江結草廬，我來抵掌笑相於。',64,'全唐诗/poet.song.207000.json','["君向星江結草廬，我來抵掌笑相於。", "三盃碧液漲甆盞，一縷青煙纏竹爐。", "劍舞春風花爛熳，琴彈夜雨竹蕭疎。", "明朝拄杖知何處，猿叫千山月滿湖。"]'),
('13a5891a-c748-47ef-853d-fb6b77ddcfec','俞樓','白玉蟾','宋','宋诗','song-poetry','','[]','十二欄桿秋月明，謫仙曾此宴飛瓊。',64,'全唐诗/poet.song.207000.json','["十二欄桿秋月明，謫仙曾此宴飛瓊。", "半窗樹色粘山色，隔岸風聲送水聲。", "織翠回紋傷薄倖，香紅染袖悵都城。", "酒愁花恨無人訴，頼有延年俞秀英。"]'),
('7b3303c0-7023-405f-9f36-ccb1fabd2dd0','贈樗野','白玉蟾','宋','宋诗','song-poetry','','[]','不嘆勞生行路難，自憐雲水許間關。',64,'全唐诗/poet.song.207000.json','["不嘆勞生行路難，自憐雲水許間關。", "別來五載多懷感，待有尺書無往還。", "微白一鈎天外月，淡青數點海邊山。", "襟情欲向何人訴，與子篝燈到夜闌。"]'),
('8440b629-ec13-41ab-bf2b-b575564fe2b8','呈萬菴十章 歸山','白玉蟾','宋','宋诗','song-poetry','','[]','生死輪迴第幾番，塵塵劫劫不曾閑。',64,'全唐诗/poet.song.207000.json','["生死輪迴第幾番，塵塵劫劫不曾閑。", "一潭湛綠是非海，千尺粉青人我山。", "性地靈苗思水國，心天明月掩雲關。", "衣中珠子無尋處，今且隨邪煉大還。"]'),
('43018d3e-7e9a-4533-9063-f8331d50c546','呈萬菴十章 採藥','白玉蟾','宋','宋诗','song-poetry','','[]','五藴山頭多白雲，白雲深處藥苗芬。',64,'全唐诗/poet.song.207000.json','["五藴山頭多白雲，白雲深處藥苗芬。", "威音王佛隨時種，元始天尊下手耘。", "石女騎龍攀雨㼌，木人駕虎摘霜芸。", "不論貧富家家有，採得歸來各一斤。"]'),
('f644409d-741b-42cd-8efb-beb28da7f456','呈萬菴十章 爐鼎','白玉蟾','宋','宋诗','song-poetry','','[]','須信先天事事無，陰陽陶鑄此形模。',64,'全唐诗/poet.song.207000.json','["須信先天事事無，陰陽陶鑄此形模。", "真空平等硃砂鼎，虛徹靈通偃月爐。", "九竅可風壇壇暖，二時失火藥材枯。", "只茲一點無明燄，煉出人間大丈夫。"]'),
('3de9404b-64d4-4b03-a6ce-dd17a639e037','呈萬菴十章 火候','白玉蟾','宋','宋诗','song-poetry','','[]','無位真人煉大丹，倚天長劍逼人寒。',64,'全唐诗/poet.song.207000.json','["無位真人煉大丹，倚天長劍逼人寒。", "玉爐火煅天尊膽，金鼎湯煎佛祖肝。", "百刻寒溫忙裏準，六爻文武靜中看。", "有人要問真爐鼎，豈離而今赤肉團。"]'),
('49963b72-4fea-43e0-ad00-f6fe23b5f53b','呈萬菴十章 沐浴','白玉蟾','宋','宋诗','song-poetry','','[]','藥爐丹鼎火炎炎，六賊三尸怕令嚴。',64,'全唐诗/poet.song.207000.json','["藥爐丹鼎火炎炎，六賊三尸怕令嚴。", "無去無來無進退，不增不減不抽添。", "愛河浪靜浮朱雀，覺海波深浸白蟾。", "一自浴丹歸密室，太陽門下夜明簾。"]'),
('e2f4765d-8327-450a-ba72-ec488dbe56fe','呈萬菴十章 溫養','白玉蟾','宋','宋诗','song-poetry','','[]','金翁姹女結親姻，洞口桃花日日春。',64,'全唐诗/poet.song.207000.json','["金翁姹女結親姻，洞口桃花日日春。", "拾得一輪天上月，煉成萬劫屋中珍。", "黄婆即是母之母，赤子乃其身外身。", "龍漢元年消息斷，威音前面更何人。"]'),
('2594b3b4-68f8-4ac9-9fc9-f85ae3239136','呈萬菴十章 脫胎','白玉蟾','宋','宋诗','song-poetry','','[]','青天白日一聲雷，撒手懸崖了聖胎。',64,'全唐诗/poet.song.207000.json','["青天白日一聲雷，撒手懸崖了聖胎。", "有眼如盲光爍爍，無繩似縛笑咍咍。", "黄金殿下千株柳，碧玉堂前萬樹梅。", "辜負鴛幃人寂寞，秦樓宴罷盍歸來。"]'),
('3f501638-dc5a-4163-9ef5-eaa5dffb3626','呈萬菴十章 金丹','白玉蟾','宋','宋诗','song-poetry','','[]','佛與衆生共一家，一毫頭上現河沙。',64,'全唐诗/poet.song.207000.json','["佛與衆生共一家，一毫頭上現河沙。", "九還七返魚游網，四諦三空兔入罝。", "混洗何年曾結子，虛空昨夜復生花。", "阿誰鼎內尋丹藥，枯木巖前月影斜。"]'),
('a802daaf-2850-4415-9aad-ae0b2a191115','呈萬菴十章 沖舉','白玉蟾','宋','宋诗','song-poetry','','[]','自從踏著涅槃門，一枕清風幾萬年。',64,'全唐诗/poet.song.207000.json','["自從踏著涅槃門，一枕清風幾萬年。", "弱水蓬萊雖有路，釋迦彌勒正參禪。", "誰將枯木巖前地，放出落花啼鳥天。", "兩箇泥牛鬭入海，至今消息尚茫然。"]'),
('a154c441-411c-447b-a225-c2ec42af5290','呈萬菴十章 參同','白玉蟾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','道人家在海之南，來訪廬山老萬庵。',64,'全唐诗/poet.song.207000.json','["道人家在海之南，來訪廬山老萬庵。", "露柱燈籠同請舉，僧堂佛殿總和南。", "山河大地自羣動，蠢動含靈共一龕。", "虀甕裏魚淹未死，此香炷向活瞿曇。"]'),
('cf5741ed-8d17-4a44-99c2-a717d66e94ca','謝鶴林見訪','白玉蟾','宋','宋诗','song-poetry','','[]','我方一枕午風眠，君正然香未解船。',64,'全唐诗/poet.song.207000.json','["我方一枕午風眠，君正然香未解船。", "知問無爲三不答，廣咨王母幾寥然。", "分明翠竹黄花意，何必紅鉛黑汞篇。", "寄語鶴林老居士，甚時叱鶴過西川。"]'),
('c9b8e670-8b75-43a6-becb-0954b957c397','大都督制侍方巖先生召彭白飲于州治之春野亭因和蘇子美韻','白玉蟾','宋','宋诗','song-poetry','','[]','夕陽花木丹青活，煙月山林水墨昏。',64,'全唐诗/poet.song.207000.json','["夕陽花木丹青活，煙月山林水墨昏。", "碧縷倦飛縈寶鼎，紅波驚漲溢金樽。", "掀髯醉接君謨筆，擊缶吟招子美魂。", "因逐尚方雙舄至，亦隨桃李入春園。"]'),
('0c6e048e-7f1b-4622-a286-e0f3f9ee8b36','題天寧寺海月亭','白玉蟾','宋','宋诗','song-poetry','','[]','晝潮夜汐大江東，江上東南寶剎雄。',64,'全唐诗/poet.song.207000.json','["晝潮夜汐大江東，江上東南寶剎雄。", "飯了從容陪海月，禪餘宴寂享松風。", "主賓無間諸塵浄，心目相忘萬象空。", "橙熟手香吟筆滑，餘情渺在夕陽中。"]'),
('ebb2b664-5d6f-4595-80cd-7e16894b8941','和主簿家兄贈別韻','白玉蟾','宋','宋诗','song-poetry','','[]','接耳交肩話綺疎，扶摇九萬此南圖。',64,'全唐诗/poet.song.207000.json','["接耳交肩話綺疎，扶摇九萬此南圖。", "對床風雨人皆有，協韻塤箎我獨無。", "偶爾詩家鴻鴈行，爲今酒島鶺鴒徒。", "情知一舸鴟夷去，臨欲出門燈影孤。"]'),
('9df4fee1-51ff-4370-9003-1e2c502c5a68','峽山寺','白玉蟾','宋','宋诗','song-poetry','','[]','重樓複屋枕層崖，想有殘碑鎖翠苔。',64,'全唐诗/poet.song.207000.json','["重樓複屋枕層崖，想有殘碑鎖翠苔。", "但見蒼山如壁立，不知綠水自何來。", "巖花滿眼紅而紫，谷鳥呼名去復迴。", "便欲買舟從此隠，豈惟一處子陵臺。"]'),
('d16b0c51-eff3-4814-afbc-32bbf7f2aaf0','峽中見芙蓉','白玉蟾','宋','宋诗','song-poetry','','[]','峽畔尋常有虎蹤，峽中聞說有蛟龍。',64,'全唐诗/poet.song.207000.json','["峽畔尋常有虎蹤，峽中聞說有蛟龍。", "心知峭壁生如劍，目送清波去似弓。", "繞樹盡皆青薜荔，舉頭忽見白芙蓉。", "西風爲我吹殘酒，最喜千峰翠色濃。"]'),
('6957b90f-455a-44c4-8ced-0f918439a640','初至肇慶府硯巖','白玉蟾','宋','宋诗','song-poetry','','[]','峽口青門束碧流，天生雙劍割清秋。',64,'全唐诗/poet.song.207000.json','["峽口青門束碧流，天生雙劍割清秋。", "可憐柳葉黄如此，曾見蘆花白也不。", "本意買舟歸楚國，此行爲硯訪端州。", "渴來欲吸三江水，洗出胸中萬斛愁。"]'),
('7079fc24-affe-42de-8ee7-8800636dd782','梅花','白玉蟾','宋','宋诗','song-poetry','','[]','損之又損玉精神，松竹新來漸卜鄰。',64,'全唐诗/poet.song.207000.json','["損之又損玉精神，松竹新來漸卜鄰。", "月夜一枝香暗度，溪樓數點影橫陳。", "直須何遜爲知己，始信張良似婦人。", "從此東風還入手，管教桃李十分春。"]'),
('db6e0e6b-7f8b-42a2-8879-09e62bf062bf','三月芙蓉','白玉蟾','宋','宋诗','song-poetry','','[]','豈論春夏及秋冬，事事皆由造化工。',64,'全唐诗/poet.song.207000.json','["豈論春夏及秋冬，事事皆由造化工。", "誰道一生無好運，何緣三月見芙蓉。", "騷人猶恐東風誤，醉眼真疑芍藥紅。", "便是重陽開未晚，且傳好意取歡容。"]'),
('5c4ceda7-8b44-4df1-8877-b90f055086c4','柳塘送春','白玉蟾','宋','宋诗','song-poetry','','[]','急雨將雷過柳塘，春因底事亦歸忙。',64,'全唐诗/poet.song.207000.json','["急雨將雷過柳塘，春因底事亦歸忙。", "經時不放荷花葉，昨夜盡收梔子香。", "判斷千林成夢去，安排一夏納風凉。", "開眉無覓愁來處，數筆晴雲盡水鄉。"]'),
('1f0cd263-8750-4e9d-a474-943f37b1a74a','暫別游德聲監稅','白玉蟾','宋','宋诗','song-poetry','','[]','風檣小艤水中央，接袖交肩話柄長。',64,'全唐诗/poet.song.207000.json','["風檣小艤水中央，接袖交肩話柄長。", "貸粟莊周輕得失，倚樓杜甫重行藏。", "情知此去無多遠，未別一聲先斷腸。", "排辦新詩消遣酒，高吟大笑渡番陽。"]'),
('5bad8e5f-e619-4e92-8229-256ec652ab82','賦月同鶴林酌別奉似紫瓊友','白玉蟾','宋','宋诗','song-poetry','','[]','婀娜姮娥處玉宮，秋來梳洗越當空。',64,'全唐诗/poet.song.207000.json','["婀娜姮娥處玉宮，秋來梳洗越當空。", "陰晴圓缺天何意，離合悲歡事與同。", "好去畫樓歌舞地，莫來清館別愁中。", "應知人不能如月，月且團圓月月逢。"]'),
('f8d611a2-f6ef-49e0-8ba8-7296a02ba953','題諸葛桂隠書堂','白玉蟾','宋','宋诗','song-poetry','','[]','豪俠相逢好弟兄，竹籬茆舍聚雙星。',64,'全唐诗/poet.song.207000.json','["豪俠相逢好弟兄，竹籬茆舍聚雙星。", "青松影裏詩鴻鴈，白石巖前酒鶺鴒。", "筆下驅回千鐵騎，胸中包得幾滄溟。", "令人憶著張華劍，三百年來無血腥。"]'),
('b84f1c38-3f11-4211-91f6-3a654804ffe1','題華嚴寺','白玉蟾','宋','宋诗','song-poetry','','[]','匹馬追風訪地靈，山銜夕照鳥飛驚。',64,'全唐诗/poet.song.207000.json','["匹馬追風訪地靈，山銜夕照鳥飛驚。", "裴休雖是參黄檗，韓愈何曾嗣哲兄。", "豎拂拈槌吾不會，篇詩斗酒過平生。", "儂家自有修行處，夜夜丹爐煉月明。"]'),
('5042cfff-8bbe-45fc-95f6-84f7f31d7647','草廬','白玉蟾','宋','宋诗','song-poetry','','[]','劉禪材非天下君，出師一表費殷勤。',64,'全唐诗/poet.song.207000.json','["劉禪材非天下君，出師一表費殷勤。", "卧龍夢破隆中月，列鴈轟開蜀口雲。", "甫得江心成八陣，奈何天意要三分。", "木牛流馬今何用，頼有玄仍繼策勳。"]'),
('363ce4fe-77f3-424f-a22c-e2d7f014ce00','不赴宴贈丘妓','白玉蟾','宋','宋诗','song-poetry','','[]','舞拍歌聲妙不同，笑携玉斚露春葱。',64,'全唐诗/poet.song.207000.json','["舞拍歌聲妙不同，笑携玉斚露春葱。", "梅花體態香凝雪，楊柳腰肢瘦怯風。", "螺髻雙鬟堆淺翠，櫻唇一點弄嬌紅。", "白鷗不入鴛鴦社，夢破巫山雲雨空。"]'),
('155aaea2-74be-42ff-8777-73b6580f2599','夜宿太清悟真成道宮','白玉蟾','宋','宋诗','song-poetry','','[]','朱樓紫殿貼晴空，前後千峯更萬峯。',64,'全唐诗/poet.song.207000.json','["朱樓紫殿貼晴空，前後千峯更萬峯。", "蝶殢秋花黄淡佇，猿啼曉樹翠溟濛。", "斷霞煙重苔粘露，薄暮雲興夜起風。", "醉倚玉欄弄明月，嗟嗟身世等萍蓬。"]'),
('e27cdd2d-3a60-46c6-92d9-7cebd5aa770b','栩菴以冰字韻求大風詩口占','白玉蟾','宋','宋诗','song-poetry','','[]','山高萬籟作秋聲，六月胡床冷似冰。',64,'全唐诗/poet.song.207000.json','["山高萬籟作秋聲，六月胡床冷似冰。", "浩浩拍窗人不寐，颼颼到枕夢難成。", "掀開雲幕飛蒼絮，推出蟾輪碾素璚。", "幸有許多閑氣力，何如吹我上瑶京。"]'),
('8a9abb01-59bf-4ff7-8b21-c9c0cd44baf4','寄桂隠','白玉蟾','宋','宋诗','song-poetry','','[]','指點篇書說向誰，武侯之後獨公奇。',64,'全唐诗/poet.song.207000.json','["指點篇書說向誰，武侯之後獨公奇。", "許瓢却大堯天小，嚴瀨應高漢座卑。", "夙世已償霖雨債，我身今結水雲知。", "何人桂樹中間隠，莫作南陽一睡驪。"]'),
('352e378c-7b3c-4478-9ee6-fdff5b3a5c14','舟行西湖詩贈諸友','白玉蟾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','二十年來雲水身，今凡七度踏京塵。',64,'全唐诗/poet.song.207000.json','["二十年來雲水身，今凡七度踏京塵。", "絲長歲月能多少，粟大功名徒苦辛。", "白日戲陪人世事，綠煙鎖斷洞門春。", "雲巖月岫今何處，一聽猿聲一愴神。"]'),
('69022011-1a64-4f14-b368-7d0e69e93cd1','繡香亭招飲','白玉蟾','宋','宋诗','song-poetry','','[]','海棠開後雨冥綿，寒食清明又一年。',64,'全唐诗/poet.song.207000.json','["海棠開後雨冥綿，寒食清明又一年。", "勝賞挨排三月朔，嫩晴將息百花天。", "水光山色供圖障，燕語鶑聲助管絃。", "我自吟邊閑拄頰，笑人陌上拾花鈿。"]'),
('eb7cb762-ce97-4865-a4e3-1bbe99620dfc','悟空寺','白玉蟾','宋','宋诗','song-poetry','','[]','迷則僧祇悟剎那，遍將此事勘禪和。',64,'全唐诗/poet.song.207000.json','["迷則僧祇悟剎那，遍將此事勘禪和。", "春深未解桃花旨，日永其如燕語何。", "曉殿冷凝山色重，夜樓闊占月華多。", "西來祖意憑誰委，只有門前窣堵波。"]'),
('8d610494-99f6-42f8-824f-6cc7fb527c97','春夏之交奉呈胡總領','白玉蟾','宋','宋诗','song-poetry','','[]','殘紅點點尚春光，小立芳臺送夕陽。',64,'全唐诗/poet.song.207000.json','["殘紅點點尚春光，小立芳臺送夕陽。", "鶑語只聞花裏面，鷗飛宛在水中央。", "風前綠草無人管，煙外青山底處藏。", "柳幄張天槐幕靜，一川漲起麥雲黄。"]'),
('be232892-bd84-4033-9b31-23c8178b8e03','初冬即事','白玉蟾','宋','宋诗','song-poetry','','[]','搘頤默默靠柴扉，頓放詩題塞翠微。',64,'全唐诗/poet.song.207000.json','["搘頤默默靠柴扉，頓放詩題塞翠微。", "三徑寒松含宿雨，一川衰草卧斜暉。", "孤煙白處丫峯露，亂葉紅邊箇鳥歸。", "觸目園林已如洗，菊花猶著鬰金衣。"]'),
('c0a1be15-77fe-46d3-b82f-686293418359','梅花二首寄呈彭吏部  其一','白玉蟾','宋','宋诗','song-poetry','','[]','一自花光爲寫真，至今冷落水之濱。',64,'全唐诗/poet.song.207000.json','["一自花光爲寫真，至今冷落水之濱。", "惟三更月其知己，此一瓣香專爲春。", "清所以清冰骨格，損之又損玉精神。", "雪中好與誰爲伴，只有竹如君子人。"]'),
('3ed46619-a840-40e0-bbe7-b89a99124109','梅花二首寄呈彭吏部  其二','白玉蟾','宋','宋诗','song-poetry','','[]','冰玉丰姿不可雙，霜前雪後想凄凉。',64,'全唐诗/poet.song.207000.json','["冰玉丰姿不可雙，霜前雪後想凄凉。", "絕憐夜氣渾如水，而况笛聲堪斷腸。", "以月照之偏自瘦，無人知處忽然香。", "從今桃李皆門士，誰道花中有孟嘗。"]'),
('fd371cd6-e313-4831-891e-8dd84331d605','有贈','白玉蟾','宋','宋诗','song-poetry','','[]','雲鎖蓬萊海接天，琪花瑶草簇春煙。',64,'全唐诗/poet.song.207000.json','["雲鎖蓬萊海接天，琪花瑶草簇春煙。", "三千年裏桃初實，十二樓前月正圓。", "白日塵埃飛不到，青冥風露冷無眠。", "共君既飽胡麻飯，一棹歸歟弱水船。"]'),
('881d9c88-00e6-4a56-bcfa-c6363b23d2e2','黄巖舟中','白玉蟾','宋','宋诗','song-poetry','','[]','滿船明月浸虛空，綠浄無痕夜氣濃。',64,'全唐诗/poet.song.207000.json','["滿船明月浸虛空，綠浄無痕夜氣濃。", "詩思浮沉檣影裏，夢魂摇曳櫓聲中。", "星辰冷落碧潭水，鴻鴈悲鳴白蓼風。", "一點漁燈依古岸，斷橋垂露滴梧桐。"]'),
('148abea3-3328-4b1c-ab42-3c308dc375ec','奉呈天谷','白玉蟾','宋','宋诗','song-poetry','','[]','底事英人便養高，角鷹放了棄弓刀。',64,'全唐诗/poet.song.207000.json','["底事英人便養高，角鷹放了棄弓刀。", "六壬八遁成韜晦，四塞三邊婁繹騷。", "九十日秋凉氣少，一千年事亂時多。", "長歌大笑不對飲，奈此水光山色何。"]'),
('d6d9701c-99a8-4b1f-b659-1c1230200909','蟠龍菴','白玉蟾','宋','宋诗','song-poetry','','[]','五乳峯前第幾峯，碧潭深處有蟠龍。',64,'全唐诗/poet.song.207000.json','["五乳峯前第幾峯，碧潭深處有蟠龍。", "半巖冷落孔明雨，一枕蕭騷少說風。", "變化爪牙君子竹，埋藏頭角大夫松。", "高人凄此結茆屋，天下蒼生怨旱虹。"]'),
('8df1770e-de0e-421d-ad39-f62ec516d4b8','玉壺睡起','白玉蟾','宋','宋诗','song-poetry','','[]','白雲深處學陳摶，一枕清風天地寬。',64,'全唐诗/poet.song.207000.json','["白雲深處學陳摶，一枕清風天地寬。", "月色似催人起早，泉聲不放客眠安。", "甫能蝴蝶登天去，又被杜鵑驚夢殘。", "開眼半窗紅日爛，直疑道士夜燒丹。"]'),
('01c8296d-3cb6-4448-a406-d02c814823b6','携友生詣桐柏','白玉蟾','宋','宋诗','song-poetry','','[]','籃輿過盡幾山丫，夜宿天台仙子家。',64,'全唐诗/poet.song.207000.json','["籃輿過盡幾山丫，夜宿天台仙子家。", "我昔巖前種芝草，爾來雲表飯胡麻。", "金前錯落楓猶葉，玉靨飄零菊更花。", "霜露逼人心興倦，無窮舊事散天涯。"]'),
('b5c11a47-7460-4f31-888a-e94f24c93e67','山中','白玉蟾','宋','宋诗','song-poetry','','[]','天台山頭梅花時，天台仙人去不歸。',64,'全唐诗/poet.song.207000.json','["天台山頭梅花時，天台仙人去不歸。", "曉猿夜鶴不堪聽，丹井藥爐何所依。", "老竹數竿瀕碧澗，寒鴉幾點餞斜暉。", "幽人無限縈心事，未得工夫隠翠微。"]'),
('fde3b4f8-bf01-48a9-bd5f-a61e96a016f6','謁鵝湖大義禪師','白玉蟾','宋','宋诗','song-poetry','','[]','古塔寒龕幾歲華，粥魚齋鼓響巖丫。',64,'全唐诗/poet.song.207000.json','["古塔寒龕幾歲華，粥魚齋鼓響巖丫。", "滿湖春水浸明月，一带晚山橫彩霞。", "石鹿至今空卧草，金鵝終不再啣花。", "寥寥此意無人委，欲界無禪果是耶。"]'),
('fabc94ae-3d99-49ae-b0d2-18be24fef39e','醉裏','白玉蟾','宋','宋诗','song-poetry','','[]','道人天地便爲家，慣見溪山眼不花。',64,'全唐诗/poet.song.207000.json','["道人天地便爲家，慣見溪山眼不花。", "竹月光中詩世界，松風影裏酒生涯。", "醒時吟笑揚州鶴，夢見常騎月府蟆。", "是則官家縻好爵，此生只合飯胡麻。"]'),
('fe65a971-caf7-419e-a728-4715ca55cc28','寄泉州□侍郎','白玉蟾','宋','宋诗','song-poetry','','[]','海山迢遞信音稀，靜對斜陽獨倚扉。',64,'全唐诗/poet.song.207000.json','["海山迢遞信音稀，靜對斜陽獨倚扉。", "回首八千餘里路，覺今二十一年非。", "白雲流水聊相伴，絳闕清都未得歸。", "昨夜樂丘殘夢覺，窗前明月照鶉衣。"]'),
('475dd4d4-1ad5-4854-ae10-9e68d911ba75','知足軒','白玉蟾','宋','宋诗','song-poetry','','[]','得隴還爲望蜀謀，貪心來往似江潮。',64,'全唐诗/poet.song.207000.json','["得隴還爲望蜀謀，貪心來往似江潮。", "誰知一死乃所欠，若曰四休渠不消。", "田氏三千人食客，元家八百斛胡椒。", "更烹侍妾充殽饌，何事貧顔但一瓢。"]'),
('8229a73a-eba2-4519-826b-39318c928759','除夕客桂嶺','白玉蟾','宋','宋诗','song-poetry','','[]','誰使詩狂墮桂林，鳴鞭裊雪一傷心。',64,'全唐诗/poet.song.207000.json','["誰使詩狂墮桂林，鳴鞭裊雪一傷心。", "自憐褦襶衣何薄，安有酴酥酒得斟。", "真箇飄蓬將欲老，何曾鹵莽似如今。", "黄劉不喜瑜蒙喜，須信甘寧有賞音。"]'),
('9f509295-c775-4529-b6c1-19d51d90c34a','卧病','白玉蟾','宋','宋诗','song-poetry','','[]','故故抽身入翠微，頭昏背痛便相隨。',64,'全唐诗/poet.song.207000.json','["故故抽身入翠微，頭昏背痛便相隨。", "只今得病緣身有，待我無身更病誰。", "天際寒雲糊遠岫，松梢歸鶴客枯枝。", "青燈獨照黄昏影，且自扶頭强賦詩。"]'),
('cf102e55-6e70-45b7-84d6-4122fab2a31e','轎中','白玉蟾','宋','宋诗','song-poetry','','[]','紅輪荏苒向西頹，筍乘鴟蹲手拄腮。',64,'全唐诗/poet.song.207000.json','["紅輪荏苒向西頹，筍乘鴟蹲手拄腮。", "摇兀形神生睡思，按行水石得詩媒。", "山光走向簷前拱，溪響飛從闥畔來。", "遥見青山如雪白，心知箇是數枝梅。"]'),
('199b055c-9335-4ca4-adbc-2d1b0e9216e7','題金粟洞','白玉蟾','宋','宋诗','song-poetry','','[]','白雲亂山深復深，洞口枯樹鳴幽禽。',64,'全唐诗/poet.song.207000.json','["白雲亂山深復深，洞口枯樹鳴幽禽。", "玉雪影梅春寂寞，琅風韻竹夜蕭森。", "海流城外青羅带，巖聳天邊碧玉簪。", "憶著仙人鄭文叔，淚隨夕照落平林。"]'),
('1fe4570d-9c76-4c36-a553-f72150d7f430','贈相士岳鬼眼','白玉蟾','宋','宋诗','song-poetry','','[]','眉峰肩井額陂陀，此相曾經鬼眼過。',64,'全唐诗/poet.song.207000.json','["眉峰肩井額陂陀，此相曾經鬼眼過。", "知有命存聊爾耳，謂無天定盍如何。", "十常九事未如意，一滿三停屬甚科。", "佛說我身周法界，恐君莫是爍迦羅。"]'),
('441aa502-740c-4ce6-b5c9-a7f87a4b9a8c','歸鴈亭','白玉蟾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','坡仙曾此縷歸程，歸鴈因而扁此亭。',64,'全唐诗/poet.song.207000.json','["坡仙曾此縷歸程，歸鴈因而扁此亭。", "草勁風剛苕水綠，水枯雪老弁山青。", "霜翎去去賓沙漠，雲足翩翩影洞庭。", "渠亦偶來還自去，弋人何用慕冥冥。"]'),
('6887465c-2f7f-4a90-bf11-49614cb1b802','黄刑部倉部陳宗博招飲','白玉蟾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','暇日聯鑣共暑鏖，冰吾瓜李雪吾醪。',64,'全唐诗/poet.song.207000.json','["暇日聯鑣共暑鏖，冰吾瓜李雪吾醪。", "樓前一水佳人士，眼底千山兒女曹。", "朝士西湖正絺綌，將軍北塞更弓刀。", "道人萬丈英雄氣，不信胥臺便是高。"]'),
('5166cab9-4ef2-4292-b831-87c71c67acb9','草亭偶書','白玉蟾','宋','宋诗','song-poetry','','[]','賦罷清都白玉樓，不知何事復閻浮。',64,'全唐诗/poet.song.207000.json','["賦罷清都白玉樓，不知何事復閻浮。", "琴彈十二欄桿月，酒洗三千世界秋。", "絳闕瑶臺知有路，空青水碧若爲求。", "紫皇早晚憐孤憤，背土凌虛上去休。"]'),
('3daa242a-2458-4281-9e84-12710d275490','年踰弱冠又多錦瑟之一絃身墮塵樊未徹玉霄之半日醉懷無奈顧影自憐抱明月以興悲向西風而思遠謾拈禿兔姑慰心猿寄鶴林友','白玉蟾','宋','宋诗','song-poetry','','[]','夜凉莫聽野猿哀，覺我枯腸轉九迴。',64,'全唐诗/poet.song.207000.json','["夜凉莫聽野猿哀，覺我枯腸轉九迴。", "淅淅秋風吹性水，淹淹暮雨滴心灰。", "自憐孤影青燈下，曾作神霄故吏來。", "若待此生塵債足，鳳凰閤下已青苔。"]'),
('b0f1218b-d60f-4dee-99b0-7dfaa01a5819','留別鶴林諸友','白玉蟾','宋','宋诗','song-poetry','','[]','千林凉葉顫秋聲，前庭後庭新月明。',64,'全唐诗/poet.song.207000.json','["千林凉葉顫秋聲，前庭後庭新月明。", "聚頭舉酒固自樂，秉燭遊園聊適情。", "此去寒衾仙骨冷，可堪清夜淚珠傾。", "人生聚散渾無據，相約同遊白玉京。"]'),
('3f133f72-c5f2-4959-bb04-a5cf209548ad','見懶翁  其一','白玉蟾','宋','宋诗','song-poetry','','[]','一掬精神迥出塵，懶翁自是不凡人。',64,'全唐诗/poet.song.207000.json','["一掬精神迥出塵，懶翁自是不凡人。", "淵明松菊逕猶綠，靈運池塘草正春。", "已把芝田栽枸杞，不將苔砌展蒲輪。", "家傳衣鉢歸龍鳳，自指冰壺嗣潁濱。"]'),
('5c86bb77-39d4-4344-95b7-90b36151d37b','見懶翁  其二','白玉蟾','宋','宋诗','song-poetry','','[]','坡仙何日跨鯨歸，公是蘇家老白眉。',64,'全唐诗/poet.song.207000.json','["坡仙何日跨鯨歸，公是蘇家老白眉。", "把劍舞殘盃內酒，撫琴彈破筆頭詞。", "桂林種德不知歲，福海流長無盡時。", "他年翁若回蓬島，穩把青氈付阿誰。"]'),
('d47054d2-d1e4-4a16-a36b-01e878f3b510','復盧良菴韻','白玉蟾','宋','宋诗','song-poetry','','[]','擬占朝班最上頭，宦情冷似一天秋。',64,'全唐诗/poet.song.207000.json','["擬占朝班最上頭，宦情冷似一天秋。", "風花雪月千金子，水竹雲山萬戶侯。", "海客盟鷗終不動，塞翁失馬更何求。", "明窗浄几華胥外，蝴蝶翩翩自夢周。"]'),
('edcd17dd-de9a-4bbf-955f-f9b790c2eaa1','翛然軒','白玉蟾','宋','宋诗','song-poetry','','[]','不著人間一點塵，翛然一室貯幽人。',64,'全唐诗/poet.song.207000.json','["不著人間一點塵，翛然一室貯幽人。", "清宵甕下酒中聖，白晝筆頭詩泣神。", "芳草惜鋤憐綠浄，落花慵掃愛紅勻。", "棋聲隔斷華胥路，自把博山燒暮春。"]'),
('24748025-f92a-4044-87ba-e48629595db3','夢中得五十六字','白玉蟾','宋','宋诗','song-poetry','','[]','醉醒曳杖訪松關，正在黄昏杳靄間。',64,'全唐诗/poet.song.207000.json','["醉醒曳杖訪松關，正在黄昏杳靄間。", "既去復來秋後暑，似無還有雨中山。", "澗邊幾葉晚花落，天際一鈎明月彎。", "自覺餘煙埋屐齒，行行印破蘚痕班。"]'),
('6a823eb6-ff83-447b-8123-6150bece4c22','謁雩都靈濟大師','白玉蟾','宋','宋诗','song-poetry','','[]','雪裏僧伽已寂然，不知香火幾何年。',64,'全唐诗/poet.song.207000.json','["雪裏僧伽已寂然，不知香火幾何年。", "殷勤琢雪雕冰語，懺悔嘲風弄月愆。", "林壑烟霞容有分，廟堂鍾鼎得無緣。", "天池舊拜金燈了，却裹兜羅一袖綿。"]'),
('c4b4444f-0f15-4d4f-a3cb-35381fe38475','次黄提刑雪韻','白玉蟾','宋','宋诗','song-poetry','','[]','久晴忽爾雨絲絲，既雨還晴亦不疑。',64,'全唐诗/poet.song.207000.json','["久晴忽爾雨絲絲，既雨還晴亦不疑。", "滕六假寧催入局，趙衰回避乞尋醫。", "搗霜碾雹些來箇，剪水雕冰片子時。", "一夜悄然飛到曉，滿天滿地化琉璃。"]'),
('f0c6131d-97d6-4d16-8136-59a80007e848','早秋諸友真率相聚','白玉蟾','宋','宋诗','song-poetry','','[]','白帝如今已有權，驕陽退壁漸凉天。',64,'全唐诗/poet.song.207000.json','["白帝如今已有權，驕陽退壁漸凉天。", "兌支一霎風來享，供送三更月與眠。", "山水秋來渾是畫，賓朋酒後總成仙。", "暗蛩彈鑷知何處，遠樹長川忽眇綿。"]'),
('22be7e52-a056-490d-9ab7-7d28dec5df33','春夢','白玉蟾','宋','宋诗','song-poetry','','[]','我亦頻年飲大苛，吟髭撚盡爲詩魔。',64,'全唐诗/poet.song.207000.json','["我亦頻年飲大苛，吟髭撚盡爲詩魔。", "夜來斗轉參橫後，夢在吳頭楚尾多。", "所喜江山無病痛，可憐故舊半消磨。", "水車自轉如誰踏，枕上松聲奈若何。"]'),
('150a94f8-fd4d-452c-a5b9-1dc4234a0f20','送彭侍晨','白玉蟾','宋','宋诗','song-poetry','','[]','鐵髭鶻眼兩顔酡，走遍江湖所得多。',64,'全唐诗/poet.song.207000.json','["鐵髭鶻眼兩顔酡，走遍江湖所得多。", "脚踏雷車朝帝極，手持斗柄戽天河。", "劍尖指處乾坤暗，丹篆書時鬼魅號。", "名滿四方今老矣，請歸玉府掌西曹。"]'),
('c4e10fa8-7952-4e1d-ad54-fabde60394a4','呈沈同知','白玉蟾','宋','宋诗','song-poetry','','[]','三面俱江一面湖，古今畫作水晶圖。',64,'全唐诗/poet.song.207000.json','["三面俱江一面湖，古今畫作水晶圖。", "門臨車馬紅塵道，身在冰霜碧玉壺。", "何道兩山俱翠紫，霅苕二水合清污。", "岸頭笑與黄冠語，爲問東林沈在乎。"]'),
('594592c4-0947-4e03-bdff-74cc37e1a096','別蔣都轄用歸鴈韻','白玉蟾','宋','宋诗','song-poetry','','[]','別來不覺八周星，過盡長亭又短亭。',64,'全唐诗/poet.song.207000.json','["別來不覺八周星，過盡長亭又短亭。", "霜鴈貼天飛去去，弋人何事慕冥冥。", "梅開春信賓南國，草勁秋聲警虜庭。", "我亦年來還慷慨，亭前一笑萬山青。"]'),
('1acab369-c56a-4182-968a-ef266d7b82b3','三衢舟次  其一','白玉蟾','宋','宋诗','song-poetry','','[]','柿葉翻黄楓葉紅，一江漲起蘆花風。',64,'全唐诗/poet.song.207000.json','["柿葉翻黄楓葉紅，一江漲起蘆花風。", "水清石露沙痕瘦，日落雨來雲意濃。", "詩思動摇帆影裏，夢魂摇兀櫓聲中。", "黄昏有底愁如織，南外寄書無去鴻。"]'),
('ff117811-c50f-42d3-9dbe-463b3bcf19eb','三衢舟次  其二','白玉蟾','宋','宋诗','song-poetry','','[]','困獸猶强劍未紅，少年羞見白蘋風。',64,'全唐诗/poet.song.207000.json','["困獸猶强劍未紅，少年羞見白蘋風。", "心寒赤縣神州遠，興入胡庭沙漠濃。", "誰謂阿蒙猶洛下，未應老亮更隆中。", "年來弓矢渾無用，只好江頭射暮鴻。"]'),
('ceb38341-0199-40eb-a78a-cb8b0a44d203','偶成','白玉蟾','宋','宋诗','song-poetry','','[]','倚蓬小立拂征衣，沙上漁翁理釣絲。',64,'全唐诗/poet.song.207000.json','["倚蓬小立拂征衣，沙上漁翁理釣絲。", "舉世更誰閑似我，只今何事未如伊。", "莫將水動疑天動，且道舟移是岸移。", "家在神霄歸未得，釣周釣漢笑人癡。"]'),
('aa6eafb0-d1b2-43b0-b550-2d8c0454536e','午飯羅漢寺','白玉蟾','宋','宋诗','song-poetry','','[]','林間一徑似驚蛇，中有禪關隠紫霞。',64,'全唐诗/poet.song.207000.json','["林間一徑似驚蛇，中有禪關隠紫霞。", "煙鎖蒼松遮寺額，風摇翠竹撼簷牙。", "客來寂寞盤香穗，飯罷從容瀹茗花。", "到此徘徊歸去晚，夕陽挂樹一聲鴉。"]'),
('afd25b0d-752f-4a58-b568-7a53f97ecbb0','北山','白玉蟾','宋','宋诗','song-poetry','','[]','驛酒沽來滿滿斟，現成詩句不須尋。',64,'全唐诗/poet.song.207000.json','["驛酒沽來滿滿斟，現成詩句不須尋。", "輕雲閣雨風聲軟，淡霽籠雲日影沉。", "夾路梔花香野水，隔山杜宇響喬林。", "草菴飯了從容睡，門外通衢無古今。"]'),
('b5d7450f-9082-40e0-8392-6a19e018d062','清貧軒','白玉蟾','宋','宋诗','song-poetry','','[]','一味逍遥不管天，日高丈五尚閑眠。',64,'全唐诗/poet.song.207000.json','["一味逍遥不管天，日高丈五尚閑眠。", "溪魚村酒別般味，野蔌山餚不用錢。", "甕牖蓽門關小逕，乾柴白米煮清泉。", "有時拄杖青松畔，便是人間快活仙。"]'),
('c9a46722-d08e-4b37-8b94-6a2053b2f781','春日遣興','白玉蟾','宋','宋诗','song-poetry','','[]','大家放下杖頭雲，夜宿南安煙水村。',64,'全唐诗/poet.song.207000.json','["大家放下杖頭雲，夜宿南安煙水村。", "蝴蝶夢殘天拂曉，杜鵑聲斷月黄昏。", "蜂王遣使使花塢，蟻陣分屯屯蓽門。", "自是吾儂適懷處，詩山酒海一乾坤。"]'),
('65c54961-9d8a-4e8d-a546-f8e3005752f1','乞紙寄諸葛桂隠','白玉蟾','宋','宋诗','song-poetry','','[]','翰墨膏肓二十年，纔親筆硯便垂涎。',64,'全唐诗/poet.song.207000.json','["翰墨膏肓二十年，纔親筆硯便垂涎。", "東陽魚卵寒霜幅，嵊縣溪藤妙雪牋。", "一日禿除千兔穎，霎時磨盡萬松煙。", "洛陽市上今無價，直欲昂頭寫碧天。"]'),
('0ff39861-1c1e-4d10-9a65-c528c4868176','春日即事','白玉蟾','宋','宋诗','song-poetry','','[]','伶倫窺管夜飛灰，萬紫千紅暗剪裁。',64,'全唐诗/poet.song.207000.json','["伶倫窺管夜飛灰，萬紫千紅暗剪裁。", "微雨績天煙織雪，寒風簸水月篩梅。", "壽鳩索婦花前笑，鰥燕呼雛柳外哀。", "春色無邊茶未莢，社前猶欠一聲雷。"]'),
('3a0046e4-e0d3-45e5-9027-d18030319006','次韻紫巖潘庭堅  其一','白玉蟾','宋','宋诗','song-poetry','','[]','人情不似吳牋厚，世路常如蜀道難。',64,'全唐诗/poet.song.207000.json','["人情不似吳牋厚，世路常如蜀道難。", "兩鬢已將沾雪白，寸心尚自炳楓丹。", "君還有意憑誰說，我亦無言把劍看。", "相對一窗風打雪，通紅榾柮謾燒殘。"]'),
('c23049ec-466c-4240-a2aa-1c9cfc6eda90','次韻紫巖潘庭堅  其二','白玉蟾','宋','宋诗','song-poetry','','[]','何人皮裏有陽秋，誰絹能包得許羞。',64,'全唐诗/poet.song.207000.json','["何人皮裏有陽秋，誰絹能包得許羞。", "早趁黄書丞相押，莫空白了少年頭。", "既無顧戀於人己，便請清閑袖手休。", "豈必滅秦安漢後，始來尋個赤松游。"]'),
('6e39255f-6aad-41a8-a3c5-f9915c99e97b','題仙槎寄呈王待制','白玉蟾','宋','宋诗','song-poetry','','[]','道人身世已盟鷗，便好乘雲御氣休。',192,'全唐诗/poet.song.207000.json','["道人身世已盟鷗，便好乘雲御氣休。", "何足風波吾一點，盍思舟楫彼迷流。", "從教水擊三千里，別是煙飄十二樓。", "松以碧濤成夜吼，山爲翠浪接空浮。", "初非孔聖乘桴志，薄類梁僧渡葦謀。", "廬阜插篙空木末，武夷停櫂尚巖頭。", "爭如太乙真人葉，往盪須彌絕頂秋。", "昔者天孫失機石，我疑博望乃牽牛。", "却無滄海桑田事，底用浮家泛宅愁。", "箇裏且吹無孔笛，向人只下直針鈎。", "而今性水涵孤月，休遣禪河起一漚。", "逝者如斯曾不返，憑誰爲我問陽侯。"]'),
('15eba47f-379c-42c6-9da3-eaca6c85d37e','捲雪樓','白玉蟾','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','煙水蒼蒼古渡頭，神鴉噪罷纜方收。',96,'全唐诗/poet.song.207000.json','["煙水蒼蒼古渡頭，神鴉噪罷纜方收。", "泊舟鳬渚鷗汀晚，夜入蘭宮桂殿秋。", "綠葦黄蘆悲落日，白蘋紅蓼閙滄洲。", "冥冥千古今如夢，浩浩長江不管愁。", "鴈陣歸時雲似幕，風檣高處月如鈎。", "驚濤飛起銀花舞，萬頃寒光十二樓。"]'),
('a54651e4-807b-4cd0-821d-8a4d52d76c38','山月軒','白玉蟾','宋','宋诗','song-poetry','','[]','老蟾飛上梧桐枝，蒼屏煙冷猿夜啼。',128,'全唐诗/poet.song.207000.json','["老蟾飛上梧桐枝，蒼屏煙冷猿夜啼。", "瀲灧金盤掛寒巘，嬋娟玉鏡沉清溪。", "風前松竹盡起舞，姮娥徘徊不歸去。", "人在廣寒天在水，滿天星斗知何處。", "幽人爲我鳴瑶琴，山前月下千古心。", "不知明月幾圓缺，只有青山無古今。", "醉持玉盞吞金餠，塵世無人知此景。", "青山無言人酩酊，浩歌卧斷桂花影。"]'),
('75744960-18fd-4179-8680-d4d2435c0609','送談執權張南顯歸廣州','白玉蟾','宋','宋诗','song-poetry','','[]','七月送我東南道，八月送我西南道。',182,'全唐诗/poet.song.207000.json','["七月送我東南道，八月送我西南道。", "西南江沙黄茫茫，東南海水白浩浩。", "海水飛作潮頭來，潮頭卷取潮舌回。", "江沙一望渺千里，千里亦此一江水。", "水外青山山外雲，雲邊蒼樹樹邊村。", "村有酒酤酤不得，小船寂寞愁黄昏。", "大丈夫，不拘此。", "無酒便如何，有酒亦樂只。", "爲問東南海水西南江，如何滔滔獨未降。", "豈不亦笑老先生，有如此水亦迷邦。", "君但歸，歸去好，人生有情爲情惱。", "明朝輕舟當徑度，不須回首端州路。"]'),
('cf1abeea-72c1-4c84-9fa6-b0374dbd523e','杜鵑行','白玉蟾','宋','宋诗','song-poetry','','[]','杜鵑哭，杜鵑哭。',108,'全唐诗/poet.song.207000.json','["杜鵑哭，杜鵑哭。", "微雨村，遠煙麓。", "山花紅，江楓綠。", "一聲殘，一聲續。", "一聲一聲復一聲，不管世間銀髮生。", "啼盡天涯夕陽影，又向空中啼月明。", "山中憔悴人，無緒傷春色。", "今古興亡一肚脾，臨風再拜君得知。", "兩行茅舍蒼煙淚，滴破浣花溪上詩。"]'),
('827bb157-2c32-40cc-8669-ff7791f2b10b','題楊家酒樓','白玉蟾','宋','宋诗','song-poetry','','[]','碧落散郎下人世，騎雲鞭霆日日醉。',48,'全唐诗/poet.song.207000.json','["碧落散郎下人世，騎雲鞭霆日日醉。", "楊家三杯松花醪，眼花渾不醒天地。", "知有溪山無名利，鐵笛吹破西山翠。"]'),
('ea5968df-22e7-4821-9d92-e7c2f8f77733','友人陳槱得楊補之三昧賞之以詩','白玉蟾','宋','宋诗','song-poetry','','[]','梅花不清是水清，最是一枝溪上橫。',320,'全唐诗/poet.song.207000.json','["梅花不清是水清，最是一枝溪上橫。", "梅花不明是雪明，凍折老梢飄碎瓊。", "梅花不暗是雨暗，隔籬和雨粘珠糝。", "梅花不淡是煙淡，煙鎖江村煙慘慘。", "梅花不枯是霜枯，霜後不俗霜前粗。", "梅花不瘦是月瘦，月下徘徊孤影峭。", "梅花不寒是風寒，落英飛上玉闌干。", "梅花不濕是露濕，冷蘂含羞曉嗚唈。", "雪明偏見梅花魂，筆下六花堆爛銀。", "水清偏見梅花骨，筆下一溪寒浸月。", "煙淡偏見梅花情，筆下一片黄昏晴。", "雨晴偏見梅花貌，筆下娉婷向人笑。", "月瘦偏見梅花真，筆下蟾蜍弄早春。", "霜枯偏見梅花操，筆下飛霜送春耗。", "露濕偏見梅花奇，筆下冷蘂垂百琲。", "風寒偏見梅花意，筆下蕭騷奪雲氣。", "有人身心似梅花，寫出清淺與橫斜。", "補之若見亦驚嗟，機杼迥然別一家。", "繁處不繁簡處簡，雪迷曉色月迷晚。", "更得一些香氣浮，陽春總在君筆頭。"]'),
('5a779c82-4f28-4ae6-81d6-8756251e4d30','覺非居士東菴甚奇觀玉蟾曾遊其間醉吟一篇舊風以紀之','白玉蟾','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u897f\u6e56"]','一甌之閩古無諸，山奇水秀真畫圖。',384,'全唐诗/poet.song.207000.json','["一甌之閩古無諸，山奇水秀真畫圖。", "霍童山在閩之隅，天下第一神仙都。", "神仙渺茫不可見，桑田滄海幾遷變。", "三山崒嵂青至今，堪嗟山下人如燕。", "螺女江頭十萬家，西湖十里碧蓮花。", "滿城和氣濃於酒，一天雨露饒桑麻。", "東有鼓山榴花谷，南有方山小王屋。", "王霸煉藥怡山西，老任跨鶴昇山北。", "距城以東七里餘，丹崖翠壁凌太虛。", "天閟地藏一蓬壺，神刓鬼劃畫不如。", "種橘仙人來瑞世，况是籛翁其後裔。", "蒼松筋骨鶴精神，謂之覺非老居士。", "居士少時觀此山，便擬歸隠乎其間。", "及其賦罷歸去來，此山尚鎖青煙寒。", "平生使節半天下，秋霜夏日大聲價。", "咄哉富貴非吾願，何似歸來一茅舍。", "百丁持钁薙荆榛，寒巖怪石翠崢嶸。", "奇花異草不知名，地靈夜泣猿鳥驚。", "天然一石大如廩，裂開發露五雲錦。", "滿地璀璨黄金沙，地下掘出玄玉枕。", "度其廣袤築屠蘇，鳷鵲峭聳鴛鴦鋪。", "人來山下抬頭看，直疑上有神仙居。", "夜靜星辰挂朱桷，萬丈華表立雙鶴。", "山童指向游山人，高處更有兼山閣。"]'),
('a490423d-0e6a-4ee5-9be6-ae159f8ee59f','題浯溪','白玉蟾','宋','宋诗','song-poetry','','[]','芙蓉睡足西風冷，漁陽捲入來無影。',192,'全唐诗/poet.song.207000.json','["芙蓉睡足西風冷，漁陽捲入來無影。", "不思夜火笑驪山，甘欲庭花唱宮井。", "馬嵬山下杜鵑聲，羅襪空淒花草馨。", "誰謂霓裳非有情，倚腔猶韻雨霖鈴。", "胡人先母而後父，此語悟君君不悟。", "天下何思復何慮，華清目送豬龍去。", "已矣去，知不知，悲莫悲於南內悲，危猶危似西狩危。", "伊人事定有所制，但得抱女成歔欷。", "元都水，顔太師，截祿山骨爲之字，瀝祿山血爲之辭。", "未千年事幾如此，風雨剝蝕蒼苔碑。", "禹啟乘雲去亦久，客舟空艤浯溪湄。"]'),
('22f37ee5-5ed8-427c-b202-7844ffa90992','賞梅感興','白玉蟾','宋','宋诗','song-poetry','','[]','千樹梅花明如月，一天月華皎如雪。',96,'全唐诗/poet.song.207000.json','["千樹梅花明如月，一天月華皎如雪。", "幽人心似梅花清，梅花亦作如是說。", "銀色世界生梅花，水晶宮中明月華。", "醉卧月華嚼梅蘂，滿身清影亂交加。", "今夕幽人換詩骨，花月即是詩衣鉢。", "明朝花作雪片飛，花下鶴雛啄苔髮。"]'),
('178717ca-1f9e-42ed-8e7b-a826571bd8ad','贈陳高士琴歌','白玉蟾','宋','宋诗','song-poetry','','[]','昨夜西風起白蘋，從前湖海幾酸辛。',384,'全唐诗/poet.song.207000.json','["昨夜西風起白蘋，從前湖海幾酸辛。", "感今懷古無限事，拄頰閑思一愴神。", "瓊窟先生鼓玉琴，一調一弄符我心。", "屈平宋玉不可挽，西風黄葉爲知音。", "初聞如風吹梧桐，次聽如雨鳴芭蕉。", "凄然如鴈聲遥遥，溫然如鶑暖夭夭。", "忽而轉調緩復急，海風吹起怒濤立。", "夜深星月墮蓬山，神官不管蛟龍泣。", "頓又換指清而和，牡丹芍藥香氣多。", "露橋月榭風雨夕，如此杜鵑愁奈何。", "浩浩長風送急雨，寂寞孤鴻落寒渚。", "昏昏月色老猿啼，藹藹風光新燕語。", "又如晴鶴唳蒼煙，倏似寒鴉噪晴川。", "良宵砌畔響秋蛩，清晝林間悲風蟬。", "我思此聲不堪比，使人欲悲復欲喜。", "五月葛亮渡瀘溪，九月荆軻過易水。", "此聲喜喜復哀哀，我志渺然在江淮。", "方且琵琶亭下坐，倏又鬰孤臺上回。", "琴聲展轉我心碎，我心多少平生事。", "絃中招我棲林泉，指下呼我入富貴。", "上界瑶池玉浪寒，鳳凰閣下羅千官。", "紫皇宴坐蒼琳宮，豈復知我猶人間。", "龜臺煙冷風蕭蕭，十萬彩女歌雲璈。", "自憐蹤跡今塵土，安得金妃復賜桃。"]'),
('effd341d-1985-4ea1-b36d-a623b038e8b1','一覽亭','白玉蟾','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','千山萬山聳寒碧，桃花李花正春色。',296,'全唐诗/poet.song.207000.json','["千山萬山聳寒碧，桃花李花正春色。", "客來登此一覽亭，東望長江渺無極。", "煙飛松塢曉蒼凝，雨過竹林晚翠滴。", "人家樓閣下參差，天宇雲霞上鬰密。", "平湖青草覆白沙，峭崖斷岸幾千尺。", "蘆荻叢中鷗鷺閑，來往漁舟三兩隻。", "柳陰濃淡夕陽斜，蘚巖石磴滿山赤。", "落鴉噪下枯樹枝，雞犬聲中半樵笛。", "疎籬小屋可容膝，目對青霄一太息。", "滿城車馬走紅塵，何人知享此幽寂。", "竹爐焚罷柏子香，甆杯傾瀉碧玉液。", "飲到如泥卧石鼓，醒來瀹茗自閑適。", "嘯詠太空歌一曲，風吼千林月華白。", "一覽亭前雙目明，詩成自覺天地窄。", "雲崖煙樹幾重重，三百六十真奇峯。", "我將持斧扣洞門，借問蟠桃幾時紅。", "流光瞬息付一電，萬事轉頭如去箭。", "南康有個陳參軍，心鏡如如成一片，自笑浮生若春燕。"]'),
('5cc15985-e15f-4c52-929e-73b2139d36ea','題潜菴','白玉蟾','宋','宋诗','song-poetry','','[]','已把功名等風絮，鶴氅星冠懶成趣。',64,'全唐诗/poet.song.207000.json','["已把功名等風絮，鶴氅星冠懶成趣。", "谷口人尋虎跡來，林間菴在猿啼處。", "好向青山白雲中，參取翠竹黄花句。", "道人珍重老維摩，明日千峯萬峯去。"]'),
('832e2ff3-7e85-4a35-8a78-1e51f78e8a0c','贈崧菴造墨','白玉蟾','宋','宋诗','song-poetry','','[]','水銖膠法仙而黠，萬杵玎璫肩欲脫。',64,'全唐诗/poet.song.207000.json','["水銖膠法仙而黠，萬杵玎璫肩欲脫。", "龍尾磨開紫玉腴，鼠鬚點動青霓活。", "油然作雲昇太清，沛然下雨驚四溟。", "何當點開衆生眼，大千世界常光明。"]'),
('d45920b3-819e-42d7-a39f-6f4f88d47943','飛仙吟送張道士','白玉蟾','宋','宋诗','song-poetry','','[]','夜騎玉鼇採明月，蘂殿瑶臺寒徹骨。',208,'全唐诗/poet.song.207000.json','["夜騎玉鼇採明月，蘂殿瑶臺寒徹骨。", "三十六天不閉門，風吹琪花散飛雪。", "簫韶鳴處隊仗多，八萬霓裳歌一闋。", "紫皇宴罷駕方出，整衣端簡去朝謁。", "火鈴將軍呵一聲，左右萬真聳毛髮。", "奏云臣是雷霆卿，舊因罪去辭金闕。", "紅塵埋身平至耳，餐青飲綠守苦節。", "飛神登天來正渴，見帝有酒覓一啜。", "賜臣一醉放臣歸，歸去人間向人說。", "鳳凰閣下問歸途，瓊童玉女却問予。", "天上日長太清虛，人間還似此間無。", "摇頭不答徑拂袖，白雲眇眇迷清都。", "洞中猿鶴更相認，白石爛兮青松枯。"]'),
('bfab789d-b8cc-4846-b937-d9e2f96a7192','詠雪于清虛堂火閣','白玉蟾','宋','宋诗','song-poetry','','[]','長空慘慘晝如夜，嚴風刮得雪片下。',224,'全唐诗/poet.song.207000.json','["長空慘慘晝如夜，嚴風刮得雪片下。", "寒猿傍樹不敢聲，江梅羞開恐易謝。", "萬山無限落葉愁，處處凝煙纏草舍。", "枯槎凍僵不復活，飛廉截住陽春赦。", "餒虎呼雛入巖卧，過鳥如梭鑽樹罅。", "園林蕭索無一物，幾夜霜威煞無藉。", "欲雨不雨數點霰，雪意沉吟天似詐。", "滿空飛起楊花架，三日兩日凍不化。", "眼前幻出白玉樓，誰敢登陟空嗟訝。", "肌膚生粟鼻流水，前村新醅復增價。", "漁翁溪畔笑收網，魚亦不知鈎有麝。", "洗鐺簇火煎雪茶，垂簾疊足說清話。", "呼童鑿碎硯中冰，呵手團欒結詩社。", "詩成此景尚自爾，安得王維收入畫。"]'),
('9babd8f8-941e-496d-8426-a7e4d2ffc200','波羅密','白玉蟾','宋','宋诗','song-poetry','','[]','南方有此波羅密，人所厭棄鬼神惜。',81,'全唐诗/poet.song.207000.json','["南方有此波羅密，人所厭棄鬼神惜。", "大如瓶笙身拳攣，長如囊枕針歷剌。", "天回故是來處遥，天南亦有能相識。", "君不見北人不夢象，南人何處夢駱駝。", "蜀犬吠月越吠雪，識與不識吾奈何。"]'),
('bf1f7e5f-8386-4d44-85ce-d41f2a153b19','悲秋辭','白玉蟾','宋','宋诗','song-poetry','','[]','蟲聲樹聲各已變，吾知流年暗中換。',368,'全唐诗/poet.song.207000.json','["蟲聲樹聲各已變，吾知流年暗中換。", "晝烏夜兔忙如箭，秋光漸入蘆花岸。", "蘆花白兮蓼花紅，鴻鴈跧蹲滿荻叢。", "牡丹海棠如夢中，蓮藕香散池館空。", "人生歲月去如水，燕去鶑歸一彈指。", "星霜磨老道人心，滿目世人紛如蟻。", "感今慨昔令人愁，乃知宋玉非悲秋。", "江山紫翠餞漢唐，風物不復追商周。", "古人混混去不返，今人紛紛知何限。", "古人憐今今憐古，夕陽影裏雲影亂。", "此身飄飄如游塵，身體髮膚皆他人。", "尚餘方寸管喜怒，不敢漏泄天公嗔。", "向時歡娛成冷落，誰與感慨憐蕭索。", "定知悲喜聚散因，世間果無揚州鶴。", "所可悲者貧且孤，覽鏡自笑清而癯。", "安能十事九如意，定數豈復人能踰。", "秋風起兮秋水寒，秋心悲兮秋興酸。", "佳人一去不復還，顧影度此時光難。", "此心寥寥秋夜月，孤光散入寒光闊。", "夜深月落無人知，江上漁翁空網撒。", "不堪舉此向愁人，使人泣下肝腸裂。", "何人爲我調素琴，疊疊爲我寫孤襟。", "庶令鬼神伴伊泣，山空樹冷風蕭森。"]'),
('14dee7b3-b620-46f2-9723-522122ec8ddf','題歐陽氏山水後','白玉蟾','宋','宋诗','song-poetry','','[]','平沙斷岸幾千尺，樹色煙光渺無極。',224,'全唐诗/poet.song.207000.json','["平沙斷岸幾千尺，樹色煙光渺無極。", "一葉扁舟歸去來，漁翁放棹倚蘆荻。", "八九山家雲水村，白蘋紅蓼數漁船。", "沙寒石瘦木葉落，一鈎淡月照黄昏。", "小橋跨水碧溪淺，蒼壁丹崖半苔蘚。", "樵子歸擔竹兩竿，落霞孤鶩天邊遠。", "千山萬山風色清，四柱茅亭立晚汀。", "花紅草綠山水靜，獨步亭前秋月明。", "山前一陣梧桐雨，落花驚斷山禽語。", "誰家樓閣隠青林，老僧歸寺立溪滸。", "一溪流水遶雲根，草舍茅庵常閉門。", "客來倚棹一回顧，直疑此是真桃源。", "洞門紫翠交相映，林幄山屏更清勝。", "何人作此無聲詩，展開如入溪山鏡。"]'),
('5533dceb-3afc-4497-9dbb-42a18c040b18','永州花月樓','白玉蟾','宋','宋诗','song-poetry','','[]','春風夜飛招月檄，檄月司花月供職。',160,'全唐诗/poet.song.207000.json','["春風夜飛招月檄，檄月司花月供職。", "月落千嬌百媚叢，諸花爲月妍爲容。", "樓東月照樓西皎，樓西月向樓東笑。", "月與花戲天中流，花與月浴江中浮。", "月皆不管春風怒，花爲月歌爲月舞。", "舞者媚綠歌嬌紅，爭憐妬寵驚春風。", "出有入無多變異，花竟不曉月之意。", "江花惱天天花愁，東樓月掩西樓羞。", "花亦自睡花自醉，月倦欲歸歸未至。", "却緣曉鍾呼月回，月回花醒花不知。"]'),
('98f913d1-f885-47d2-ae78-fd889e1c4880','燕巖行','白玉蟾','宋','宋诗','song-poetry','','[]','有客來從天竺峯，渡溪恰趁一篙風。',208,'全唐诗/poet.song.207000.json','["有客來從天竺峯，渡溪恰趁一篙風。", "秋風著力送行李，吹入燕巖松竹裏。", "松竹淒淒天作秋，空來空去空中浮。", "高巖萬丈聳空碧，仙翁騎鶴去無迹。", "丹爐不火草芊芊，數間巖屋掩寒煙。", "下有龍潭綠無底，瀑布懸崖千尺水。", "夜來月影滿空山，石鍾一響生秋寒。", "玉燕何年巖下舞，飛時化作滿天雨。", "盡言此巖多仙靈，白鶴點破一山青。", "煙霧罩山石常潤，莓苔滿地翠無盡。", "我欲誅茅此煉丹，奪取人間千歲閑。", "有箇高人陸巖主，抱琴對我彈中呂。", "勸我他年歸去來，此巖莫被煙雲埋。"]'),
('cdb774a8-3d6b-4425-a306-e5c8bac1d604','卧雲菴醉後','白玉蟾','宋','宋诗','song-poetry','','[]','千巖萬壑深復深，洞口枯樹鳴幽禽。',96,'全唐诗/poet.song.207000.json','["千巖萬壑深復深，洞口枯樹鳴幽禽。", "瑶月影松大靜淡，琅風韻竹夜蕭森。", "暮雲獻碧出孤岫，夕鳥拖紅投暝林。", "孔明終久須朝日，安石不來誰作霖。", "然則從龍雖有志，定知化鶴亦無心。", "先生不是終南子，滿洞蒼煙何處尋。"]'),
('d9d13a9a-daeb-4e5b-8a33-743971a7294b','景德觀枕流','白玉蟾','宋','宋诗','song-poetry','','[]','寒泉瀉破青山腹，青山不改寒泉綠。',128,'全唐诗/poet.song.207000.json','["寒泉瀉破青山腹，青山不改寒泉綠。", "幽人一心泉石心，倚溪著此數椽屋。", "窗外飄噴萬斛珠，枕邊玲瓏一片玉。", "山澗金龍嘯欲飛，澗底銀蟾清可掬。", "敲磬愁驚曉鷺眠，停經坐看昏鴉浴。", "香浮茗雪滋肺腑，響入松濤震崖谷。", "清浄耳觀絕絃琴，廣長舌相無生曲。", "客來坐此亦忘歸，溪南溪北千竿竹。"]'),
('03ac3581-ccd3-4662-9988-cd6dc0e55664','將進酒','白玉蟾','宋','宋诗','song-poetry','','[]','秋山蒼蒼秋雲黄，鴉浴咸池忽扶桑。',172,'全唐诗/poet.song.207000.json','["秋山蒼蒼秋雲黄，鴉浴咸池忽扶桑。", "一月二十九日醉，百年三萬六千場。", "嗟君千丈擎天手，而有萬卷懸河口。", "亂花飛絮心擾擾，不如中山千日酒。", "黄鑿落，赤叵羅。", "姑射真人注寶雪，廣寒仙子行金波。", "玉蛆初泛松花露，瓊螺再薦椒花雨。", "米大功名何足數，鴻毛利害奚自苦。", "醉則已，睡則休。", "水浩浩，天悠悠。", "君知否，昔在甲辰堯嗣位，迄今嘉定之辛巳。", "其中三千六百年，幾度寒楓逐逝川。"]'),
('044b861c-d478-4737-8470-d25557fb1b3a','秋思','白玉蟾','宋','宋诗','song-poetry','','[]','蒼崖高處雲濛濛，雲氣深中有碧鴻。',144,'全唐诗/poet.song.207000.json','["蒼崖高處雲濛濛，雲氣深中有碧鴻。", "萬里青霄飛徑度，依然又掠西風去。", "此時桂花開未開，故人不來鴻鴈來。", "一瞬四方無覓處，不堪回首瀟湘路。", "我方拄頰吟夕煙，徘徊欲賦空茫然。", "故人有酒坐秋夕，似我兩地遐相憶。", "一寫此詩聊問秋，江楓岸柳替人愁。", "縱然對面亦如夢，幽情付在玉三弄。", "玉笛淒涼遠不聞，不念山中有白雲。"]'),
('813207c7-1113-43ab-9112-91fe84a06ed9','聞鶴嘆','白玉蟾','宋','宋诗','song-poetry','','[]','霜翎雪羽臙脂頂，玄裳翠距白玉頸。',234,'全唐诗/poet.song.207000.json','["霜翎雪羽臙脂頂，玄裳翠距白玉頸。", "何年乘風下太清，芝田煙暝瑶池冷。", "天臺山上玉京天，何似青天玉帝前。", "曉雲黯淡但欲唳，夜月凄凉那得眠。", "君不見東海蒼魚浮吞舟，一朝失却風濤秋，陸地螻蟻俱逆謀。", "又不見南山白虎嘯裂石，一朝不得山林力，平原狸兔起圖食。", "如彼茅圊蠅，不知天池翔大鵬。", "如彼布褌虱，不知白鸞舞空碧。", "世間炎凉相渭涇，是非寵辱無限情。", "彼鶴暫爾耳，自警聊自鳴。", "山靈更須勤愛護，忽然鼓翅翔四溟。", "上有崑臺琪花紅，下有蓬山芝草青。", "山頭知音復能幾，幾人得如華與丁。", "那堪九霄去，人世無此聲。"]'),
('52e248b5-8516-4507-aba0-d530d6a8c7d8','道過成蹊菴偶成舊風一篇','白玉蟾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','笑把青藜出武夷，不辭千里訪幽奇。',384,'全唐诗/poet.song.207000.json','["笑把青藜出武夷，不辭千里訪幽奇。", "吐吞風月一壺酒，拈弄溪山萬首詩。", "道過星河駭雙目，萬竈清煙纏華屋。", "老巖峭拔森翠屏，大江東去流蒼玉。", "樵人弛薪指似予，中有玉洞藏仙都。", "樓閣參差美輪奐，神仙隠顯知有無。", "夕陽掛樹暮山紫，行行到此欲脫屣。", "門前三徑綠苔深，浩蕩春風醉桃李。", "子然放步成蹊菴，其一仙翁樂笑談。", "蒼髯綠鬢兩眸碧，霞標芝宇清巖巖。", "青牛人去幾千載，源流尚有玄孫在。", "身裏蓬萊十二樓，杖頭雲水三千界。", "大隠從來只市廛，年來教法况蕭然。", "先生駐錫廬山下，混俗和光四十年。", "琅庭琛館五雲起，五湖四海來如蟻。", "天下三百六十洲，未見堂宇高於此。", "自非先生真棟梁，安能玄閫顔輝光。", "煙簑雨笠捘入門，琴佩劍履充其堂。", "先生何年創丹室，寶篆灰寒門牖密。", "明窗浄几一爐香，何人會此真消息。", "先生何日結草廬，讀盡丹臺紫府書。", "有時瞑目坐蒲團，閑即汲水澆園蔬。", "妙南老人畫真迹，一枝薜荔纏寒碧。", "莫問當年老沈翁，先生默契真端的。"]'),
('ed81a655-c075-481f-a2f0-23407dbfeff5','琵琶行','白玉蟾','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u957f\u6c5f"]','長江浩浩送千古，江流不斷魚龍舞。',384,'全唐诗/poet.song.207000.json','["長江浩浩送千古，江流不斷魚龍舞。", "蘆花荻花愁暮雲，天風吹我客湓浦。", "移舟回首思故人，凄然一登琵琶亭。", "琵琶亭上秦天遠，琵琶亭下楚江橫。", "嗚呼我祖唐少傅，兜率天中已歸去。", "客來倚棹問漁翁，香山居士今何處。", "冰魂雪魄挽不回，濤山浪屋空崔嵬。", "檣烏驚起水鷗睡，遶船明月夜徘徊。", "謫官江左秋風慘，江上黄昏月黯黯。", "那堪送客聞琵琶，况對怨女不傷感。", "洛陽城外蝦撁陵，下有甲妓何娉婷。", "花落色衰婚舶客，獨守孤舟伴月明。", "手撫琵琶意嗚唈，挑攏撚抹緩復急。", "大絃哀哀小絃悲，孤舟嫠婦豈不泣。", "霓裳纔歇六么鳴，四絃盡作裂帛聲。", "碧落黄泉兩凄苦，幽愁暗恨不堪聽。", "凜如猿咽梧桐晚，款若鶑啼春晝暖。", "鵾絃轉處如胡笳，宮調彈時若羌管。", "江州司馬一斷腸，燈前老淚如雨滂。", "老婦低眉嬌滴滴，琵琶掩面羅衣香。", "初彈如珠後如縷，一聲兩聲落花雨。", "訴盡平生雲雨心，盡是春花秋月語。", "羅衣揾淚向人啼，妾是秦樓浪子妻。", "流落煙塵歸未得，青樓昔在洛陽西。"]'),
('0e00bd93-874d-4199-8104-79f11335fc43','酌月亭','白玉蟾','宋','宋诗','song-poetry','','[]','夜深花前月落酒，花前舉酒月在手。',98,'全唐诗/poet.song.207000.json','["夜深花前月落酒，花前舉酒月在手。", "一杯嚥下月一團，併把青天都吸了。", "酒沃詩腸猶醺醺，月乃渺渺深入雲。", "從知我醉認不真，所嚥只是兔魄蟾蜍精。", "天又領月盃中走，月還把天杯中攪。", "臨風酌盡我欲眠，一聲雞唱千山曉。"]'),
('5b0aae3c-1c68-4d8c-9769-e21c9e8175db','觀魚歌','白玉蟾','宋','宋诗','song-poetry','','[]','君不見東海有鯉釣不上，馮夷翻江春浩蕩。',262,'全唐诗/poet.song.207000.json','["君不見東海有鯉釣不上，馮夷翻江春浩蕩。", "漁者歸舟載月明，一聲雷震桃花浪。", "又不見北溟有鯤能吞舟，浪屋濤山相拍浮。", "忽朝擊水三千里，九萬扶摇吳葉秋。", "道人放浪游太乙，一泓寒玉浸春碧。", "十丈晴波何浄明，百尾巨魚自跳躑。", "錦鱗鐵鬣紅玉鬐，珠齒冰腮紫金脊。", "綠玻瓈裏飛璚梭，碧琉璃中擲金尺。", "吾疑漢室曾漏網，否則禹門曾點額。", "釣臺千古松風寒，渭水一竿霜月白。", "子産之意徒洋洋，庚氏之呼可策策。", "有時聽琴躍水心，有時認履伏池側。", "古人觀棠有何心，今朝鑑止輸閑客。", "群魚群魚聽我語，太乙真人在何許。", "尚埋頭角守污池，不展爪牙上星渚。", "種成紅杏不騎去，留向人間作霖雨。"]'),
('d3e66bba-fa70-4518-b4f9-654a0ac67b9f','問月臺蘇竹莊同賦','白玉蟾','宋','宋诗','song-poetry','','[]','千山萬山翠交鎖，何處瑶臺天上墮。',226,'全唐诗/poet.song.207000.json','["千山萬山翠交鎖，何處瑶臺天上墮。", "臺前吟久忽登樓，樓前開窗天入座。", "留天且莫放天歸，問天明月來幾時。", "青天推月上雲表，使我對月自問之。", "試問月中玉妃子，人言羿妻無乃是。", "夜夜清風爲作媒，欲把冰姿嫁誰氏。", "桂子婆娑今幾秋，蘂宮珠殿何年修。", "吳剛執斧胡不休，玉兔銀蟾猶更留。", "我聞明皇排空聽，又聞李白騎鯨水中捉。", "至今天上弄銀盤，依舊萬星攢碧落。", "但見一輪月在天，如何千江千月圓。", "月還似水水似月，千眼所見皆同然。", "今方得月爲詩侶，月亦有情但無語。", "延月不久月竟歸，我欲乘風游玉宇。"]'),
('e88fdf7a-b95d-42f2-ac4e-61f478ea9912','贈畫魚者','白玉蟾','宋','宋诗','song-poetry','','[]','昔日僧繇所畫魚，三十六鱗依翠蒲。',256,'全唐诗/poet.song.207000.json','["昔日僧繇所畫魚，三十六鱗依翠蒲。", "徐高畫中多畫魚，鼓鱗揚鬣今爲圖。", "古人妙畫猶不朽，今人妙處古未有。", "郭丹青者冠古今，天下畫魚第一手。", "畫到妙處手應心，心匠巧甚機智深。", "紙上溶溶一溪水，放出鰷鱨二三尾。", "金鱗錦鬣紅玉鬐，圉圉洋洋戲波裏。", "小魚如針同隊行，噞喁水面隨風萍。", "擲頭掉尾浮沉勢，三聚二散游躍意。", "筆分濃淡計萬鱗，劃鬚點眼勻墨痕。", "狀如拋尺量波練，復似穿梭擲水紋。", "宛然鱍鱍巢青藻，漁翁未釣先吹火。", "壁上魚躍水不流，稚子睥睨敲針釣。", "君今畫到入神處，此畫一出聲尤著。", "魚雖無腸有活意，玉波浸荇澄寒渚。", "深恐後夜或雷雨，化作龍飛禹門去。"]'),
('377a7c79-2b95-46d2-a67d-37b9fb2e88ee','雲游歌','白玉蟾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雲游難，雲游難，萬里水煙四海寬。',384,'全唐诗/poet.song.207000.json','["雲游難，雲游難，萬里水煙四海寬。", "說著這般滋味苦，教人怎不鼻頭酸。", "初別家山辭骨肉，腰下有錢三百足。", "思量尋師訪道難，今夜不知何處宿。", "不覺行行三兩程，人言此地是漳城。", "身上衣裳典賣盡，路上何曾見一人。", "初到孤村宿孤館，鳥啼花落千林晚。", "明朝早膳又起行，只有隨身一柄傘。", "漸漸來來興化軍，風雨蕭蕭欲送春。", "惟一空自赤毿瑉，囊中尚有三兩文。", "行得艱辛脚無力，滿身瘙痒都生蝨。", "茫然到此赤條條，思欲歸鄉歸未得。", "爭奈旬餘守肚饑，埋名隠姓有誰知。", "來到羅源興福寺，遂乃捐身作僕兒。", "初作僕時未半月，復與僧主時作別。", "火雲飛上支提峰，路上石頭如火熱。", "炎炎畏日正燒空，不堪赤脚走途中。", "一塊肉山流出水，豈曾有扇可摇風。", "且喜過除三伏暑，蹤跡于今復劍浦。", "真箇徹骨徹髓貧，荒郊一夜梧桐雨。", "黄昏四顧淚珠流，無笠無簑愁不愁。", "偎傍茆簷待天曉，村翁不許住簷頭。", "聞說建寧人好善，特來此地求衣飯。", "耳邊但聞慚愧聲，阿誰可具慈悲眼。"]'),
('ac54c027-7f80-4ce5-acb4-a5af55d7235b','題諸葛繡香園','白玉蟾','宋','宋诗','song-poetry','','[]','碧桃枝上東風轉，一點陽和開柳眼。',384,'全唐诗/poet.song.207000.json','["碧桃枝上東風轉，一點陽和開柳眼。", "何人收拾羅浮春，藏在此園天不管。", "每歲東君召勾芒，玉壺淡淡晴煙暖。", "佳人有恨嫌花遲，王孫不來空草偃。", "南陽公子筆下詩，先遣一番風雨趲。", "底事鶑啼似駡春，山川失色花神赧。", "淺碧牡丹呈一枝，嫩紅芍藥開數本。", "小池水脈漲春波，古洞燒痕鋪翠巘。", "寒泉漱玉奪琴聲，舊竹移陰侵酒盞。", "如人畫出香錦圖，任與白雲自舒卷。", "海棠落地春閉門，杜鵑聲斷蜂蝶懶。", "秧針刺水盈南畝，老桑脫樹蠶方繭。", "其他苑囿皆春歸，酒酹花魂不可挽。", "此園春色無增損，主人不肯扃池館。", "荷花吐出十丈紅，芹秀泥融燕空卵。", "茉莉避席方夏闌，芙蓉彈冠已秋晚。", "面蘭琢句詩清新，賓菊開樽意蕭散。", "丹桂風中金屑飛，早梅雪裏璚香遠。", "曉來泣煙枝上猿，夜靜吠月花間犬。", "壺中景富人榮華，身外天寒苦日短。", "醉後焚香厭濁醪，詩成入口勝金臠。", "水晶簾捲翡翠屏，何必蓬萊和閬苑。", "諸郎青衿輩侃侃，一觴一詠心燕衎。", "紅袖佯醉倚莆萄，白丁不敢躡苔蘚。"]'),
('23541a9e-2f79-4e4f-beff-4bc4d786e623','丫頭巖','白玉蟾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','君不見武夷九曲溪之東，三峯號爲玉女峯。',212,'全唐诗/poet.song.207000.json','["君不見武夷九曲溪之東，三峯號爲玉女峯。", "當時嫁與大王峰，至今櫛雨而梳風。", "又不見廬山三疊江之湄，大姑小姑凡兩磯。", "小姑聘與彭郎磯，至今波眼而浪眉。", "湘夫人寂寞湘水濱，巫山女窈窕巫峽浦。", "亦有有情者，亦有無情者。", "鬼物託物以爲靈，俗子謂之山石精。", "吾來丫頭巖下坐，已覺此身本非我。", "朝雲暮雨或有之，年來心下已無火。", "兩峯相並各鬽崒，對人長是嬌媚色。", "過者見此如雙鬟，雲鬙霧鬢蒼苔髮。", "我來適值天方秋，孤懷暗抱不能愁。", "巖下行人幾回老，此巖依舊喚丫頭。"]'),
('6cbb4e80-56c9-4c63-8db7-615cf2888a5c','麻姑山','白玉蟾','宋','宋诗','song-poetry','','[]','瑶林猿嘯春坡月，玉淵蛟舞秋崖雪。',64,'全唐诗/poet.song.207000.json','["瑶林猿嘯春坡月，玉淵蛟舞秋崖雪。", "伊獨脯麟飯胡麻，仙爪肯理君毛髮。", "往事王遠徵蔡經，苔碑寂寞顔真卿。", "嗅柑羽人叫無處，一鶴飛上尋真亭。"]'),
('24f3a1fa-1f49-4796-af55-d5aabbb23f12','常山道中','白玉蟾','宋','宋诗','song-poetry','','[]','既雨山色晴轉佳，望洋雪色脂麻花。',64,'全唐诗/poet.song.207000.json','["既雨山色晴轉佳，望洋雪色脂麻花。", "白雲無邊鳥聲暮，目斷遠水明殘霞。", "流螢飛出衰草叢，宿鵲走上枯松丫。", "行人路上暗回首，月下獨對溪頭沙。"]'),
('d1b37ed7-d876-49a5-98da-e7528865e22c','久旱得雨晚凉得月奉似鶴林','白玉蟾','宋','宋诗','song-poetry','','[]','驕魃羞明曉失威，前村落罷雨絲絲。',64,'全唐诗/poet.song.207000.json','["驕魃羞明曉失威，前村落罷雨絲絲。", "四方萬里共明月，五嶽六輔生凉颸。", "我亦白雲一逋客，幸不龍門遭點額。", "尋常袖手不爲霖，直恐風生天地黑。"]'),
('ec41e237-94d2-4dec-96a2-e43f8cc8ec19','禱雨有應寄鶴林','白玉蟾','宋','宋诗','song-poetry','','[]','魃燄爇天草木煩，請檄上清火鈴君。',128,'全唐诗/poet.song.207000.json','["魃燄爇天草木煩，請檄上清火鈴君。", "爲我挽斷黄河源，併與拽翻蒼海根。", "我亦弗信神龍頑，我亦弗疑神雷蠻。", "速須𣬬雨如傾盆，鶴林真人事奏函。", "白晝香篆昇天門，東井箕星訪白羊。", "豐隆急速追玄溟，宇宙肸蠁一彈指。", "郊外萬絲懸如繩，人疑袖手倦作霖。", "豈知此心冥太清，夙世已是神霄卿。"]'),
('a0d8ae7a-fb68-489d-85d3-24edf5809e0e','王仙君讖','白玉蟾','宋','宋诗','song-poetry','','[]','持蠡一酌白龜泉，滋味有若醍醐然。',96,'全唐诗/poet.song.207000.json','["持蠡一酌白龜泉，滋味有若醍醐然。", "白龜上合玄武精，碧溜甃玉寒涓涓。", "何人汲水灌皂木，樹必開花趁春綠。", "前人遺讖人不知，皂木本應奎婁宿。", "金水木火結成丹，復用真土築爲壇。", "阿誰會此造化機，千日藥成登雲端。"]'),
('073866db-bbf8-42e9-a026-8c4cfe137dea','秋思','白玉蟾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','萬蠢懼寒皆向蟄，千巖凉風舞黄葉。',64,'全唐诗/poet.song.207000.json','["萬蠢懼寒皆向蟄，千巖凉風舞黄葉。", "雨痕印水如撮纈，蟲聲入夜如彈鑷。", "酒澆心緒轉悽愴，带減腰圍增瘦怯。", "夢向西湖采芙蓉，覺來山外青猿泣。"]'),
('c07ffc96-dc60-47c8-a7eb-9f29f07bd6e4','可惜','白玉蟾','宋','宋诗','song-poetry','','[]','人間何似神霄府，我今面目蒙塵土。',192,'全唐诗/poet.song.207000.json','["人間何似神霄府，我今面目蒙塵土。", "年來無夢到神霄，一度傷懷淚如雨。", "風前無奈倚欄干，雪裏不堪聞杜宇。", "此情欲訴有誰知，只有春風知我苦。", "竹籬斷兮茆簷頹，桃花落兮猿聲哀。", "白雲漠漠去無盡，青鳥杳杳何曾來。", "不愁我死故自惜，有此枯骨知誰埋。", "芳草連汀雨如織，春煙慘愁晝不開。", "可惜可惜復可惜，幽懷欲吐不可得。", "神霄有路平如掌，青雲可梯星可摘。", "可惜袖中一卷書，可惜手中一枝筆。", "南方有人無消息，對花對酒長相憶。"]'),
('d1503615-cca9-4150-98f6-1d1657248bf3','行路難寄紫元','白玉蟾','宋','宋诗','song-poetry','','[]','贈君以丹棘忘憂之草，青裳合懽之花。',65,'全唐诗/poet.song.207000.json','["贈君以丹棘忘憂之草，青裳合懽之花。", "馬腦游仙之夢枕，龍綜辟寒之寶砂。", "天河未翻月未落，夜長如年引春酌。", "古人安在空城郭，今夕不飲何時樂。"]'),
('e3a6fa79-8855-42a5-beab-b63579300af6','懷仙吟  其一','白玉蟾','宋','宋诗','song-poetry','','[]','蟠桃脫核吾來時，銖衣拂石吾未歸。',64,'全唐诗/poet.song.207000.json','["蟠桃脫核吾來時，銖衣拂石吾未歸。", "翻思此日朝玉帝，有淚如雨沾帝衣。", "自起凭樓眉自繭，琪花開後知誰剪。", "鳳凰閣上定蛛絲，鳳凰閣下須苔蘚。"]'),
('24037dc4-bbb4-4eb9-b26d-bca16bbcb6cd','懷仙吟  其二','白玉蟾','宋','宋诗','song-poetry','','[]','坐見雲來復雲去，樓裏朝朝還暮暮。',64,'全唐诗/poet.song.207000.json','["坐見雲來復雲去，樓裏朝朝還暮暮。", "人間天上夢悠悠，把酒長吁知幾度。", "不堪吞吐良亦苦，暗想珠宮欠良遇。", "臨風對月但無言，無言即是懷仙處。"]'),
('28f37db9-7e01-4a37-8a4a-6b9efe4dcde1','祈雨歌','白玉蟾','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','天地聾，日月瞽，人間亢旱不爲雨。',144,'全唐诗/poet.song.207000.json','["天地聾，日月瞽，人間亢旱不爲雨。", "山河憔悴草木枯，天上快活人訴苦。", "待吾騎鶴下扶桑，叱起倦龍與一斧。", "奎星以下亢陽神，縛以鐵札送酆府。", "驅雷公，役電母，須叟天地間，風雲自吞吐。", "㘞火老將擅神武，一滴天上金瓶水，滿空飛線若機杼。", "化作四天凉，掃却天下暑。", "有人饒舌告人主，未幾尋問行雨仙，人在長江一聲櫓。"]'),
('0b959a69-a2ec-4c52-9dd2-d4cb92b59f64','夜漫漫','白玉蟾','宋','宋诗','song-poetry','','[]','雷聲初散天成霽，雨改青山顔色翠。',112,'全唐诗/poet.song.207000.json','["雷聲初散天成霽，雨改青山顔色翠。", "清猿嘯夜月濛朧，木客暗吟悽愴意。", "麻姑峯頭一縷雲，苒苒如綿飄羽袂。", "良宵展轉不成眠，天外青鸞何未至。", "碧空冷露落無聲，誰見幽人揮玉涕。", "情緒紛綸天籟起，起讀璚書言語祕。", "曉霧護寒山狗吠，紅日松窗金縷細。"]'),
('5ffa1daf-1176-4fb7-9c91-150d017a4bfa','周唐輔仙居莊作','白玉蟾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','黄鸝聲斷桃花飛，一雨三日溪水肥。',168,'全唐诗/poet.song.207000.json','["黄鸝聲斷桃花飛，一雨三日溪水肥。", "龍孫破地蝴蝶懶，梅子如豆糝青枝。", "東風吹轉楊柳腰，村南村北杜鵑啼。", "稻針刺水鷗抱卵，雙燕商量春欲歸。", "蟾溪主人拆社甕，百杯醉我爛如泥。", "翠麓軒壁凝古墨，一闋松窗傷春詞。", "夜來飲到姮娥去，笙鶴響空人不知。", "露華煙華濕蒼蘚，朦朧沆瀣霑我衣，瀑布懸珠濺紫芝。", "山猿恐我呼杖屨，啼到日高丈二時。", "廬山山下一回首，只是此生長別離。"]'),
('91962413-387a-4454-b0e4-b3cf312b8d4b','浙江待潮','白玉蟾','宋','宋诗','song-poetry','','[]','秋空無塵鴈可數，蘆花蓼花滿江渚。',64,'全唐诗/poet.song.207000.json','["秋空無塵鴈可數，蘆花蓼花滿江渚。", "夕陽影裏高掀蓬，落葉聲中更鳴櫓。", "六角扇起解熱風，三杯酒爲澆詩雨。", "船頭拔劍叫飛廉，潮花捲雪魚龍舞。"]'),
('355998a1-cb5c-4b8e-97fe-f185d3291179','贈陶琴師','白玉蟾','宋','宋诗','song-poetry','','[]','一雨濯旱秋滴滴，西風吹破蒼苔色。',144,'全唐诗/poet.song.207000.json','["一雨濯旱秋滴滴，西風吹破蒼苔色。", "松壇月冷夜三更，烏鵲無聲露華白。", "鼇宮飲散酒盃空，萬籟蕭騷天變黑。", "惠然爲我鼓長琴，聲裏胡笳十八拍。", "凄凄嗚嗚寒蟬鳴，黯然古澗泉琤琤。", "挑攏撚抹緩復急，遠聽近聽如猿聲。", "我生飄泊何雲萍，故國關山萬里程。", "君將三疊入吾耳，調中話出吾平生。", "曲罷空歌舞笙鶴，直欲騰身歸碧落。"]'),
('74649fa9-4898-45f9-9d3e-fca074585b84','贈周龐齋居士','白玉蟾','宋','宋诗','song-poetry','','[]','召公八十入爲相，太公八十出爲將。',226,'全唐诗/poet.song.207000.json','["召公八十入爲相，太公八十出爲將。", "趙州八十方行脚，鍾離八十離塵劫。", "古者八十方施爲，何况百歲七十稀。", "居士而今七十七，黄髮皓齒修龐眉。", "漢時欒巴七十七，紅爐煉就一朱橘。", "晉鄭思遠七十七，方與葛洪一相識。", "我知居士神仙人，蓬萊路上空月明。", "人間宿留不肯歸，老松筋骨鶴精神。", "性海淡淡寒潭瑩，心天耿耿銀河靜。", "有一孟子耕書田，有一季子鏖筆陣。", "弄璋弄瓦遂箕裘，雙鳳飛鳴椿樹秋。", "壽山福海身優游，掇取酒船相拍浮。", "南極一點夜照耀，勸君遲赴玉皇詔。", "既到人間不住千百年，歸去空被老彭笑。"]'),
('5d10ea88-6c80-4faf-8ed5-47622bd456f5','贈玉隆王直歲游武當山','白玉蟾','宋','宋诗','song-poetry','','[]','西山猿啼啼不己，千巖萬壑綠煙起。',96,'全唐诗/poet.song.207000.json','["西山猿啼啼不己，千巖萬壑綠煙起。", "杖頭挑月過瀟湘，去飲清陽澗下水。", "清陽澗上五龍池，池邊落葉不敢飛。", "太玄真人去未歸，七十二峯空斜暉。", "峯頭有人名㘞火，洞泉飄出松花老。", "他年君自武當回，惠我數枝石燈草。"]'),
('9b1d12cd-220c-46cb-9b3a-d8bb8296bd3e','題劉心月','白玉蟾','宋','宋诗','song-poetry','','[]','汨羅江山水嗚唈，魚鼈不知老龍泣。',392,'全唐诗/poet.song.207000.json','["汨羅江山水嗚唈，魚鼈不知老龍泣。", "徒棹龍舟何處尋，何不辦取屈原生前一枝楫。", "大吳江頭伍侯廟，夕陽滿樹聞啼鳥。", "行人過此焚紙錢，何不辦取子胥生前一杯酒。", "屈伍死後今寥寥，其名千古如一朝。", "江邊垂淚知幾人，冰魂雪魄不可招。", "哀哉道人劉心月，其身貧甚其性烈。", "少年雖落風塵中，末後猛省自擺脫。", "其心雖美其名腥，一旦死于武夷溪之濱。", "却將九曲溪中水，洗却千愁萬恨身。", "曹娥尋父尺赴水，死作婦女英靈鬼。", "柳翠蕭璚俱水亡，但見渺渺一溪水。", "汝何不自忍些憂，又却結憤滿心頭。", "冰肌玉膚落潭碧，黄昏風慘水空流。", "武夷溪九曲，無人垂釣水空綠。", "武夷三十六峯巒，無人結草惟空山。", "月明尋之不知處，尚自哀猿聲不住。", "那堪一夜瀟瀟雨，使人吟盡哀慘句。", "休休心月君亦賢，人生不死空百年。", "掀翻四大驚魚龍，踏破碧潭深處天。", "李白騎鯨去捉月，知章水底眠霜雪。", "古人猶自水中逝，皆得水化超生訣。", "吾與心月係渠師，來此慘慘烟正飛。", "天空水寒千山暗，酌水一酹心含悲。"]'),
('1e862b6f-3c30-4041-8bb0-5f207ba210ef','清勝軒夜話','白玉蟾','宋','宋诗','song-poetry','','[]','殘燈結花滿堂紅，酒興未已詩興濃。',112,'全唐诗/poet.song.207000.json','["殘燈結花滿堂紅，酒興未已詩興濃。", "寒雲蠹星鎖翠空，一林幽竹夜呼風。", "逸士倚樓嘯玉龍，秋聲泣露落梧桐。", "把酒論文開心胸，黑甜相催話未終。", "香篆飛蛇穿簾櫳，鄰雞喚曉何處鍾。", "摩挲醉眼欄干東，茶鐺無火召玉童。", "三子芒鞋七尺筇，踏破前山綠幾重。"]'),
('1766a704-16cd-4f35-b71a-2d5b773b9296','冥鴻辭','白玉蟾','宋','宋诗','song-poetry','','[]','夜來烏鵲棲寒楓，蒼天萬里煙霞濃。',208,'全唐诗/poet.song.207000.json','["夜來烏鵲棲寒楓，蒼天萬里煙霞濃。", "海神洶湧翻怒濤，風伯鼓舞吹冥鴻。", "霜翰不入矰繳內，星眼直射煙霄中。", "下嗤鳥雀戀籬落，俯視鷺鷗偎蘆叢。", "雲間矯首已萬里，天外鼓翅期四通。", "鐵爪裂破帝乙網，銀觜笑折由基弓。", "知音鯤鵬擊溟渤，嬌騃鸚鵡遭牢籠。", "數行縱橫灑天面，一聲嘹唳悲秋客。", "來時蹤跡度衡湘，昔者音信通鎬豐。", "豈念稻粱在一粒，如彼仕宦迷千鍾。", "橫飛直捎林壑表，自是挺出風煙雄。", "易水荆軻業已北，大滓蘇武勢須東。", "好同鷹鸇彈燕雀，滿地萍蕪毛血紅。"]'),
('777a3603-0893-4c08-b2a8-923727ec19ee','有所思','白玉蟾','宋','宋诗','song-poetry','','[]','蒼官無祿花有封，花王開國胙春風。',64,'全唐诗/poet.song.207000.json','["蒼官無祿花有封，花王開國胙春風。", "不念蒼官秦大夫，竹君亦嗤梅兄聾。", "夜寒愁吟正無思，青燈喚人補殘睡。", "夢爲蝴蝶宿花回，畫角吹香蒸素被。"]'),
('832be590-1377-4dc5-aa82-f34168306f6e','送珊上座歸育王','白玉蟾','宋','宋诗','song-poetry','','[]','一雙膝脛兩條鐵，一掬精神一團雪。',236,'全唐诗/poet.song.207000.json','["一雙膝脛兩條鐵，一掬精神一團雪。", "早曾火燄上翻身，鴛幃不把丁香結。", "風吹香囊滿路香，知君也結欽山轍。", "忽然洗面摸得鼻，方知皮下各有血。", "急携柏子禮孤雲，後來足跡遍江浙。", "阿育王山倉廩空，百指張頤欲嚼舌。", "延壽堂中幾病僧，囊無挑藥寒徹骨。", "見君把箇無孔笛，吹起還鄉曲一闋。", "此來漳泉走一遭，龐翁猶在波旬滅。", "拄杖挑起空中雲，鉢盂漉上波心月。", "默隨春色歸故山，江路梅花先漏泄。", "遂邀君來香一爇，重把篇詩呈醜拙。", "此行拗折老藤條，選佛場中作英傑。", "君今三千里外行，不涉程途猶自別。", "恰似一壺冰，千古光瑩徹。"]'),
('d989707a-baeb-47ee-8ec8-9927d5805796','端午述懷','白玉蟾','宋','宋诗','song-poetry','','[]','方瀛山上風颼颼，五月六月常如秋。',312,'全唐诗/poet.song.207000.json','["方瀛山上風颼颼，五月六月常如秋。", "松花落地鶴飛去，萬頃白雲空翠浮。", "夜半蟾蜍落丹井，琪林深鎖寒葉暝。", "滿天白露點蒼苔，蛙市一散萬籟靜。", "三樹兩樹啼斷猿，樹冷棲禽夜不眠。", "數點飛螢戀沙徑，山腰石潤悲寒泉。", "鍾聲隔斷華胥路，不知蝴蝶蜚何處。", "摩挲兩眼摺紙衾，人道今辰正端午。", "曉雨初霽梅子肥，龍孫脫籜新燕飛。", "山居蕭然無一物，摘薺搗麥充晨炊。", "憶著往年五月四，葛巾羽扇鸞溪市。", "龍艘破浪槳萬枝，鉦鼓聒天旗掣水。", "紙錢飛起屈原祠，行人往來如蟻移。", "桐花入鬢綵繫臂，家家禦疫折桃枝。", "庭前綠艾制綠虎，細切菖蒲斟綠醑。", "羹鵝鱠鯉辦華筵，冷浸水團包角黍。", "今年寂寞坐空山，山雨山風生曉寒。", "默菴令我休噫氣，作詩畧述山居意。", "安得兩腋生飛翰，與君飛上泬寥間，免使在世賦辛酸。"]'),
('a89f6c85-bd92-48c5-8cb1-569a2bdfb81c','仙巖行','白玉蟾','宋','宋诗','song-poetry','','[]','醉携七尺霜前行，雲錦山前灣幾曲。',256,'全唐诗/poet.song.207000.json','["醉携七尺霜前行，雲錦山前灣幾曲。", "溪頭秋雨添寒綠，蛟龍冷浸一壺玉。", "蓼花錦岸紅欲流，稻田高下鋪棋局。", "碧巖聳出碧天半，鳥不敢飛縮雙足。", "古洞無人石酒酢，峭壁仙倉積天粟。", "老稍指顧猶驚呼，神刓鬼劃出崖谷。", "搗藥聲乾人已仙，萬丈丹井一泓泉。", "風擊古松飛翠蓋，日射蒼苔鑄綠錢。", "藤蘿拽樹擘輕煙，黄鶴一去今何年。", "天欲夕陽空鳴蟬，夜深嶺月向誰圓。", "古寺老屋留數椽，殘僧一二掩柴門。", "鐵像面壁蕭蕭然，瓦爐無火古殿前。", "寒鴉到窗簷息溜，暮雲衰草覺山瘦。", "楮衾不暖不成眠，虎聲入耳猿聲又。", "幾點疎星落梧桐，丹巒紫壑高相鬭。", "何當汗漫跨青牛，曉露泠泠白玉樓。"]'),
('6c8b07dc-cd2f-4245-a498-f9ae2f81fdb1','短歌行','白玉蟾','宋','宋诗','song-poetry','','[]','我適越，君適秦。',194,'全唐诗/poet.song.207000.json','["我適越，君適秦。", "舟掛越帆猶柳下，馬回秦首更江濱。", "江濱綠柳多煙顰，岸下碧水生風鱗。", "四海交游不易得，一州雲月聊相津。", "向來君亦何爲者，空自紅生滿袖塵。", "君行無遽行，感我思古人。", "詩禮謾撩頗牧笑，弓刀自取荀楊嗔。", "君不見趙璧生還燕圖死，輕肥關心不顧身。", "又不見鴻門舞罷已成陳，怒撞玉斗豈無因。", "夫誰擊笏血朱泚，或者明年貴買臣。", "題柱高司馬，棄繻壯終軍。", "君去幾時回，此別休愴神。", "百萬呼盧銀燭夜，十千買酒玉樓春。"]'),
('488efa7d-ed3b-417f-9323-91a5fda1b423','琴歌','白玉蟾','宋','宋诗','song-poetry','','[]','月華飛下海棠枝，樓頭春風鼓角悲。',352,'全唐诗/poet.song.207000.json','["月華飛下海棠枝，樓頭春風鼓角悲。", "玉杯吸乾漏聲轉，金劍舞罷花影移。", "蘂珠仙子笑移燭，喚起蒼潭老龍哭。", "一片高山流水心，三奏霓裳羽衣曲。", "初如古澗寒泉鳴，轉入哀猿凄切聲。", "吟猱撚抹無盡意，似語如愁不可聽。", "神霄宮中歸未得，天上此夕知何夕。", "瓊樓冷落琪花空，更作胡笳十八拍。", "君琴妙甚素所慳，知我知音爲我彈。", "瑶簪琅珮不易得，渺渺清飈吹廣寒。", "人間如夢只如此，三萬六千一彈指。", "蓬萊清淺欲桑田，君亦輟琴我隠幾。", "爲君歌此幾操琴，琴不在曲而在心。", "半顰如苦萬綠縷，一笑不博千黄金。", "我琴無徽亦無軫，瓠巴之外餘可哂。", "指下方爾春露晞，絃中陡覺和風緊。", "琴意高遠而飄飄，一奏令人萬慮消。", "淒涼孤月照梧桐，斷續夜雨鳴芭蕉。", "我琴是謂造化柄，時乎一彈混沌聽。", "見君曾是蘂珠人，欲君琴與造化並。", "昔在神霄莫見君，蘂珠殿上如曾聞。", "天上人間已如隔，極目靄靄春空雲。"]'),
('59333c22-132c-4bd9-a450-d2ab8e8c8440','食生菜','白玉蟾','宋','宋诗','song-poetry','','[]','殘風剩雨放春晴，久醉欲醒何由醒。',88,'全唐诗/poet.song.207000.json','["殘風剩雨放春晴，久醉欲醒何由醒。", "枕上扶頭更解酲，五官六吏皆失寧。", "滿園萵苣間蔓青，火急掣鈴呼庖丁。", "細膾雨葉縷風莖，酢紅薑紫銀鹽明，豆臡麻膏和使成。", "食如辣玉兼甜冰，毛骨灑灑心泠泠。"]'),
('b976da08-6bb3-4602-a18d-67c843b5cc62','立春','白玉蟾','宋','宋诗','song-poetry','','[]','顓帝位方禪，勾芒印已交。',24,'全唐诗/poet.song.207000.json','["顓帝位方禪，勾芒印已交。", "芭蕉有封事，黄鳥莫譊譊。"]'),
('adab3293-6dd3-40ea-b41a-f199a5d806ae','早行','白玉蟾','宋','宋诗','song-poetry','','[]','店遠鷄聲近，月斜人影長。',24,'全唐诗/poet.song.207000.json','["店遠鷄聲近，月斜人影長。", "再三謝風露，拜賜一天凉。"]'),
('6fc48f4b-a5e9-430e-889f-eb8b7de69f76','風窗','白玉蟾','宋','宋诗','song-poetry','','[]','窗隙針來大，霜風聖得知。',24,'全唐诗/poet.song.207000.json','["窗隙針來大，霜風聖得知。", "耳邊如箭急，直把菊花吹。"]'),
('4228d5ac-a82f-4095-9042-97292337f72f','遠景','白玉蟾','宋','宋诗','song-poetry','','[]','岸樹冥茫外，人家點畫中。',24,'全唐诗/poet.song.207000.json','["岸樹冥茫外，人家點畫中。", "斷煙分紫翠，殘照抹青紅。"]'),
('d271077a-7e64-46ae-adb8-438a61661c1f','梅花','白玉蟾','宋','宋诗','song-poetry','','[]','影上酥花峭，枝頭蠟糝清。',24,'全唐诗/poet.song.207000.json','["影上酥花峭，枝頭蠟糝清。", "姮娥約滕六，夜半過江城。"]'),
('47d1f5f3-37ba-4d76-8407-2aff5bfc7f6d','江頭','白玉蟾','宋','宋诗','song-poetry','','[]','江上初收雨，雲頭尚戀山。',24,'全唐诗/poet.song.207000.json','["江上初收雨，雲頭尚戀山。", "歸帆巡古岸，晴草守滄灣。"]'),
('3132f7a4-1531-4d0f-b7e3-182e42ae649a','許旌陽故宅','白玉蟾','宋','宋诗','song-poetry','','[]','詩多唐代刻，柏尚晉時青。',24,'全唐诗/poet.song.207000.json','["詩多唐代刻，柏尚晉時青。", "想得真君劍，猶餘蛟血腥。"]'),
('94931aec-2924-4467-8a99-09c822a92e7d','示周道士','白玉蟾','宋','宋诗','song-poetry','','[]','人行秋色裏，詩入畫圖中。',24,'全唐诗/poet.song.207000.json','["人行秋色裏，詩入畫圖中。", "笑指白雲頂，猿啼第一峰。"]'),
('27cd7f91-7549-408b-b755-591d8107bd86','得友人書','白玉蟾','宋','宋诗','song-poetry','','[]','千里如天遠，三年不此來。',24,'全唐诗/poet.song.207000.json','["千里如天遠，三年不此來。", "書從雲外至，手把月中開。"]'),
('5b020c10-0682-44c0-8dda-2d33979e1b6e','五夜','白玉蟾','宋','宋诗','song-poetry','','[]','五夜風吹露，林間鳥喚熟。',24,'全唐诗/poet.song.207000.json','["五夜風吹露，林間鳥喚熟。", "鍾聲和月落，驚起四山雲。"]'),
('d5872a28-534e-4a8e-82bf-c519a8ce1d98','步自玉乳峰歸  其一','白玉蟾','宋','宋诗','song-poetry','','[]','薄暮一凝佇，歸鴻千有餘。',24,'全唐诗/poet.song.207000.json','["薄暮一凝佇，歸鴻千有餘。", "倚松吟半餉，月影瀉庭除。"]'),
('cd797c4c-66bc-42b6-932a-f79452aa0cf6','步自玉乳峰歸  其二','白玉蟾','宋','宋诗','song-poetry','','[]','月映山頭禿，雲迷路口叉。',24,'全唐诗/poet.song.207000.json','["月映山頭禿，雲迷路口叉。", "仰天方索句，一鶴立松丫。"]'),
('3a2dbdb9-748f-4351-b174-b978abf2a3e1','課園夫  其一','白玉蟾','宋','宋诗','song-poetry','','[]','已屬畦丁了，都將菜甲耘。',24,'全唐诗/poet.song.207000.json','["已屬畦丁了，都將菜甲耘。", "數時稽食籍，醢芥又羹芹。"]'),
