('5754de9b-94e4-461e-8436-a9c8718199a7','冬夕酌月  其二','白玉蟾','宋','宋诗','song-poetry','','[]','兔冷蟾寒桂影疎，化爲霜露瀉庭除。',32,'全唐诗/poet.song.207000.json','["兔冷蟾寒桂影疎，化爲霜露瀉庭除。", "已驚柏液冰吾齒，莫弄梅花粟爾膚。"]'),
('842ed043-56ae-4869-bd9e-b37f88da8534','冬夕酌月  其三','白玉蟾','宋','宋诗','song-poetry','','[]','二毛可惜雪霜侵，日有清都絳闕心。',32,'全唐诗/poet.song.207000.json','["二毛可惜雪霜侵，日有清都絳闕心。", "枝冷鵲翻簷外影，庭空鴻墮月邊音。"]'),
('7d0f7aa4-905d-4bd7-b26e-bce1853c4014','贈明講師  其一','白玉蟾','宋','宋诗','song-poetry','','[]','昔從師在月巖時，我過鵝湖即語離。',32,'全唐诗/poet.song.207000.json','["昔從師在月巖時，我過鵝湖即語離。", "每見孤鴻每生感，不曾一日不相思。"]'),
('4442e87d-5c1b-4663-ac6d-0da036846938','贈明講師  其二','白玉蟾','宋','宋诗','song-poetry','','[]','豈謂東吳得再逢，二俱老盡少時容。',32,'全唐诗/poet.song.207000.json','["豈謂東吳得再逢，二俱老盡少時容。", "來從上國鶑花裏，墮在輞川圖畫中。"]'),
('72ab6ac0-63d5-4c44-97a2-190f89ed7750','雪中  其一','白玉蟾','宋','宋诗','song-poetry','','[]','朔風吹冷裂窗紗，重把羅幃繡幕遮。',32,'全唐诗/poet.song.207000.json','["朔風吹冷裂窗紗，重把羅幃繡幕遮。", "青女先將霜起早，素娥始放雪飛花。"]'),
('f66ceb80-a357-4b57-b6b8-d11aa3c261e2','雪中  其二','白玉蟾','宋','宋诗','song-poetry','','[]','曉來紅日尚羞明，四外彤雲欲詐晴。',32,'全唐诗/poet.song.207000.json','["曉來紅日尚羞明，四外彤雲欲詐晴。", "一夜九天開玉闕，六花萬里散璚英。"]'),
('7a3cb0ca-99d0-40ef-8383-654aad70a3b2','雪中  其三','白玉蟾','宋','宋诗','song-poetry','','[]','飛廉滕六逞寒威，費酒陪詩爲解頤。',32,'全唐诗/poet.song.207000.json','["飛廉滕六逞寒威，費酒陪詩爲解頤。", "雪待夜深飛落盡，梅嗔風惡放開遲。"]'),
('e7e0940b-49b3-41f5-9286-c90ead04643e','龍虎山祈雨早行有作','白玉蟾','宋','宋诗','song-poetry','','[]','兩三條電復無雨，六七點星微上雲。',32,'全唐诗/poet.song.207000.json','["兩三條電復無雨，六七點星微上雲。", "鞭起卧龍我騎去，揮戈叱問五雷君。"]'),
('96df8af0-94f4-4aeb-99fe-344e3d067b9d','題棲鳳亭  其一','白玉蟾','宋','宋诗','song-poetry','','[]','亭前綠密玉成叢，鳳宿枝頭烟雨空。',32,'全唐诗/poet.song.207000.json','["亭前綠密玉成叢，鳳宿枝頭烟雨空。", "簫管一聲人未寢，滿林明月浸清風。"]'),
('1974b3a9-ce6a-43ae-a1be-d686431f4df7','題棲鳳亭  其二','白玉蟾','宋','宋诗','song-poetry','','[]','竹也多年管風月，鳳兮幾夜宿雲烟。',32,'全唐诗/poet.song.207000.json','["竹也多年管風月，鳳兮幾夜宿雲烟。", "林間有客吹簫去，竹化成龍鳳入天。"]'),
('263a26a5-6766-4aa2-93e1-e1adb1bf542f','題棲鳳亭  其三','白玉蟾','宋','宋诗','song-poetry','','[]','潘氏亭前飲一宵，酒酣對竹嘯瓊簫。',32,'全唐诗/poet.song.207000.json','["潘氏亭前飲一宵，酒酣對竹嘯瓊簫。", "不知棲鳳來多少，鳳去人歸竹寂寥。"]'),
('8b88557f-4e8c-4866-a2f0-f1965bc7584d','題棲鳳亭  其四','白玉蟾','宋','宋诗','song-poetry','','[]','聲傳琴瑟風生枕，影瀉琅玕月滿庭。',32,'全唐诗/poet.song.207000.json','["聲傳琴瑟風生枕，影瀉琅玕月滿庭。", "白鳳飛來枝外宿，夜深點破一林青。"]'),
('fd67797c-531b-4717-88b6-0ffcd19aae1a','梅花有嘆','白玉蟾','宋','宋诗','song-poetry','','[]','蒼苔玉艷委西施，玉膽冰姿尚伯夷。',32,'全唐诗/poet.song.207000.json','["蒼苔玉艷委西施，玉膽冰姿尚伯夷。", "春色一般清濁異，梅花亦自有安危。"]'),
('426ecc11-c369-44c7-8d53-6c4e19f71e84','中秋月','白玉蟾','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','千崖爽氣已平分，萬里青天輾玉輪。',32,'全唐诗/poet.song.207000.json','["千崖爽氣已平分，萬里青天輾玉輪。", "好向錢塘江上望，相逢都是廣寒人。"]'),
('8bcaaf37-0ddf-4dd7-a048-512222f42431','卧雲','白玉蟾','宋','宋诗','song-poetry','','[]','滿室天香仙子家，一琴一劍一盃茶。',32,'全唐诗/poet.song.207000.json','["滿室天香仙子家，一琴一劍一盃茶。", "羽衣常带煙霞色，不惹人間桃李花。"]');
